-- Poems batch 385
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('57469a91-2b4d-4a2a-aa52-9f416ab71506','贈明師','郭印','宋','宋诗','song-poetry','','[]','四民不相奪，事業勤且專。',240,'全唐诗/poet.song.95000.json','["四民不相奪，事業勤且專。", "所適既多歧，乃爲異物遷。", "初心轉錯亂，故步成跰𨇤。", "一縱不可收，有如解纜船。", "而况佛之徒，辭家童其顛。", "耕杼兩不知，蕭條香火緣。", "胡爲反自棄，捨已芸人田。", "筆墨殘畫永，詞章奪春妍。", "持此謁豪貴，往往求知憐。", "大事殊未明，口張鼻撩天。", "不見湯休輩，才名舉世傳。", "形化心亦爾，抱病歸黄泉。", "汝質本渾金，未逢妙手鐫。", "好名一以誤，沈溺在詩篇。", "毫釐失千里，萍梗空十年。", "吾言雖屢苦，掉首終弗然。", "邇來心孔開，舊學都棄捐。", "青山决棲隱，求師覓安禪。", "聞之喜且疑，此志諒能堅。", "行矣無所贈，短章當緡錢。"]'),
('a7bbecd4-16d3-4503-b790-71a9185dc544','諸公以嵩師破戒作詩嘲詠因次韻解之','郭印','宋','宋诗','song-poetry','','[]','老嵩悟塵緣，洪爐一點雪。',192,'全唐诗/poet.song.95000.json','["老嵩悟塵緣，洪爐一點雪。", "飛行三界外，宴坐常兀兀。", "有如出籠鳥，豈比縮頸鼈。", "萬象一詩本，章句真瑣屑。", "世人不識渠，小智互分别。", "豈知日用處，默語無殊轍。", "春雷未出地，草木含凍結。", "大聲歘然來，蟄龍起脩骨。", "神功無定在，作止纔一瞥。", "以詩來議師，所見何纖末。", "想當聞此言，揮麈笑且咄。", "惜哉二三子，微漚更出没。", "眼翳揮未掃，幻化何從滅。", "月體元自空，三三認盈缺。", "長篇陋摛錦，敏思遲擊鉢。", "秪向語邊尋，那解默時說。"]'),
('eed0d9b4-3168-404d-a21c-ebe9b7eb466e','和何耕道别字韻詩','郭印','宋','宋诗','song-poetry','','[]','失身落宦網，十載溪山别。',84,'全唐诗/poet.song.95000.json','["失身落宦網，十載溪山别。", "麋鹿念故棲，舉目但愁絕。", "偶來招提遊，幽亭坐深樾。", "美人抗高論，亹亹非涉獵。", "忽焉到佳處，目擊了無說。", "世患苦磨人，吾肱已三折。", "從兹數訪君，臨流弄明月。"]'),
('9b494f6d-b0f8-452e-a194-2a1238645e1b','和淵明韻贈耕道','郭印','宋','宋诗','song-poetry','','[]','游從無俗調，我輩鍾此情。',60,'全唐诗/poet.song.95000.json','["游從無俗調，我輩鍾此情。", "高談傲羲黄，豈復念功名。", "嗟哉夸奪子，役役勞其生。", "得失動中懷，寵辱多自驚。", "形化心亦爾，闔棺竟無成。"]'),
('05aa5629-2f6c-4a50-816a-189e4703cd57','再和','郭印','宋','宋诗','song-poetry','','[]','學道無所得，但忘物我情。',60,'全唐诗/poet.song.95000.json','["學道無所得，但忘物我情。", "顔彭竟何在，壽夭皆空名。", "有酒且斟酌，同心唯友生。", "江亭縱言笑，鳥來語不驚。", "昭琴元未鼓，誰復問虧成。"]'),
('16cf65a5-898b-4350-91d3-15ef4d42d6d7','和楊齊伯韻','郭印','宋','宋诗','song-poetry','','[]','邪師挾幻術，念念皆狂圖。',132,'全唐诗/poet.song.95000.json','["邪師挾幻術，念念皆狂圖。", "化出一切象，形容乃甚都。", "佛光亦幻成，非有與非無。", "煙霞異明晦，寥廓元太虛。", "離婁塞其目，象罔得玄珠。", "脱能如是解，安用空睢旴。", "宇定天光發，豈關七尺軀。", "癡兒生謗語，往往墮眉鬚。", "乃知西方聖，勇猛真丈夫。", "聖人與人同，此道誰不如。", "歸來但宴坐，反照自有餘。"]'),
('be95e38d-344b-400b-ba67-ab195d9ea3f9','和樊直夫兼簡允南','郭印','宋','宋诗','song-poetry','','[]','士而志於道，誰云不自量。',192,'全唐诗/poet.song.95000.json','["士而志於道，誰云不自量。", "山海雖崇深，行者尚梯航。", "况復我固有，本根先混茫。", "渺然一微塵，猶足鑄虞唐。", "隨遇得真樂，何適非道場。", "回首觀世間，汩沒誠可傷。", "余豈不知耶，駑馬戀豆糠。", "春林聽鳴鳥，秋壁聞啼螿。", "是心如死灰，妄念不復猖。", "持此欲求交，滿目都倀倀。", "邇來得吾人，宿願欣已償。", "文字果超詣，聖門早升堂。", "視彼俗學流，一一癡與狂。", "所爲雜覇下，未可語皇王。", "與君期戮力，起廢鍼其肓。", "相將入山中，采薇以爲糧。"]'),
('8f7080b6-3ea4-451d-9c1c-bee4229cb217','再用前韻','郭印','宋','宋诗','song-poetry','','[]','少年讀書時，人謂未可量。',192,'全唐诗/poet.song.95000.json','["少年讀書時，人謂未可量。", "及乎泛官海，慄慄乘危航。", "帆開風不順，四望何淼茫。", "爲郎首已白，安能笑馮唐。", "緬觀乾坤大，分明一戰場。", "何異兩虎鬭，大小終死傷。", "所嗟在誅求，舐米不止糠。", "窮甿愁歎聲，深秋聽蛩螿。", "皇穹未悔禍，尚縱兵戈猖。", "遂令四海人，冥行日倀倀。", "得非宿世業，今生來共償。", "否極泰自至，君臣嚴陛堂。", "肯爲阮籍醉，忍效接輿狂。", "似聞申甫生，天遣佐宣王。", "一展活國手，疾危救在肓。", "庶幾富斯民，家家有餘糧。"]'),
('f2de433b-ea17-4fdb-adad-3b0bbf7517ef','和于子儀觀見贈二十韻','郭印','宋','宋诗','song-poetry','','[]','壯歲悟修性，磨礲謝圭角。',240,'全唐诗/poet.song.95000.json','["壯歲悟修性，磨礲謝圭角。", "墮身塵網中，意氣翔寥廓。", "動遭白眼觀，罕識黄金諾。", "聖賢皆吾心，所讀真糟粕。", "妙處誰與語，此道今蕭索。", "西施及嫫母，本身非美惡。", "掩關學宴坐，浩氣合沖漠。", "身世鴻毛輕，利名蟬翼薄。", "兀兀寡知音，頭童齒將豁。", "向未得良友，盃酒屢同酌。", "見我輙傾倒，清音聽明鐸。", "馬隊驤天驥，鷄群昻野鶴。", "新詩續風騷，久矣無此作。", "詞鋒敏而鋭，百獻敢一酢。", "願君偃戈矛，使我堅城郭。", "中虛道自來，大信本不約。", "養兹百鍊金，刼火難銷鑠。", "心法兩俱忘，無解亦無縛。", "參乎一以貫，回也不改樂。", "富貴何足云，侯門空赭堊。"]'),
('0e6e65d0-5e8b-45a6-932e-01fd149b4ad6','少虛用前韻見貽仍答二首  其一','郭印','宋','宋诗','song-poetry','','[]','别君歲月多，萬事皆非昔。',144,'全唐诗/poet.song.95000.json','["别君歲月多，萬事皆非昔。", "天昏慘暮雲，愁緒繁堪織。", "豈期成東隣，日造芝蘭室。", "吟哦戒騷奴，揮灑驚墨客。", "猶嫌小伎耳，宴坐學欺魄。", "人間倐流電，悟此真良策。", "堂堂少林老，我豈得其骨。", "君來叩兩端，一笑非言默。", "超然反其真，游子歸故宅。", "玄機儻未領，對面千山隔。", "象罔亦何心，珠還赤水北。", "聖賢勿云遠，謦咳常在側。"]'),
('9b668165-521c-46ba-b8ff-d9a15b4fd530','少虛用前韻見貽仍答二首  其二','郭印','宋','宋诗','song-poetry','','[]','倦游思林泉，歸夢空昔昔。',144,'全唐诗/poet.song.95000.json','["倦游思林泉，歸夢空昔昔。", "田無二頃良，何以充耕織。", "古來貴公子，氣熖熏王室。", "家饒數百僮，門走三千客。", "志滿釁日生，坐使天奪魄。", "我今安下僚，倖進無奇策。", "空懷愛主心，但欠封侯骨。", "躍金恐不祥，守道甘沈默。", "岷山高峨峨，其下可卜宅。", "地靈雲物秀，似與塵凡隔。", "誅茅存晚計，好在西巖北。", "每逢風雨夜，念此空反側。"]'),
('41a487b6-94c7-45cc-9606-92d900d989cc','當可有詩索和章次韻答之','郭印','宋','宋诗','song-poetry','','[]','日斜弄孤桐，妙趣寄無絃。',120,'全唐诗/poet.song.95000.json','["日斜弄孤桐，妙趣寄無絃。", "暮天四垂幕，溪山當華筵。", "碧玉湛新醪，招集飲中仙。", "雲車夜未散，短燭蟠青煙。", "合坐皆豪俊，風流踵前賢。", "佳客吾豈敢，追陪幸自天。", "人材未易得，終夜喜不眠。", "殊特見騷雅，武庫森戈鋋。", "未能當筆陣，敢發一矢先。", "來意何以報，慚無錦段鮮。"]'),
('73a7f79b-f918-4f04-b1a7-2a25012f86f2','次韻劉中遠見貽之什','郭印','宋','宋诗','song-poetry','','[]','中原殺氣昏，魚鳥巢穴改。',144,'全唐诗/poet.song.95000.json','["中原殺氣昏，魚鳥巢穴改。", "城池失金湯，郡邑更守宰。", "鸞旗狩吳越，朔騎滿淮海。", "維蜀限山川，無人識鍪鎧。", "五年愧端居，萬里思行在。", "官曹敢尸素，職事甘煩猥。", "儻得容棲遲，奚暇擇爽塏。", "陋巷飽簞瓢，隣墻挹蘭茝。", "新詩出清奇，高論吐雄邁。", "談諧不知倦，氣充無是餒。", "藉君風飄颻，祛我雲靉靆。", "相期樹勳名，戮力熙帝載。"]'),
('3e2bbc2a-ed35-4bd6-883a-45c6bf47c8f6','次韻宋南伯見貽之什','郭印','宋','宋诗','song-poetry','','[]','衰遲來作邑，勞苦劇萬狀。',240,'全唐诗/poet.song.95000.json','["衰遲來作邑，勞苦劇萬狀。", "朝朝趁衙參，歛版趨踉蹡。", "病驥耳雙垂，蘭筋困銜鞅。", "饑鷹長附人，六翮空韝上。", "緬思陶彭澤，解綬一何壯。", "歸去事田園，林木施幃帳。", "隣曲喜過從，時節爭餽餉。", "高山與流水，無日不尋訪。", "况逢桃李春，協氣郊原盎。", "或携古笻行，或放孤舟漾。", "我欲追其蹤，卜築依清曠。", "三徑落松花，四墻圍竹筤。", "縛橋架斜川，鑿戶延層嶂。", "長笛月下吹，逸響從風颺。", "興來攜野老，爛醉傾村釀。", "便足了一生，折腰寧肯強。", "十年計未遂，口腹成魔障。", "蹉跎鏡中秋，白髪不相放。", "新交得山濤，磊落多識量。", "志趣儻能同，斯文未淪喪。"]'),
('d7274718-b99b-40ea-b08d-7d7d2d8e8b11','次莫少虛韻','郭印','宋','宋诗','song-poetry','','[]','富貴等勞生，不如行樂耳。',192,'全唐诗/poet.song.95000.json','["富貴等勞生，不如行樂耳。", "遑遑觀一世，榮辱隨僨起。", "幽尋苦無暇，佳處誰屈指。", "春歸呼我游，邂逅佳公子。", "莫侯江南秀，幽香發蕙茝。", "新詩更清激，㶁㶁寒流駛。", "錦屏有蒲郎，冰壺清徹底。", "便腹久空洞，了不見嗔喜。", "歲晚得二友，追隨當行李。", "五湖三江寛，亦不遺洲沚。", "偶來泛扁舟，朱墨推案几。", "徜徉一水間，便欲寄殘齒。", "追觀少年心，寂寞已灰死。", "窮通豈無命，流坎聽行止。", "岷山行築室，計决吾往矣。", "斗酒相往還，素約自今始。"]'),
('11370a28-8d17-41fa-861d-4fe9faa3e8dd','次蒲大受檢覆韻','郭印','宋','宋诗','song-poetry','','[]','身親掃除役，敝袍染塵泥。',96,'全唐诗/poet.song.95000.json','["身親掃除役，敝袍染塵泥。", "青雲一何高，天險不可躋。", "西風吹秋來，草木含凄凄。", "韝鷹屢飛掣，櫪馬空鳴嘶。", "丈夫兩鬢斑，籍未通金閨。", "不如買田園，荷鍤理蔬畦。", "歲月無停軌，歸計亦已稽。", "年來稍聞道，所學忘筌蹄。"]'),
('d0992bf9-da98-45bd-9312-368e4020bad7','次韻彦正兄見寄','郭印','宋','宋诗','song-poetry','','[]','轉食柅東州，安閑遂忘歸。',96,'全唐诗/poet.song.95000.json','["轉食柅東州，安閑遂忘歸。", "蘭齋寒燈話，忽作一年違。", "江流鯉魚遠，但見鴻雁飛。", "緘封一再啟，字字蠅頭微。", "書詞與詩意，髣髴聆音徽。", "君如初生月，浮雲翳其輝。", "清光畢竟滿，安用長噓欷。", "勉哉辨此心，正直神所依。"]'),
('8f84d626-ae06-4782-b0f2-4d3cc3892a78','次何耕道韻','郭印','宋','宋诗','song-poetry','','[]','壯歲已倦游，况今老大時。',120,'全唐诗/poet.song.95000.json','["壯歲已倦游，况今老大時。", "素交久離索，勞思何可支。", "夫子晚識面，迥非塵中姿。", "高言風凛凛，直氣山巍巍。", "欲登公卿門，進退尚狐疑。", "飄然至是邦，爲言某在斯。", "相見無別事，清談白日移。", "時時矜小技，挽我賦新詩。", "自憐憔悴態，容德愧姜姬。", "辱贈何以報，恨無瓊琚辭。"]'),
('b18cf56c-3767-4c41-b0ee-e04c082d7fa7','次楊拱辰韻兼簡馮可當劉韶美','郭印','宋','宋诗','song-poetry','','[]','窮居罕人事，來往斷交親。',288,'全唐诗/poet.song.95000.json','["窮居罕人事，來往斷交親。", "粗安鷦鷯居，靡求尺蠖伸。", "坐看柴門外，日飛車馬塵。", "誰能學桔橰，俯仰更隨人。", "况今世道喪，風俗已澆淳。", "爲民非野鹿，作吏無古循。", "太倉五斗粟，食之愧高旻。", "故人善處我，儒官飽常珍。", "風月即儕侣，詩書乃比鄰。", "隤然一室中，浩氣横八垠。", "劉郎晚相遇，放曠如逐臣。", "素心日傾倒，吟嘯樂天真。", "粃糠嵇阮輩，自號葛天民。", "馬曹似是耳，寧畏官長嗔。", "墨池子楊子，風流吾里仁。", "偶來官一邦，眉端喜津津。", "抵掌論進修，德業須競辰。", "有時相就飲，幕天地爲茵。", "馮君十年别，龍鵠迹久陳。", "邂逅果山底，一見兩腳踆。", "初來梅蕚吐，欲去柳眉顰。", "平生知識多，斯人罕其倫。", "我今亦西矣，笻竹訪峨岷。", "憑誰與之俱，足跣頭不巾。"]'),
('dfb9eb71-5e51-4ffb-b095-d782425fd942','和元汝功元日感懷','郭印','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','少時喜節物，常恨春來遲。',144,'全唐诗/poet.song.95000.json','["少時喜節物，常恨春來遲。", "而今新年至，懷抱不勝悲。", "兒童薦椒酒，未飲增長欷。", "陜洛果何罪，半世戎馬嘶。", "坐令冠盖流，星散鳥擇棲。", "回頭望鄉國，淚雨秋悽悽。", "我公關中豪，志氣青雲齊。", "誓當剪豺狼，不復問狐狸。", "夫何丘壑間，從事酒與詩。", "煙塵要一掃，櫜弓卧鼓鞞。", "天下維泰山，置器安不危。", "廓廓大丈夫，功勳千載奇。"]'),
('089177cd-a01f-4234-bd68-2521ff32617c','正月初八日同莫少虛蒲大受王園泛舟各賦二首  其一','郭印','宋','宋诗','song-poetry','','[]','春江晚多思，拂面風稜稜。',144,'全唐诗/poet.song.95000.json','["春江晚多思，拂面風稜稜。", "舟行明鏡中，天水同一澄。", "滄波濯新柳，喬松上寒藤。", "風梅雪飄徑，兩麥青平陵。", "文魴自潛躍，好鳥相喚譍。", "倥偬日少暇，因循來未曾。", "清游鄙謝傅，豪氣壓陳登。", "豈惟得佳士，亦復同高僧。", "幽情各披寫，醉語或侵凌。", "偶兹愜懷抱，蕭然遺愛憎。", "曠野暝煙合，長林初月升。", "回舟興未已，孤塔耿疏燈。"]'),
('538b7612-764b-43e2-ae06-ef105e61097a','正月初八日同莫少虛蒲大受王園泛舟各賦二首  其二','郭印','宋','宋诗','song-poetry','','[]','名園春信來，冷眼思一窺。',168,'全唐诗/poet.song.95000.json','["名園春信來，冷眼思一窺。", "吏文巧束縛，穎脱迺不覊。", "興發勇欲往，壯士先登埤。", "但得一樽樂，豈論官職卑。", "况兹横清流，適然副心期。", "梅梢出翠竹，照水兩猗猗。", "野航轉澄碧，小雨斜風吹。", "平生江海懷，是日慰渇饑。", "村迥孤煙處，林深幽鳥時。", "端疑是吳越，夢到身亦隨。", "同遊客靡惡，喜氣回朝曦。", "醉倒不自惜，一葉忌傾欹。", "新詩許共賦，未唱心力疲。", "歸來已陳迹，物理觀盛衰。"]'),
('65553e18-fb84-4e05-8862-9857832c37d4','和蒲大受王園泛舟用文老韻  其一','郭印','宋','宋诗','song-poetry','','[]','邑西屋連雲，中有水竹居。',48,'全唐诗/poet.song.95000.json','["邑西屋連雲，中有水竹居。", "和風縱輕楫，尚憶故年初。", "川光宛明媚，况乘春雨餘。", "臨波一以照，颯颯鬢毛疏。"]'),
('42ca5dc4-2ef1-4a92-b630-7dd3cea71e86','和蒲大受王園泛舟用文老韻  其二','郭印','宋','宋诗','song-poetry','','[]','江邊春色動，水面縠文生。',48,'全唐诗/poet.song.95000.json','["江邊春色動，水面縠文生。", "陽和先着力，岸柳摇金晶。", "草木有欣意，人心隨物情。", "日暮不知返，逍遥興彌清。"]'),
('97a5e3ac-c026-4c30-ad12-febdc4692b4c','和蒲大受王園泛舟用文老韻  其三','郭印','宋','宋诗','song-poetry','','[]','古木卧偃蹇，脩篁立蔥青。',48,'全唐诗/poet.song.95000.json','["古木卧偃蹇，脩篁立蔥青。", "春風渺無迹，林鳥報先聲。", "篙師任沿泝，潭紋亂虛明。", "佳人更吟詠，洗我塵慮清。"]'),
('6a981a79-9d0f-46bd-9a54-768cca5f9d14','和蒲大受王園泛舟用文老韻  其四','郭印','宋','宋诗','song-poetry','','[]','平生喜閑曠，夢想祗山林。',48,'全唐诗/poet.song.95000.json','["平生喜閑曠，夢想祗山林。", "曲江理煙艇，魚鳥皆知音。", "晴天亂鳬鶩，相呼時一沉。", "油然淵中鱗，潛伏恐不深。"]'),
('4b7129e4-b41f-4f07-af8e-537957d02491','和蒲大受王園泛舟用文老韻  其五','郭印','宋','宋诗','song-poetry','','[]','晚風江色佳，水碧煙冥冥。',48,'全唐诗/poet.song.95000.json','["晚風江色佳，水碧煙冥冥。", "聊持一壺酒，落日相與傾。", "浮榮何預人，於焉樂此生。", "往來信扁舟，恍若空中行。"]'),
('007d95b9-646d-432d-950b-1cec7995f19c','感春','郭印','宋','宋诗','song-poetry','','[]','百花感陽和，次第變枯槁。',96,'全唐诗/poet.song.95000.json','["百花感陽和，次第變枯槁。", "寒梅秀臘前，紅葉媚春杪。", "無端造化兒，戱劇何小小。", "迎春復送春，堪笑枝間鳥。", "我以虛靜觀，一室乾坤悄。", "平生誦聖言，聞道亦頗早。", "了兹色相空，寧復問先後。", "冥心大化俱，左肘從生柳。"]'),
('0258644f-2a55-4438-9b60-f8c3e292207a','中秋月','郭印','宋','宋诗','song-poetry','','[]','蕭蕭灝氣清，風露秋將半。',96,'全唐诗/poet.song.95000.json','["蕭蕭灝氣清，風露秋將半。", "今夕更無雲，銀盤轉霄漢。", "鳥語茂林驚，樹影空庭亂。", "常時豈不佳，作意人瞻翫。", "我欲上廣寒，瑤瓊躡飛觀。", "騎鯨諒不能，永夜空慨歎。", "歸來卻燕坐，神光自輝煥。", "始知方寸間，桂闕元非遠。"]'),
('0ca0806c-4582-491c-b497-82272d159c53','中秋馬溪山中望月','郭印','宋','宋诗','song-poetry','','[]','佳月四時有，古來重中秋。',144,'全唐诗/poet.song.95000.json','["佳月四時有，古來重中秋。", "今夕萬里懷，共作陰霾憂。", "我宿招提境，山空夜更幽。", "兹念亦未掃，天際屢回頭。", "冰輪湧碧空，宇宙寒颼颼。", "清輝聊一吸，洗盡肝膽愁。", "山中魑魅窟，驚竄無所投。", "自言天眼明，此地非我留。", "緬思區域內，醜怪繁匹儔。", "不知大圓影，能盡驅除不。", "仰首祝天公，勿遣纖雲浮。", "縱此白玉盤，年年照九州。"]'),
('5dc8674d-384a-45e0-b25b-92212155add3','中秋月試院中作呈莫少虛','郭印','宋','宋诗','song-poetry','','[]','月色本無别，殊觀空世情。',168,'全唐诗/poet.song.95000.json','["月色本無别，殊觀空世情。", "今宵雲四卷，冰蟾照寰瀛。", "無端坐文闈，兀若翳雙睛。", "窺牗偶一見，始驗陰陽并。", "孤光何自來，遡日以爲明。", "三五魄既絕，輪郭自充盈。", "循環到今夕，逢金氣轉清。", "乃知造物意，微妙不可名。", "伊余稟賦初，二曜同流行。", "呼吸即寒暑，乾坤屹崢嶸。", "隋珠彈高鳥，惜哉輕此生。", "恨無騰化術，返老成童嬰。", "要須驗羲易，觀象研其精。", "聖處儻心悟，超然合混成。"]'),
('0742d365-e3fa-45b9-95dc-ca558c14dfa1','次韻莫少虛中秋月','郭印','宋','宋诗','song-poetry','','[]','纖阿駕秋空，雲散無一髪。',168,'全唐诗/poet.song.95000.json','["纖阿駕秋空，雲散無一髪。", "長廊步清影，露頂腳不襪。", "緬懷同心人，尺咫限胡越。", "豈殊南郭老，連墻不通謁。", "我憂今夕去，難得如此月。", "佇立耿不寐，精誠通恍惚。", "莫兄新詩來，夜光映深樾。", "頗驚筆力壯，滔滔漲溟渤。", "喜極屢索酒，引滿非人罰。", "醉歌還起舞，恍若換凡骨。", "何當乘飛雲，舉手探蟾窟。", "一吸徑寸光，盡解平生暍。", "飄飄曵霞裾，出入黄金闕。", "陋哉揖爽氣，空拄西山笏。"]'),
('00193e89-4f62-4cda-8503-c246c945ae41','再用前韻','郭印','宋','宋诗','song-poetry','','[]','我生垂四十，兩鬢抽素髪。',168,'全唐诗/poet.song.95000.json','["我生垂四十，兩鬢抽素髪。", "聲色不掛眼，豈羡凌波襪。", "唯有學道心，了不見超越。", "何由插羽翰，往造金門謁。", "反觀金水性，端似天邊月。", "本從無中來，一物肇恍惚。", "玉兔吐寒光，琪樹遥清樾。", "亭亭照八紘，圓影射滄渤。", "斯言世豈聞，輕泄恐天罰。", "吁嗟夸毗子，自分無仙骨。", "狥財析秋毫，嗜酒醉深窟。", "一迷不復返，長病如中暍。", "空存玄牝門，金樞已摧闕。", "猶爲兒女計，白首戀簪笏。"]'),
('48b10608-f06c-440b-afd9-276dde54082c','少虛以中秋有月預作詩亦次韻矣而月不爲出因成數語以解前篇','郭印','宋','宋诗','song-poetry','','[]','兹辰陰雨霽，佳月望雲端。',120,'全唐诗/poet.song.95000.json','["兹辰陰雨霽，佳月望雲端。", "徹燈不掩戶，佇對清輝寒。", "嫦娥豈誤人，出入由天關。", "天應怕鐫鑱，故將好景慳。", "坐久成歎息，邂逅一何艱。", "收視照肝肺，中有白玉盤。", "光明無與比，通昔夢魂安。", "君今先悟此，一笑定忘言。", "雖云形影隔，是心常往還。", "前詩非游戱，勿作綺語觀。"]'),
('855ac0fa-9ef8-47ca-a3ab-9129849e35c4','再用前韻以謝諸公見答之什','郭印','宋','宋诗','song-poetry','','[]','三賢富文詞，獻笑發其端。',120,'全唐诗/poet.song.95000.json','["三賢富文詞，獻笑發其端。", "瓦礫換瓊瑤，光照窗几寒。", "熒煌句中眼，真透祖師關。", "孺子或可敎，傾倒無用慳。", "嗟余腹空虛，思苦言亦艱。", "豈如新詩章，字字珠走槃。", "同門法禁嚴，欲往心未安。", "跬步乃千里，髣髴聞笑言。", "憑誰寫胸臆，錦囊去復還。", "步海吾豈憚，波瀾時一觀。"]'),
('5a1f0ad8-e9c2-46db-b9be-72a882c25ce5','九日詩','郭印','宋','宋诗','song-poetry','','[]','去年今日好，在家作重陽。',180,'全唐诗/poet.song.95000.json','["去年今日好，在家作重陽。", "佳菊嗅金蘂，濁酒篘瓊漿。", "婦子相提攜，江臯步晚凉。", "頗思一遠眺，平原欠崇岡。", "今年九日惡，踆踆走路傍。", "即無新釀白，豈有半開黄。", "老婦與弱子，千里遥相望。", "登臨眼雖飽，四顧斷人腸。", "自憐如浮雲，天風久飄揚。", "世間功名夢，一枕猶未償。", "而此蒲柳年，餬口落四方。", "五斗計何拙，饑烏謀稻粱。", "况復事塵土，險艱皆備嘗。", "家有二頃田，可耕亦可桑。", "賦租願少鐫，翩然歸故鄉。"]'),
('03fd73f7-d322-49dd-a3b4-7005135fb70e','九日同諸友游豐樂院翠圍亭檻前竹樹蓊蔽命僧剪除青山宛然復出遂以開林出遠山爲題探韻印得林字','郭印','宋','宋诗','song-poetry','','[]','築亭邀青山，眷此幽意深。',144,'全唐诗/poet.song.95000.json','["築亭邀青山，眷此幽意深。", "十年廢掃除，木拱竹成林。", "客來眼生翳，不惜斤斧尋。", "丁丁度餘響，几席延嶔崟。", "一掌開平川，雙鬟出高岑。", "初疑白日晦，坐頃失繁陰。", "虛壁蕩晴影，耿耿明衣襟。", "是時菊花節，悠然副登臨。", "殘霞映夕酌，幽籟隨清吟。", "人情異晨夕，山色無古今。", "世間諸法空，通塞本由心。", "勉揮金寶劔，勿使茅葦侵。"]'),
('f0bd0909-8504-4274-a663-8e1ca0ad98dc','九月二十日率趙彦和王平叔劉誼夫遊棲巖寺彦和有詩次其韻','郭印','宋','宋诗','song-poetry','','[]','少時苦愛山，藜杖春復秋。',144,'全唐诗/poet.song.95000.json','["少時苦愛山，藜杖春復秋。", "峰巒如佳人，一顧銷百憂。", "野性不受覊，思與麋鹿遊。", "失腳名宦場，冠纓絡人頭。", "州家費經營，心輪日萬周。", "遇陰求少息，此身等蜉蝣。", "頗聞西山佳，往作半日留。", "小徑開宇宙，髣髴規神州。", "萬象几席間，雲煙渺沉浮。", "同來三益友，清逸詩家流。", "相期老巖穴，委質巢與由。", "吾廬有雲溪，拂袂行歸休。"]'),
('bbde00df-a634-448d-9feb-4d09b3dd1dfb','朝日','郭印','宋','宋诗','song-poetry','','[]','雞號出郊坰，殘月猶未沒。',168,'全唐诗/poet.song.95000.json','["雞號出郊坰，殘月猶未沒。", "東方迤邐明，林表上初日。", "團圓狀車盖，光射半天赤。", "我時決兩眥，喜極還歎息。", "邇來天令乖，宇宙秋霖積。", "陰霾翳扶桑，不放翔陽逸。", "行者厭泥塗，耕者憂稼穡。", "官卑何所爲，坐視空戚戚。", "金烏忽飛曉，光曜宛如昔。", "須臾一鏡昇，煙霧眇無迹。", "八紘頓清明，萬象趨烜赫。", "人情絕愁歎，熙熙遍阡陌。", "無端南山雲，尚恐復蒸欝。", "安得大力士，長挽羲和出。"]'),
('9d560623-4632-48fc-8f23-95e168f8effd','晚晴','郭印','宋','宋诗','song-poetry','','[]','朝來寒露重，旭日慶新晴。',120,'全唐诗/poet.song.95000.json','["朝來寒露重，旭日慶新晴。", "長空煙靄凈，遙岑錦繡明。", "野競農夫穫，路多游子行。", "歲事竟如何，且欲供粢盛。", "矧彼關外戍，仰哺十萬兵。", "糧運儻不絕，因緣活此生。", "吾家有瘠田，努力事躬耕。", "寧辭畎畝勞，每作風雨驚。", "心期了租賦，敢望倉箱盈。", "耋齡無多日，妄意觀太平。"]'),
('e835a51c-da22-463d-8c3b-01d14477fb33','馮當可以日暮碧雲合佳人殊未來效建除體作詩招勝之且索同賦因用其韻','郭印','宋','宋诗','song-poetry','','[]','日色久無光，霖霪更彌旬。',120,'全唐诗/poet.song.95000.json','["日色久無光，霖霪更彌旬。", "暮空出華月，秋氣生精神。", "碧天湛如水，山川供奇珍。", "雲韶髣髴奏，嗈嗈鴻雁賓。", "合歡亦有酒，寫景招四隣。", "佳篇一諷誦，逸氣凌蒼旻。", "人龍憶許子，枉駕定何辰。", "殊方思會面，語笑情益親。", "未聞環珮音，懷想空谷人。", "來成六溪逸，氣合同天倫。"]'),
('4b5ad3a4-6cca-49a9-867a-172a6cd8f650','恭南酷熱','郭印','宋','宋诗','song-poetry','','[]','陰陽有定數，天地無全功。',192,'全唐诗/poet.song.95000.json','["陰陽有定數，天地無全功。", "偏雨或偏暘，消息豈難窮。", "今夏孟仲雨，季月暑隆隆。", "赫曦不停軌，火雲日燔空。", "晨興迨晚暮，危坐沸鼎中。", "一夕四五起，倦鳥思逃籠。", "扇手腕幾脱，所招皆温風。", "年來復何罪，遭此爐炭烘。", "迅雷空殷殷，微雨秪濛濛。", "燋燃到草木，禾稻憂不豐。", "頗聞炎瘴地，威勢增祝融。", "又聞大熱獄，食飲渾洋銅。", "法法惟心造，報應萬不同。", "吾家有雲溪，竹間二水通。", "入門爽毛骨，清絕廣寒宫。", "插羽欲飛去，免爲旱魃攻。"]'),
('ebf26f61-d3a3-4903-b8fe-2e46f5845ce1','和元汝功晚凉城上','郭印','宋','宋诗','song-poetry','','[]','潛鱗思縱壑，倦羽欲歸林。',120,'全唐诗/poet.song.95000.json','["潛鱗思縱壑，倦羽欲歸林。", "平生山水興，過眼必登臨。", "况復西風來，天雲布層陰。", "殘暑退十舍，新凉直萬金。", "寒光流素魄，遠碧露危岑。", "高士感時節，忘言發幽琴。", "子期不可作，天地知吾心。", "林木爲之振，人間無此音。", "詩成寄孤客，清飇一披襟。", "會當逢好景，藜杖去相尋。"]'),
('20abcd96-4a7d-4c80-b41a-896481db01b2','久雨','郭印','宋','宋诗','song-poetry','','[]','乾坤冷氣積，無日不陰雨。',120,'全唐诗/poet.song.95000.json','["乾坤冷氣積，無日不陰雨。", "涔涔晝連宵，簷聲暗砧杵。", "田間愁老農，道上泣行旅。", "首尾四周旬，泥深污后土。", "有時暫止息，無奈雲仍聚。", "晴陽出復沒，明滅見林莽。", "萬事姑置之，所傷在秋稌。", "何歲無凶荒，中原尚豺虎。", "軍食竟不充，饋餉尤艱苦。", "稽首望羲和，披陰照寰宇。"]'),
('6b07c8a4-2003-445a-b6ca-9e6ebdab2b55','亦樂堂','郭印','宋','宋诗','song-poetry','','[]','君子素位行，窮通等寒暑。',96,'全唐诗/poet.song.95000.json','["君子素位行，窮通等寒暑。", "漠然隨所寄，廊廟即環堵。", "姬孔彼何人，名德照今古。", "若以優劣觀，此論吾不與。", "鄙夫晚聞道，行藏心自許。", "白髪尚婆娑，青衫久藍縷。", "雞鳴意在晨，寧復問風雨。", "樂天夫何憂，貴賤同歸土。"]'),
('aca1b81a-9345-40fd-adf2-1fd81f6ba9cd','自堂詩爲張億作','郭印','宋','宋诗','song-poetry','','[]','大道絕群倫，古今無匹配。',144,'全唐诗/poet.song.95000.json','["大道絕群倫，古今無匹配。", "張子涉其源，超然意冥會。", "宴坐一堂空，乾坤皆破碎。", "八荒自神遊，萬法非我對。", "眼前欝崢嶸，毫髪了無礙。", "揭名諒真實，舉首誰領解。", "咄哉愚癡兒，矜已妄尊大。", "一念思遺物，胸次先憒憒。", "不見南榮趣，偕來還幾輩。", "顛倒欲何之，卻走山愈背。", "吾今識子綦，獨立形骸外。", "寂寥千載餘，光采炯如在。"]'),
('2b96978f-8266-43b9-b92b-700e9fa54ba3','李文山書堂','郭印','宋','宋诗','song-poetry','','[]','蓄書不能讀，人以書簏方。',144,'全唐诗/poet.song.95000.json','["蓄書不能讀，人以書簏方。", "譬如守錢奴，萬鏹空靳藏。", "讀書不能行，虎皮質犬羊。", "詩禮假發冡，高言誣黄唐。", "我觀古聖賢，道學甘膏粱。", "文字初未廣，游心自得場。", "後人富典籍，洛誦日洋洋。", "唇腐無所歸，白首徒悲傷。", "普慈群圃勝，中間敞華堂。", "本非挾冊地，賓筵羅豆觴。", "揭名意安在，詩板借輝光。", "斵輪如可作，試與一平章。"]'),
('b15761f9-bd70-4960-8dce-884edc85815d','横翠堂成與諸公落之蒙貺佳篇不敢當也謾作數語以紀其實','郭印','宋','宋诗','song-poetry','','[]','何處無奇觀，隱顯隨所遇。',240,'全唐诗/poet.song.95000.json','["何處無奇觀，隱顯隨所遇。", "事有幸不幸，邂逅元非素。", "招提枕山趾，出郭纔數步。", "高亭齊浮雲，杖策邀我屢。", "西廂偶徘徊，屋敝驚頹仆。", "穴壁試一窺，似覺萬景聚。", "同來老先生，錯愕喜相顧。", "明朝便鳩工，棟宇更尋度。", "華堂不日成，雜沓千山赴。", "落日下層巔，寒烟籠遠樹。", "乾坤發祕藏，物象爭呈露。", "爛賞良未能，草略杯盤具。", "群公意盡歡，韻語各吟賦。", "和氣回陽春，篇篇奏韶濩。", "堂以横翠名，誇詫盈道路。", "人材何異此，用舍得其趣。", "渭濱一釣夫，起爲周室輔。", "皇皇魯真儒，終以不合去。", "聖道奚加損，山亦無新故。", "廢興適然耳，萬事成感悟。"]'),
('e0d99783-ee50-474c-8d31-9c5d816917db','草堂','郭印','宋','宋诗','song-poetry','','[]','草堂何處覓，雲黯浣花溪。',120,'全唐诗/poet.song.95000.json','["草堂何處覓，雲黯浣花溪。", "棟宇已非昨，松竹尚依依。", "荒坡卧頹日，寒浪摇清颸。", "萬象不禁寫，吟哦想當時。", "我公本天人，造化生肝脾。", "道大世不容，遠跡西南維。", "波濤湧筆端，孤憤寄新詩。", "詩中盡經濟，秋毫未設施。", "後人不知公，但賞瓊琚詞。", "文章一小技，于道信爲卑。"]'),
('7ecdb0e4-0dea-4420-82b1-ee3e671290eb','山齋','郭印','宋','宋诗','song-poetry','','[]','我本丘壑姿，脱巾爲謀食。',168,'全唐诗/poet.song.95000.json','["我本丘壑姿，脱巾爲謀食。", "隨牒幾推遷，銅章領巖邑。", "初期竊餘閑，焚香弄書冊。", "文法何苦多，日力不暇給。", "訟紙秋葉翻，使符星火急。", "自憐拙追科，難復濟繁劇。", "秋毫殊未試，直道聊抆拭。", "白眼已紛紛，丹心猶汲汲。", "要令四萬家，實惠涓塵及。", "怒罵奚足云，此意天應識。", "西齋靚且深，於焉少游息。", "幽獨誰相對，古壁蒼崖立。", "高人喜過從，玄論揮八極。", "世情一笑休，欲語不如默。"]'),
('8f4fe7ba-a7a3-4515-b538-a2c5b4410494','仁壽縣治新開小軒以琴中趣名之用趣字韻賦之','郭印','宋','宋诗','song-poetry','','[]','淵明識琴心，徽絃總不具。',96,'全唐诗/poet.song.95000.json','["淵明識琴心，徽絃總不具。", "興發時撫弄，悠然得真趣。", "杳然太古音，充滿一切處。", "吾今琴亦亡，至樂隨所寓。", "調此方寸微，物物盡和豫。", "一奏萬化熙，再奏九功敘。", "大聲越宫商，俗耳恐難喻。", "單父不下堂，陽春被黎庶。"]'),
('02adddf4-960d-42f8-af56-892207dc6901','次韻蒲大受琴中趣二首  其一','郭印','宋','宋诗','song-poetry','','[]','二器入範圍，物物皆吾琴。',96,'全唐诗/poet.song.95000.json','["二器入範圍，物物皆吾琴。", "外響藴真寂，中虛含妙音。", "世人若著相，正墮聲色林。", "那知反聽處，萬象融一心。", "伊余晚聞道，奇病得聾瘖。", "詩成自吟詠，酒熱誰獻斟。", "山高水洋洋，子期亦已沉。", "燕坐忽神遊，月明秋夜深。"]'),
('3cd1eb27-ad4e-44ca-be93-00417f94c01e','次韻蒲大受琴中趣二首  其二','郭印','宋','宋诗','song-poetry','','[]','人生飲天和，各抱無絃琴。',96,'全唐诗/poet.song.95000.json','["人生飲天和，各抱無絃琴。", "云何不自開，溺彼宫商音。", "鄭衛劇淫哇，聽者返如林。", "耳根一以蕩，萬刼迷真心。", "安得佛之力，與世開群瘖。", "神機運帝車，元氣如酌斟。", "魚鳥得其性，雲淵自飛沉。", "不見南風歌，仁聲入人深。"]'),
('020478cc-1b1f-4089-b698-fb442b4d1535','新開小軒晁子西有詩以韻答之二首  其一','郭印','宋','宋诗','song-poetry','','[]','平生棲息地，往往旋修築。',144,'全唐诗/poet.song.95000.json','["平生棲息地，往往旋修築。", "爲憐雙凈眼，不肯受羈束。", "官居鑿小軒，容膝盖已足。", "於焉得逍遥，內視聊自牧。", "廓廓乾坤大，冥冥鬼神服。", "是心不違仁，如種五穀熟。", "乃知窮且賤，未必不爲福。", "朋僚餉新詩，句法驚小陸。", "秀色增雲山，榮光發林木。", "何妨曵杖來，斯樂未敢獨。", "清談可以飽，豈但蠲煩促。", "非必酒與肴，佳客始能速。"]'),
('a349ec42-0d5f-4447-a522-bf58c8a4f3cc','新開小軒晁子西有詩以韻答之二首  其二','郭印','宋','宋诗','song-poetry','','[]','我無先世英，敢望燕臺築。',144,'全唐诗/poet.song.95000.json','["我無先世英，敢望燕臺築。", "譬如坎井蛙，拘虛徒窘束。", "又如鷦鷯巢，所寄一枝足。", "名不聞公卿，迹非侣樵牧。", "眼花鬢毛霜，黽勉作侯服。", "吏才固不高，民事亦稍熟。", "每欲思寡過，豈敢求多福。", "群公遲風雲，行矣龍起陸。", "佳篇雜沓來，文繡被土木。", "坐令北窗下，不知有窮獨。", "相逢一笑粲，語妙席自促。", "憑誰覓仙方，造酒逡巡速。"]'),
('0e71e0d1-40b8-463f-b38e-06de9fd921cf','題蘇慶嗣睡樂軒','郭印','宋','宋诗','song-poetry','','[]','六鑿森劍戟，一枕寄華胥。',144,'全唐诗/poet.song.95000.json','["六鑿森劍戟，一枕寄華胥。", "覺夢既殊轍，睡兮真樂歟。", "達人藴大觀，方寸包太虛。", "憂樂兩不知，寤寐常如如。", "昔也蝶栩栩，今焉周蘧蘧。", "而於我法中，無欠亦無餘。", "以睡爲樂耶，不睡寧悲渠。", "然則此軒名，無乃滯一隅。", "蘇子笑而應，斯豈真吾居。", "飄流閲世故，早識心地初。", "今古一偃仰，天地一蘧廬。", "揭名聊爾耳，至言恐驚愚。"]'),
('c93c33d2-5ca0-442a-9047-800a8b2c9c99','楊隱父新開竹軒賦詩遺之','郭印','宋','宋诗','song-poetry','','[]','擢幹傍東崗，窮年閟幽獨。',96,'全唐诗/poet.song.95000.json','["擢幹傍東崗，窮年閟幽獨。", "寒分渭水烟，瑩矗藍田玉。", "鑿戶清飇來，秀色鮮可掬。", "羈人初一見，洗盡塵土目。", "中心已空洞，勁節秋仍綠。", "相期老歲寒，榮悴從草木。", "堅姿恐爲用，扶危度深谷。", "化龍生雲雨，豈止鸞鳳宿。"]'),
('9af8e76b-57c8-470f-94d7-a5d44ccffbe5','隱父見示和章再用前韻','郭印','宋','宋诗','song-poetry','','[]','關西千戶侯，分此霜根獨。',96,'全唐诗/poet.song.95000.json','["關西千戶侯，分此霜根獨。", "幾年用幽意，列屋攢蒼玉。", "如聞手自種，培養非一掬。", "高標邈何所，於焉識面目。", "臉笑桃花紅，睂憎楊柳綠。", "頎然立兒孫，挺操異群木。", "我嘗聽餘音，球琳響山谷。", "當約嵇中散，攜琴此間宿。"]'),
('8f34e959-8995-42a4-9f66-d4e13e450c8d','再和前韻答隱父二首  其一','郭印','宋','宋诗','song-poetry','','[]','吾宗枝幹衰，弱植念孤獨。',96,'全唐诗/poet.song.95000.json','["吾宗枝幹衰，弱植念孤獨。", "結交得此君，蒹葭倚瓊玉。", "即之不忍去，爽氣如可掬。", "初觀愛柯莖，久坐窮節目。", "細葉裁雲新，深根封蘚綠。", "從今凈兩眼，不數山中木。", "世路繁荆榛，相將隱空谷。", "直須丹鳳來，采實虞庭宿。"]'),
('300d84c2-6de1-4ff9-9fad-6342c2f1dd02','再和前韻答隱父二首  其二','郭印','宋','宋诗','song-poetry','','[]','植物稟清氣，天與寒筠獨。',96,'全唐诗/poet.song.95000.json','["植物稟清氣，天與寒筠獨。", "陸離草樹間，貴賤分珉玉。", "王孫愛夭紅，采蘂動盈掬。", "如何檀欒姿，睥睨少青目。", "物色變炎凉，永守霜中綠。", "豈無噦噦音，律呂諧金木。", "世無伶倫耳，風雲駐幽谷。", "七賢何苦來，契約元有宿。"]'),
('25b53ea1-5c2b-4af4-86af-bf0b60c2d1bb','知郡范公澤游野意軒盡斬軒前惡竹之蔽眼界豁然時升有詩用其韻','郭印','宋','宋诗','song-poetry','','[]','勝景天壤間，造物不能祕。',168,'全唐诗/poet.song.95000.json','["勝景天壤間，造物不能祕。", "堂堂亘古今，取舍愈無匱。", "江山本自如，優劣隨人意。", "城東古招提，軒宇舊鑿翠。", "老僧不解事，養竹日蒙蔽。", "高人偶來游，躊躇重增喟。", "呼童縱斧斤，似割眼中翳。", "平原露寒蕪，遠樹浮翠氣。", "天闊飛鳥沒，雲烟蕩無際。", "快哉指顧間，千里歸睥睨。", "我聞亟走觀，宛非前日地。", "風光捆載歸，髣髴挑吟思。", "珠璣忽飛來，怳與吾心契。", "更欲紀其由，多辭亦云贅。"]'),
('491cb8e3-c49e-4784-90c2-fe30ba1f7d3e','題宋公圭宿雲軒','郭印','宋','宋诗','song-poetry','','[]','趨名老鞍馬，避世終山林。',96,'全唐诗/poet.song.95000.json','["趨名老鞍馬，避世終山林。", "二塗各有蔽，賢哲多所箴。", "宋侯初出仕，逸足已駸駸。", "世路厭荆棘，翩然脱華簪。", "卷舒何自由，白雲本無心。", "開軒資笑傲，霜筠綠陰森。", "牀頭有濁醪，壁間餘素琴。", "淵明久寂寞，千載得知音。"]'),
('356a9f04-e856-48c2-9a32-8aa6b0e74431','題絕塵亭','郭印','宋','宋诗','song-poetry','','[]','咫尺有佳境，何用山澤游。',120,'全唐诗/poet.song.95000.json','["咫尺有佳境，何用山澤游。", "地偏塵自遠，松竹鏁深幽。", "亭亭出危塔，湛湛俯長流。", "憑軒目一縱，驕蹇萬象收。", "我來意頗適，坐對孤雲浮。", "同心二三友，曠達亦罕儔。", "銜盃送頹日，隨寓得所休。", "不知世間人，亦有此樂不。", "出處付身外，吾生可自由。", "他時儻乘興，相伴只沙鷗。"]'),
('54e17fd6-ad8b-4f26-a9fd-3b161d673819','與大受述之耕道游絕塵亭探韻得賦字','郭印','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','人生合散多，罕與故人遇。',120,'全唐诗/poet.song.95000.json','["人生合散多，罕與故人遇。", "今辰天氣佳，偶爾得清晤。", "况復臨江亭，一目萬景聚。", "晚煙乍明滅，天遠重重樹。", "長江灣環來，浩蕩仍東注。", "對此酌春酒，飲酣詩可賦。", "我欲寫筆端，恨無摩詰句。", "豈如二三公，才力超七步。", "觀情殊未闌，倐忽天欲暮。", "憑誰挽羲和，爲把車輪駐。"]'),
('33950052-e7bd-4905-bb51-6d990abb67a7','和光亭','郭印','宋','宋诗','song-poetry','','[]','竹裏徜徉了，花開也一過。',120,'全唐诗/poet.song.95000.json','["竹裏徜徉了，花開也一過。", "桃杏東風淺，海棠春意多。", "華麗豈不好，達人要同和。", "青青與紅紅，相去能幾何。", "况兹十二法，凈穢本同科。", "而彼世間愚，妄想分臼窠。", "我昔早聞道，隨流挹其波。", "照鏡靦功業，素髪從蹉跎。", "林下既逍遥，塵中亦婆娑。", "不妨喚天女，來伴老維摩。"]'),
('9d16e342-1db2-4f06-8758-0ed88b1a984e','乘桴亭','郭印','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','孔子道不行，時君目腐儒。',120,'全唐诗/poet.song.95000.json','["孔子道不行，時君目腐儒。", "亂邦難置足，遂欲九夷居。", "更作乘桴語，與此意何殊。", "一木異舟楫，波濤寧可踰。", "憤世有激爾，蓋用警聾愚。", "季路猶未達，而况他人與。", "我生亦不辰，兵戈溷中區。", "兩腳倦遠涉，跼蹐西南隅。", "臨深每慨嘆，長江良起予。", "興發撐小艇，鬰堙聊一舒。"]'),
('b859cc67-7803-4dab-82e4-e6b4ad198917','倚樓','郭印','宋','宋诗','song-poetry','','[]','官閑何所之，倚樓縱遠目。',216,'全唐诗/poet.song.95000.json','["官閑何所之，倚樓縱遠目。", "田疇耒耜出，高下春雨足。", "人家有生意，慰我苦幽獨。", "憶昨水沴餘，海氣蕩坤軸。", "蛟龍坼川原，舟楫造谿谷。", "禾麻安更論，未能保骨肉。", "有子易爲食，何以厚風俗。", "上賴天子聖，詔書勤撫育。", "雖使發倉廩，飽歲實無蓄。", "郡縣徒倉皇，論丁具饘粥。", "所救無幾何，往往委溝瀆。", "今兹氣候正，逋民稍來復。", "楚風重祠廟，纔歸競巫祝。", "此物豈有靈，焉能助豐熟。", "渺思濟時策，慎擇良宰牧。", "金繒斥誅求，教化行比屋。", "祖宗德澤深，萬歲長沐浴。", "題詩起高興，飄然跨鴻鵠。"]'),
('3c34ee99-92a5-47b3-a590-41b55272adaa','登致爽閣觀山用種字韻同賦一首','郭印','宋','宋诗','song-poetry','','[]','群峰鬰崔嵬，西北天壁竦。',132,'全唐诗/poet.song.95000.json','["群峰鬰崔嵬，西北天壁竦。", "短松被南岡，髪立何種種。", "中間一川平，楸枰界千隴。", "晨光霽霧搴，冥色寒烟重。", "幽人每登臨，氣與秋山聳。", "萬象入嘲弄，敏思飛泉湧。", "嗟予老索寞，高躅難繼踵。", "風光本自如，綺語浪嘉寵。", "况復將此心，勃勃塵慮壅。", "日月不假借，學道須猛勇。", "誓當守株愚，從人呼傝䢆。"]'),
('93c5b6d8-644c-414c-9f67-cdeaa3c8ee44','戲題睡庵壁','郭印','宋','宋诗','song-poetry','','[]','自我觀世間，色色厭逐迫。',72,'全唐诗/poet.song.95000.json','["自我觀世間，色色厭逐迫。", "箇中無尺地，漫不見阡陌。", "中有南柯游，未怕東方白。", "閉眼一榻多，開眼六合窄。", "彌明息如雷，非我門下客。", "覺寐兩不知，偃仰有真宅。"]'),
('7ab229df-b23b-494e-81ee-0eb734ba715c','遊大隋山','郭印','宋','宋诗','song-poetry','','[]','我聞大隋名，夢寐猶記錄。',192,'全唐诗/poet.song.95000.json','["我聞大隋名，夢寐猶記錄。", "得檄天彭道，喜氣和可掬。", "出城六十里，崎嶇轉江曲。", "山門忽斗上，危步依笻竹。", "崩石带烟雲，異草羅澗谷。", "寂鳥下窺人，纍猿時挂木。", "路窮纔見寺，金碧煥雙目。", "祖師古定光，燈冷無人續。", "開公生異世，大事如付囑。", "僧言山長陰，朝暮雲容蹙。", "兹辰爲我晴，叠岫堆濃綠。", "虛閣倚秋風，一洗塵土俗。", "舉手揖丹景，摃身跨白鹿。", "十年勞問訊，親到心始足。", "坐久燭漸微，借榻雲間宿。", "山寒寐不成，窗外泉鳴玉。"]'),
('f3127672-b5c0-4d29-bbe2-7142206fa41b','題李彦澤紫雲洞','郭印','宋','宋诗','song-poetry','','[]','老李天中仙，一念人間世。',168,'全唐诗/poet.song.95000.json','["老李天中仙，一念人間世。", "簪裳四十秋，不取公卿位。", "星斗爛文章，日月懸忠義。", "緣斷還帝鄉，飄飄若蟬蜕。", "玉骨瘞高丘，乃其所卜地。", "山川暨草木，拱揖浮蒼翠。", "向來峰之巔，勃鬰蟠紫氣。", "神物常護持，景色多秀異。", "郎君久慕道，泥滓唾聲利。", "石洞琢青苔，萬古開天秘。", "非關痼烟霞，稍欲遠朝市。", "要棲老仙靈，以奉香火事。", "不知騎鯨去，塵宇寧俯視。", "洞兮既清幽，且盡人子志。"]'),
('d7a2b833-40b9-487c-a8a2-866534f9c3f9','龍淵','郭印','宋','宋诗','song-poetry','','[]','脩竹不知數，雲藏小渭川。',168,'全唐诗/poet.song.95000.json','["脩竹不知數，雲藏小渭川。", "亭沼經營初，觀者日駢闐。", "耆舊爲我語，中有一龍淵。", "時時見怪象，吐氣如長烟。", "漁人或艤舟，樵牧不敢前。", "兹實總角時，耳聆父老言。", "相攜示其處，止水涵青黫。", "沈沈不見底，似有蛟蛇蟠。", "我時心語口，龍豈居其間。", "江湖非不廣，而此棲蜿蜒。", "有無未可知，疑信空相傳。", "皇天儻困汝，時至須騰騫。", "滄溟可以家，一徙窟宅慳。", "變化作霖雨，滌蕩驕陽愆。"]'),
('9b30ea2a-b257-478e-9bba-9b678e2970a0','和元汝功江臯感懷','郭印','宋','宋诗','song-poetry','','[]','奸諛同一轍，舉世誰與歸。',180,'全唐诗/poet.song.95000.json','["奸諛同一轍，舉世誰與歸。", "溪山有佳趣，此樂知者稀。", "悠然遠罾弋，魚潛鳥高飛。", "不作無根雲，蒼狗變白衣。", "使君見幾早，萬事已覺非。", "拏舟漾清波，策杖登高崎。", "逍遥興未已，烟霞收夕霏。", "身從麋鹿遊，心與塵垢違。", "惜哉經綸手，把釣渭水湄。", "冷眼笑紛紛，甘貽肉食譏。", "強敵猶張王，屠滅煩天威。", "要取虞淵日，咸池浴明暉。", "願君投緡竿，風雲起苔磯。", "雍容坐帷幄，密勿旋樞機。", "莫學西山卧，窮年空采薇。"]'),
('ff0fe9e4-9d52-44e6-9e62-13f92c75241f','泛舟至臨江院','郭印','宋','宋诗','song-poetry','','[]','清江借篙師，津流不須問。',60,'全唐诗/poet.song.95000.json','["清江借篙師，津流不須問。", "行行鏡中天，水鳥嗔人近。", "絕岸得危亭，一目千里盡。", "山川草木妍，造物無少吝。", "誰知天壤間，眇然一方寸。"]'),
('33514314-ccc2-459b-a872-60b345ad555d','十一月四日陪諸公游神泉南山院二十韻','郭印','宋','宋诗','song-poetry','','[]','官閑訪招提，偶作南山遊。',240,'全唐诗/poet.song.95000.json','["官閑訪招提，偶作南山遊。", "門前喬木陰，蒼藤掛髯虬。", "野僧出迎我，貌古氣且柔。", "相將入壺中，水竹凈雙眸。", "萬竿團脩翠，一溪皺横流。", "長橋翼方沼，髣髴疑行舟。", "角門通細路，崎嶇上層丘。", "樹色老欲瞑，風聲寒自颼。", "佛閣瞰澄碧，下有百丈湫。", "客言龍所邑，不受魚與鰌。", "行行更小亭，羅坐得小休。", "石罅流清泉，甘冷無與儔。", "濯足夫豈敢，洗耳良末由。", "自憐山中人，十載冠壓頭。", "公檄聽奔走，端似置書郵。", "惟有烟霞疾，沈緜未肯瘳。", "邂逅愜幽懷，落日尚遲留。", "五斗奚堪戀，十畝亦易求。", "要希陶淵明，投紱事農疇。", "超然傲塵世，知命復何憂。"]'),
('77ef25f9-228e-49f9-80c0-3925022ec19e','遊楊村仁王院二十韻','郭印','宋','宋诗','song-poetry','','[]','山行不作懶，杖策窮幽邃。',240,'全唐诗/poet.song.95000.json','["山行不作懶，杖策窮幽邃。", "崎嶇十里餘，乃得桃源地。", "竹樹蓊以鮮，峰巒秀而媚。", "嬌雲弄奇姿，啼鳥含幽意。", "周遭帷幄中，一带江流駛。", "始知造物慳，異境亦所秘。", "行行松門深，鐘磬出蕭寺。", "殘僧五六輩，相顧各猜異。", "須臾問訊通，顔色頗夷粹。", "高堂清風多，起我無窮思。", "提攜更小庵，清絕非人世。", "自憐學宦游，十載沉卑位。", "功名與丘壑，兩計皆未遂。", "時變攪中腸，憂端叢千蝟。", "豈如山間僧，了無秋毫累。", "一榻寄巖阿，烟霞爲活訃。", "脱身名利塵，洗耳市朝事。", "兹遊成邂逅，頗與宿心契。", "晚日下層巔，躊躇聊自慰。", "重來定何時，往往先夢寐。"]'),
('29aa128e-0370-4a8a-94fb-d4b72c947674','普慈郡池板橋頹壊更爲石橋','郭印','宋','宋诗','song-poetry','','[]','蓮塘十畝方，中作長橋渡。',144,'全唐诗/poet.song.95000.json','["蓮塘十畝方，中作長橋渡。", "荒荒歲月老，烈烈風雨蠧。", "板面拆已穿，梁脊橈而腐。", "我來日曵杖，往往不能步。", "平生歷險危，所至靡驚懼。", "唯持忠信行，似有神物護。", "但憂強童子，失足或顛仆。", "乃伐南山石，甃成如砥路。", "曾微十日勞，遂享百年固。", "悵昔用材力，其費一何巨。", "前人豈不思，襲舊終莽鹵。", "作詩示兒曺，萬事長要慮。"]'),
('6790211a-8f12-4228-825f-b1ded01bd704','放步園林得俗字韻','郭印','宋','宋诗','song-poetry','','[]','林稀怨秋風，松柏未改綠。',120,'全唐诗/poet.song.95000.json','["林稀怨秋風，松柏未改綠。", "偷閑挈杖來，小逕緣詰曲。", "鳥鳴契深心，山色供遐矚。", "欣然若有獲，一蕩塵襟俗。", "平生本逸放，誰信簡書束。", "失身名宦場，冠冕成桎梏。", "老驥欲何之，鹽車終局促。", "求仁又焉貪，知足乃不辱。", "納納乾坤大，胡爲自蹐跼。", "歸歟倘成賦，矯首雲中鵠。"]'),
('1e005df0-ad79-42b7-9015-be69f0204490','次韻仲明舉西郊别墅','郭印','宋','宋诗','song-poetry','','[]','我聞脩竹陰，清邃不受暑。',120,'全唐诗/poet.song.95000.json','["我聞脩竹陰，清邃不受暑。", "安得十畝餘，其中創幽墅。", "日長惟鳥聲，晝靜無人語。", "習習來微風，蕭蕭墮寒雨。", "呼兒出柴扉，垂綸坐沙渚。", "斯志久未遂，世路今彌阻。", "新詩何起予，風味勝清醑。", "自憐拘一官，隱逸愧前古。", "好夢只林泉，羈蹤猶糞土。", "豈能學貪夫，忘身徇圭組。"]'),
('adeb6aa0-b9d8-4da4-9d13-e3cadf8d65da','前十三章未見營創之意因成古風','郭印','宋','宋诗','song-poetry','','[]','紛紛世間法，失得隨所寓。',240,'全唐诗/poet.song.95000.json','["紛紛世間法，失得隨所寓。", "有心不吾來，無以不吾拒。", "敝帚貴千金，窮閻封萬戶。", "成理先默定，疇能測其故。", "我生麋鹿姿，林壑所忻慕。", "抗志老淵明，早卜柴桑住。", "蓬門直清江，傍有萬竹塢。", "捐金買尋丈，地主牢不許。", "往來二十秋，垂涎焦肺腑。", "誰歟誘其衷，百畝倐見予。", "雲棲渺空明，似有神物護。", "入林兩腋風，步武覺輕舉。", "三徑手自開，一一通幽處。", "取勝著新亭，揭名非苟取。", "遐光遠山入，靜聽珍禽語。", "園花四時春，岸木千年古。", "昔也荆榛場，今焉瓊玉府。", "清境世所無，金谷誰比數。", "再拜天之賜，從兹謝簪組。", "名宦空疲人，視此真糞土。"]'),
('4e607a59-6c71-44b6-b711-e3018b2a357b','治園','郭印','宋','宋诗','song-poetry','','[]','故園别日久，歸來三徑荒。',72,'全唐诗/poet.song.95000.json','["故園别日久，歸來三徑荒。", "叢竹壊新壁，枯荷掩幽塘。", "滿地葉狼籍，草木爲不芳。", "兒童力併除，百卉儼成行。", "遥岑出蔥菁，清波皺滄浪。", "一朝舊觀還，林壑愈爭光。"]'),
('b97553fa-6e7e-4efe-9119-41457f2c6abe','掃徑','郭印','宋','宋诗','song-poetry','','[]','陰森百畝林，所向無不好。',72,'全唐诗/poet.song.95000.json','["陰森百畝林，所向無不好。", "俗客豈曾來，幽處通蓬島。", "一色盡琅玕，堅潤真可寶。", "天風時脱葉，滿徑堆殘槁。", "適然賓客至，課奴先痛掃。", "要使吾心凈，置之勿復道。"]'),
('f6b25261-7b16-4b51-aa57-d7d919e26e2c','留客','郭印','宋','宋诗','song-poetry','','[]','田廬欠過從，每與樵漁伍。',72,'全唐诗/poet.song.95000.json','["田廬欠過從，每與樵漁伍。", "胸中抱欝欝，舌在不能吐。", "佳客忽顧我，苦留終日語。", "林間喜徜徉，縱舌評今古。", "所具只村醪，水竹當籩俎。", "臨去約重來，一笑便相許。"]'),
('d2fc360b-11b4-47d6-8e9d-c89b05e9b05c','負暄','郭印','宋','宋诗','song-poetry','','[]','儒生習氣深，寒陋渾未除。',72,'全唐诗/poet.song.95000.json','["儒生習氣深，寒陋渾未除。", "茅簷負晨曦，暖入四體舒。", "怡然得真趣，自謂世所無。", "不知華屋下，繡茵圍紅爐。", "風霜攪乾坤，凍死盈路隅。", "無計凌空去，雲間留日車。"]'),
('126601c9-4083-4db5-a001-d9b26d29301a','臨流','郭印','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江一鏡凈，豈但燭鬚睂。',72,'全唐诗/poet.song.95000.json','["長江一鏡凈，豈但燭鬚睂。", "清光瑩我心，雙鬢任如絲。", "鷗鷺近人來，游魚亦可窺。", "不把塵纓濯，身世兩相遺。", "好觀東去浪，晝夜無休時。", "學道正如此，到海以爲期。"]'),
('07338bec-0f2f-4129-be69-d13f18c401e3','閑中真樂','郭印','宋','宋诗','song-poetry','','[]','人間富與貴，孰不羡王侯。',120,'全唐诗/poet.song.95000.json','["人間富與貴，孰不羡王侯。", "靜邊細一觀，何其勞且憂。", "去來風中雲，出沒水上漚。", "推遷無定在，秋毫非我謀。", "既仕知此理，官衢屢回頭。", "今也衡門下，卧起得自由。", "隨流任縱横，飄如不繫舟。", "觸處盡禪悦，俗樂寧可侔。", "死生夜旦耳，吾心有天遊。", "肯學癡狂子，盖棺事始休。"]'),
('a44fbdcc-51fa-4c41-abd6-72f567aa7afb','閑中打睡','郭印','宋','宋诗','song-poetry','','[]','永日無一事，何妨白晝眠。',120,'全唐诗/poet.song.95000.json','["永日無一事，何妨白晝眠。", "是中有佳處，心形每自便。", "六用不能行，根塵都棄捐。", "非醉亦非迷，神守得安全。", "古人曷訶責，蓋欲繩其愆。", "糞牆斥宰予，便腹嘲孝先。", "我則異於是，一息養綿綿。", "魂夢既已無，中扃絕萬緣。", "不游華胥國，真樂侔乎天。", "要學希夷子，且作地行仙。"]'),
('b818e798-4686-4729-9e5a-ee83b9987c99','夜坐','郭印','宋','宋诗','song-poetry','','[]','永夜不可寐，霜風悽北窗。',120,'全唐诗/poet.song.95000.json','["永夜不可寐，霜風悽北窗。", "一室何所有，書帙對寒釭。", "當今苦乏才，九鼎從敵扛。", "翠華塵屢蒙，南北分大江。", "有酒強排遣，飲濕難空缸。", "孫臏不再生，疇能死窮龐。", "肉食無遠謀，狐裘正茸尨。", "我欲叩閶闔，鐘以寸筳撞。", "理亂非吾事，憂心如是降。", "宴坐鳴天鼓，和聲聽逢逢。"]'),
('32cb9a67-5986-4e4f-84e9-da6bbd70b1e1','感懷','郭印','宋','宋诗','song-poetry','','[]','冬仲陰氣驕，微陽尚潛伏。',72,'全唐诗/poet.song.95000.json','["冬仲陰氣驕，微陽尚潛伏。", "草木慘無容，霜威日夜酷。", "君子覽時運，悠然守幽獨。", "吹律者何人，微暖還燕谷。", "玉衡無淹次，天道旋反復。", "低回佇春風，求友升喬木。"]'),
('57881dce-9346-451f-9f1f-df482aedc887','又用前韻','郭印','宋','宋诗','song-poetry','','[]','道人息以踵，氣馬自調伏。',72,'全唐诗/poet.song.95000.json','["道人息以踵，氣馬自調伏。", "神爐造化馳，不畏寒暑酷。", "雖同一世塵，超然立於獨。", "飛泉上崑山，赫日升暘谷。", "我今涉津涯，宴坐成休復。", "不材終天年，庶比山中木。"]'),
('18a9b2cc-e18a-4896-b5a2-fe0c8d93d017','次韻宋南伯感懷三首  其一','郭印','宋','宋诗','song-poetry','','[]','青山含遠意，白雲弄奇姿。',48,'全唐诗/poet.song.95000.json','["青山含遠意，白雲弄奇姿。", "喚客早歸來，一洗塵土衣。", "巖壑定誰伍，泉清竹漪漪。", "危邦固難入，賢哲多遯肥。"]'),
('3da3d7cf-274c-4d4c-8c6b-2f0c972a9d2c','次韻宋南伯感懷三首  其二','郭印','宋','宋诗','song-poetry','','[]','酒盞解忘憂，茶甌工破睡。',48,'全唐诗/poet.song.95000.json','["酒盞解忘憂，茶甌工破睡。", "酒酣無何鄉，睡起人間世。", "但看了了時，孰與陶陶醉。", "千古杜康功，麴糵因君置。"]'),
('7e9f007e-a620-4ee3-9b54-3916efd8f807','次韻宋南伯感懷三首  其三','郭印','宋','宋诗','song-poetry','','[]','衰年今五十，兩鬢雪霜明。',48,'全唐诗/poet.song.95000.json','["衰年今五十，兩鬢雪霜明。", "出處負前輩，折腰若爲情。", "日月鳥飛翔，燕歸鴻復征。", "是身已虛幻，敢希身後名。"]'),
('d5aa537b-48dd-42c9-8342-16d7a742be68','再用南伯韻  其一','郭印','宋','宋诗','song-poetry','','[]','乾坤誰整頓，世乏英雄姿。',48,'全唐诗/poet.song.95000.json','["乾坤誰整頓，世乏英雄姿。", "陛下求賢切，焦勞見宵衣。", "草茅豈無人，耕兩釣寒漪。", "如何一終星，坐視戎馬肥。"]'),
('c41462f9-4a84-4d85-897b-c8a96a6a20bd','再用南伯韻  其二','郭印','宋','宋诗','song-poetry','','[]','紛紛愚癡兒，開眼卻如睡。',48,'全唐诗/poet.song.95000.json','["紛紛愚癡兒，開眼卻如睡。", "况於世法中，而能了出世。", "接輿本非狂，阮籍未爲醉。", "知命百無憂，餘生任廢置。"]'),
('413a42d3-dfb5-4f1f-89a0-c7974f060e0f','再用南伯韻  其三','郭印','宋','宋诗','song-poetry','','[]','同僚多絕識，冏冏秋月明。',48,'全唐诗/poet.song.95000.json','["同僚多絕識，冏冏秋月明。", "遨遊但詩酒，頗慰薄宦情。", "否極泰將來，天衢看彙征。", "顧我老無用，敢附青雲名。"]'),
('f07cdc0e-73b2-4f30-a1e2-7850e020be3a','再和  其一','郭印','宋','宋诗','song-poetry','','[]','玄真仙中人，蕭散自天姿。',48,'全唐诗/poet.song.95000.json','["玄真仙中人，蕭散自天姿。", "放情烟波裏，不肯汙朝衣。", "一葦載明月，寒光動碧漪。", "何以羞晨餐，春江鱖魚肥。"]'),
('5e12dffb-5d04-4d45-afa1-f1181db664ca','再和  其二','郭印','宋','宋诗','song-poetry','','[]','我愛希夷子，妙處渾一睡。',48,'全唐诗/poet.song.95000.json','["我愛希夷子，妙處渾一睡。", "無心樹勳業，栩栩同汙世。", "夢裏還獨醒，卻笑群兒醉。", "時事嗔人說，達官從措置。"]'),
('6f176071-84fb-44df-b192-874bf8f3bdd6','再和  其三','郭印','宋','宋诗','song-poetry','','[]','由來世間事，黑白忌太明。',48,'全唐诗/poet.song.95000.json','["由來世間事，黑白忌太明。", "稍欲辨淄澠，開口咈衆情。", "青山有歸路，杖屨借遐征。", "寄語社中友，休苦釣時名。"]'),
('dbd570f6-af7c-48f5-87da-193062fcba80','病起贈劉元圭','郭印','宋','宋诗','song-poetry','','[]','學道淹四紀，微痾一點無。',240,'全唐诗/poet.song.95000.json','["學道淹四紀，微痾一點無。", "今年歲八十，有疾纒吾軀。", "初因水道澀，藥寒變河魚。", "食飲便退縮，脾土成中虛。", "言語氣自短，坐起人須扶。", "四肢時厥冷，甘心委冥途。", "醫者紛紛來，其說庸且疏。", "萬方覓靈丹，千載憶神盧。", "紫巖老劉君，深通黄帝書。", "易學自該貫，醫術乃緒餘。", "一診洞腑臟，再診知榮枯。", "謂當十朞壽，小恙安足虞。", "藥石未數進，疾證半已除。", "乃知所造妙，當與古人俱。", "自足著方論，欲以開迷徒。", "新書若行世，功倍南陽朱。", "吾聞活人多，天報定不渝。", "施此安樂法，勝造千浮屠。", "陰德在一念，豈止治獄歟。", "况君有令子，歸矣高其閭。"]'),
('a17c15fa-a14a-4c22-b34c-dba51dc9f578','病目','郭印','宋','宋诗','song-poetry','','[]','開眼萬象生，闔眼萬象滅。',144,'全唐诗/poet.song.95000.json','["開眼萬象生，闔眼萬象滅。", "生滅本無體，人心妄分别。", "我初病眸子，散漫空花發。", "視物都矇矇，浮雲翳秋月。", "謁告旋掩關，十日人事絕。", "密室宴坐餘，神光潛洞達。", "俄於冥冥中，瞭然得朗徹。", "以兹悟色性，六根成解脱。", "緬思濁世人，逐見互攘奪。", "外爲物所障，兩眼暗添屑。", "豈知有良醫，利重金篦刮。", "作詩示盲俗，聽此還丹訣。"]'),
('83dafe5e-ce6f-4297-ad95-536861289580','問養生於曾端伯','郭印','宋','宋诗','song-poetry','','[]','平生慕道心，荏苒歲月永。',156,'全唐诗/poet.song.95000.json','["平生慕道心，荏苒歲月永。", "尠福未逢人，桑榆驚短景。", "使君蓬萊仙，天遣下塵境。", "訟簡刑獄清，吏退文書省。", "詩鋒禿千毫，量陂吞萬頃。", "縱言及養生，大抵宗虛靜。", "逍遥思慮空，恬淡聲色屏。", "火透尾閭關，泉落崑崙頂。", "龍虎閑名字，安用分爐鼎。", "衰遲偶遭逢，踴躍真自幸。", "願許燕閑餘，摳衣竊有請。", "半語爲發藥，醉夢一呼醒。", "庶幾垂盡年，獲與天地並。"]'),
('23f4f62b-9713-44dd-af46-6911694dcd5f','謝曾帥養生訣','郭印','宋','宋诗','song-poetry','','[]','人生不盈仞，中有天地機。',168,'全唐诗/poet.song.95000.json','["人生不盈仞，中有天地機。", "哀哉蠢蠢群，沉湎無所知。", "六根亂塵境，一念落邪思。", "遂令至真宅，棟宇日頹隳。", "先生早悟此，寂照通幽微。", "真火下騰熖，靈泉上生肥。", "巧妙神明出，功深造化馳。", "每憐好道人，羅縷爲指迷。", "鄙夫尋訪久，膚淺得其皮。", "向來發關鍵，一掃雜學卑。", "五行識顛倒，八卦知推移。", "兔從月窟隱，魚向天池飛。", "躍躍心自喜，扶老得吾師。", "何以報恩德，晝夜勤行之。"]'),
('72ebd7be-b3bd-4b9a-a2a8-0f8484b02489','閑中讀易','郭印','宋','宋诗','song-poetry','','[]','聖人闡性命，易書所自作。',120,'全唐诗/poet.song.95000.json','["聖人闡性命，易書所自作。", "要令末世士，悟取先天學。", "俗儒何紛紛，私意妄穿鑿。", "或被陰陽拘，或遭象數縛。", "執一以爲真，盲夫妄捫摸。", "我嘗皆過眼，去道轉遼邈。", "粤從探釋氏，奥處窺其略。", "返照日月久，豁然生妙覺。", "八卦未畫初，玄門啓關鑰。", "向來百家言，盡把束高閣。"]'),
('77c47a84-7bed-41c1-8e8a-619036234437','閑看佛書','郭印','宋','宋诗','song-poetry','','[]','金仙入漢夢，始聞佛法東。',120,'全唐诗/poet.song.95000.json','["金仙入漢夢，始聞佛法東。", "梁武好尤篤，上下爭尊崇。", "尋譯到李唐，伽藍棟宇充。", "煌煌五千卷，披讀未易終。", "楞嚴明根塵，金剛了色空。", "圓覺祛禪病，維摩現神通。", "四書皆等敎，真可發愚蒙。", "我常日寓目，清晨課其功。", "油然會心處，喜樂浩無窮。", "寄語看經人，勿墮文字中。"]'),
('d6392005-ab94-469f-80bc-d679cf7a900f','讀維摩經','郭印','宋','宋诗','song-poetry','','[]','白衣心出家，從古推凈名。',120,'全唐诗/poet.song.95000.json','["白衣心出家，從古推凈名。", "無疾現有疾，特地真機生。", "佛欲遣人問，指示轉分明。", "宜是諸大士，辭屈不能行。", "文殊末後往，萬衆心已傾。", "箭鋒相注處，妙義益崢嶸。", "芥子容須彌，毛孔受四溟。", "此理自灼然，學者疑且驚。", "更談不二門，法法俱見成。", "一默豈無語，其聲如震霆。"]'),
('90c4e08a-59cc-42a2-84af-e798de1417f3','讀金剛經','郭印','宋','宋诗','song-poetry','','[]','智慧比金剛，能碎諸煩惱。',120,'全唐诗/poet.song.95000.json','["智慧比金剛，能碎諸煩惱。", "良哉須菩提，爲衆非草草。", "再三立問端，一起復一倒。", "要以撼瞿曇，俾之攄懷抱。", "瞿曇了不惜，意切如老媼。", "始終談四相，畢竟盡除掃。", "爲言福德性，勝施千萬寶。", "因果本來空，種種惟心造。", "默觀契予意，披味恨不早。", "已喜識真吾，何妨行六道。"]'),
('cf1efa10-f151-486d-8478-b41a38c20530','讀楞嚴經','郭印','宋','宋诗','song-poetry','','[]','學道證聲聞，習氣猶未斷。',120,'全唐诗/poet.song.95000.json','["學道證聲聞，習氣猶未斷。", "百生恩愛情，會遇終惱亂。", "阿難佛寵弟，亦遭淫女難。", "神咒攝來歸，宿業堅冰泮。", "快演涅槃門，反復徵所見。", "文殊更說偈，明指圓通岸。", "其餘肆口言，心真自一貫。", "三界七趣中，有相無非幻。", "最後大慈悲，力破邪女叛。", "天魔與外道，從此悉銷散。"]'),
('355fba8e-b3b2-4eeb-b0c0-a37b693b6712','讀圓覺經','郭印','宋','宋诗','song-poetry','','[]','萬法歸一心，一心何所寄。',120,'全唐诗/poet.song.95000.json','["萬法歸一心，一心何所寄。", "靈光自巍巍，無物不具備。", "如來既先覺，要警衆生寐。", "倒說縱横說，莫非明此事。", "上根可與語，惟有十二士。", "問略答更詳，玄關大開示。", "下及三種觀，真修豈容廢。", "定輪各差殊，均入清凈地。", "直須頓悟入，不落第二義。", "圓覺與圓通，總是閑名字。"]'),
('a412cf42-4824-432e-8edf-cef73f54d855','治平院三蘇像','郭印','宋','宋诗','song-poetry','','[]','三蘇皆天人，著作浩篇簡。',144,'全唐诗/poet.song.95000.json','["三蘇皆天人，著作浩篇簡。", "少讀鬢成絲，苦恨生何晚。", "人言筦庫卑，我自得疏散。", "春風牽衣裾，興發無近遠。", "禪堂儼真容，光炯破昏眼。", "父子也而處，天畀岷峨産。", "揚馬爭軌躅，孔孟發關鍵。", "日月有盡時，斯文未埋鏟。", "邪說入人深，風俗頽莫返。", "招得戎馬來，中原恣蹂踐。", "緬思藥石言，禍患已先見。", "安得起其靈，一副蒼生願。"]'),
('34bb89d0-1862-4ddb-9b9c-38ccdd617529','提宮宇文朝議輓辭','郭印','宋','宋诗','song-poetry','','[]','憶昔我弱冠，辟廱尾群英。',216,'全唐诗/poet.song.95000.json','["憶昔我弱冠，辟廱尾群英。", "公時少二歲，籍注國子生。", "同舍氣味同，異姓而弟兄。", "厥後公筮仕，我亦獵科名。", "參辰不相比，邈焉笑語并。", "雲溪既卜築，來往數逢迎。", "玄譚入理窟，淡交遺世情。", "邑人敬二老，可爲來者程。", "頃年我出使，公言勉一行。", "僂指解轡歸，請當踵前盟。", "山頹梁木壊，聞訃恍以驚。", "迹公生平事，表裏皆純誠。", "居家簡以肅，從官廉而平。", "應酬心地虛，不見喜慍萌。", "處順悠然去，了無絲髮驚。", "迺知學道力，堅剛老益明。", "天報良未已，諸孫何錚錚。", "回首丹旌路，風悲涕淚横。"]'),
('8656d898-872d-4707-9fd8-d78e6347bfe9','輓朝請大夫致仕李公詞','郭印','宋','宋诗','song-poetry','','[]','聖賢志於道，朝聞而夕死。',216,'全唐诗/poet.song.95000.json','["聖賢志於道，朝聞而夕死。", "回視名宦場，唾去如泥滓。", "高風既寂寥，士俗皆靡靡。", "倒行日云暮，漏盡不知止。", "遂令搢紳談，進退爲難事。", "二疏及淵明，千載幾人爾。", "公生富貴中，習熟在紈綺。", "胡爲總角時，嗜好異群子。", "愛親自天性，弗忍離步跬。", "治官即理家，所至功可紀。", "夫何不待年，棄紱休田里。", "定應早聞道，追跡前賢軌。", "盃深别墅春，舟漾清江水。", "圍棋或賦詩，此樂真無比。", "優游二十秋，所得益多矣。", "臨終更琅琅，視身如脱屣。", "洪範五福兼，於公未爲美。", "誌銘乃實錄，便可當青史。"]'),
('03abb680-84ba-4f05-893f-bfb94bbb1cc8','宋元繪輓詞','郭印','宋','宋诗','song-poetry','','[]','國家有禍源，王氏變新法。',168,'全唐诗/poet.song.95000.json','["國家有禍源，王氏變新法。", "元祐壅其流，舊防無敢越。", "逮至崇寧初，陰霾蔽日月。", "潰彼千仞堤，横波不可遏。", "求言姦臣計，正欲穽豪傑。", "君時亦抗章，痛哭深論列。", "禁錮二十秋，著書憂愈切。", "緬觀前日事，一一符君說。", "朝廷思大用，銅虎初旌别。", "使者復何心，吹毛聽媒孽。", "皇天不憖遺，山梁遽摧折。", "七十五年間，飛電纔一瞥。", "殘編溢巾箱，光焰星斗揭。", "後人何酋酋，端不墜風烈。"]'),
('6fb7d4c2-b682-4a16-abce-cbea52bdc1fe','史德修輓詞','郭印','宋','宋诗','song-poetry','','[]','世道交相喪，古風邈悠悠。',168,'全唐诗/poet.song.95000.json','["世道交相喪，古風邈悠悠。", "真純化浮僞，士俗日以偷。", "公生寂寥後，慨然跋前修。", "奥學窮根柢，高文謝雕鎪。", "壯歲拾科目，回翔四十秋。", "孝弟可移官，所至人歌謳。", "處巳務恬退，馳騖吾所羞。", "臨民本慈惠，擊搏吾所咻。", "俯仰無愧怍，言行何悔尤。", "邦符與使節，異乎人之求。", "可憐貪殘子，快意乏遠謀。", "報應捷影響，坐致無邊愁。", "儻如西方說，寧逭鐵圍囚。", "不知公英靈，久矣清都遊。"]'),
('3681e53a-ccd2-4fe2-b5b7-88d15bc591e5','弔張道從','郭印','宋','宋诗','song-poetry','','[]','風俗久頽壊，人物無軒昂。',156,'全唐诗/poet.song.95000.json','["風俗久頽壊，人物無軒昂。", "夫君抱貞質，卓卓誠所長。", "千牛解寸刃，萬象窮智囊。", "獸群走麒麟，鳥族鳴鳳凰。", "炎政忽中微，權姦肆猖狂。", "彊敵乘釁起，垂涎睨蜀疆。", "君持山南節，武略見鋒鋩。", "坐令兩蜀口，飛鳥莫敢翔。", "坤維倚長城，老稚日以康。", "誰謂波濤際，中流失舟航。", "悲風揚丹旐，觀者淚浪浪。", "丈夫事則已，可爲邦家傷。", "緬知忠烈在，報國猶未忘。"]'),
('55eca92a-0a59-4059-8e27-3761d87d5807','胡夫人輓詞','郭印','宋','宋诗','song-poetry','','[]','士夫惜名節，楚楚空衣冠。',120,'全唐诗/poet.song.95000.json','["士夫惜名節，楚楚空衣冠。", "寧如武陵孀，守義人所難。", "哀哉禍變仍，歸櫂危狂瀾。", "至誠泣蒼穹，雙櫬果平安。", "堦前三珠樹，豈但馥芝蘭。", "科名一一收，平步籋廣寒。", "方爲反哺烏，風木悲珊珊。", "慶弔一何遽，聞者鼻辛酸。", "千年懿德馨，翠琰立巑岏。", "英靈滿乾坤，莫作長夜看。"]'),
('8b076597-660b-4b63-ab0f-c2123cd136b1','栽梅','郭印','宋','宋诗','song-poetry','','[]','平生不愛花，獨喜雪中梅。',72,'全唐诗/poet.song.95000.json','["平生不愛花，獨喜雪中梅。", "江皋無人問，移近小亭栽。", "連朝勤培溉，的皪犯寒開。", "青枝綴瓊粒，絳萼扶冰腮。", "奇哉出群姿，不待春風媒。", "調羹貪結子，碎玉點蒼苔。"]'),
('90097916-dff2-44a5-8a23-9841087f16fa','師吉甫探梅二首  其一','郭印','宋','宋诗','song-poetry','','[]','花如霧中見，百念已灰槁。',96,'全唐诗/poet.song.95000.json','["花如霧中見，百念已灰槁。", "愛梅習氣深，興發霜冬杪。", "行行步江郊，恰似兒童小。", "榮枯能幾時，日月疾過鳥。", "獨立望南枝，村空人悄悄。", "何似東皇駕，今歲來不早。", "忍令瑤臺姿，冷落群芳後。", "欲寄同心人，不折門前柳。"]'),
('6350eeff-83f4-46ab-856e-d6e454edb523','師吉甫探梅二首  其二','郭印','宋','宋诗','song-poetry','','[]','吏塗牛馬走，未老顔色槁。',96,'全唐诗/poet.song.95000.json','["吏塗牛馬走，未老顔色槁。", "歸來隱林坰，富貴輕毫杪。", "前村梅樹芳，點萼紅猶小。", "問訊疏籬邊，側聽迎春鳥。", "春工有先馳，一浣憂心悄。", "寒梢未粘玉，攀折嫌太早。", "吹香定重來，宿留嚴冬後。", "明朝韶景妍，更不齒花柳。"]'),
('7927ff68-c5f7-4231-b43a-a02e4c9127de','落梅','郭印','宋','宋诗','song-poetry','','[]','名園探梅時，粉苞才半開。',120,'全唐诗/poet.song.95000.json','["名園探梅時，粉苞才半開。", "如逢姑射仙，偃蹇下瑤臺。", "孤潔自天賦，肯聽東君媒。", "别來今幾日，雪片點蒼苔。", "玉笛誰家子，噴月一聲哀。", "可惜飛幽館，不上美人腮。", "柳條忽萌動，春風原上回。", "芳菲已後時，百卉胡顔哉。", "轉首鶗鴂鳴，殷紅亂成堆。", "卻來綠陰下，青子薦瓊盃。"]'),
('5667f901-3255-47d7-b37c-340553acf44d','次韻杜安行見寄憶梅之什','郭印','宋','宋诗','song-poetry','','[]','穠華桃李容，不染雙眸凈。',72,'全唐诗/poet.song.95000.json','["穠華桃李容，不染雙眸凈。", "唯有愛梅心，夢中行庾嶺。", "安得移瓊林，月下對清影。", "坐想冰雪姿，蕭然幽興永。", "我欲從君游，羈絆未能騁。", "平生溪山懷，倥偬迷簿領。"]'),
('9a644c1e-1c7d-408f-8d75-5585b135de7a','次韻友人寄牡丹','郭印','宋','宋诗','song-poetry','','[]','我居不識春，春至驗鳥語。',120,'全唐诗/poet.song.95000.json','["我居不識春，春至驗鳥語。", "誰知有芳叢，遠在幽人墅。", "千葩籠霧縠，萬朵羅烟縷。", "盛開笑白日，半落啼紅雨。", "餘花自臣妾，天公費機杼。", "賞翫應亡厭，分來儻相許。", "穠姿忽在眼，微馥驚穿戶。", "初觀但妖韶，細看尤媚嫵。", "尚想壓枝態，未易此間伍。", "何當就花飲，不憂腸脇腐。"]'),
('422a2e68-0621-4a0b-86c1-1265bed2da56','池蓮','郭印','宋','宋诗','song-poetry','','[]','疏池養白蓮，故作夏時景。',72,'全唐诗/poet.song.95000.json','["疏池養白蓮，故作夏時景。", "田田綠初齊，便成清凈境。", "雖無藕如船，風味同玉井。", "水仙何處來，露浥晨妝靚。", "苦乏社中友，永日對孤影。", "爽氣入人懷，酩酊爲之醒。"]'),
('18deb95c-6803-43c2-88ae-32d9e3e87a17','瓶水生數花須臾有蜂來集感而賦詩','郭印','宋','宋诗','song-poetry','','[]','折花養瓶水，老眼聊自怡。',154,'全唐诗/poet.song.95000.json','["折花養瓶水，老眼聊自怡。", "案置須臾間，游蜂已著枝。", "嗅香起還泊，{甍瓦=羽}{甍瓦=羽}動天機。", "不知何方來，神速乃如斯。", "宇宙一氣通，萬類不相違。", "石虎没勁矢，竹龍化清陂。", "矧兹抱靈識，倐與吾心期。", "吾心未専寂，舉念物先知。", "千生風輪轉，都緣愛欲移。", "勉哉學坐忘，宜默同木雞。", "無中産物象，顯晦隨所之。", "超然合大空，鬼神莫能窺。"]'),
('27a8d8c7-6e65-4287-ac7f-57d15c4ce2d9','諸公詠竹以籠竹和煙滴露梢爲韻得滴字','郭印','宋','宋诗','song-poetry','','[]','草木盡柔脆，夫君抱剛質。',96,'全唐诗/poet.song.95000.json','["草木盡柔脆，夫君抱剛質。", "孤標老更高，翠葉秋仍密。", "伊余亦剛介，論交自疇昔。", "相見眼終青，直諒蓋多益。", "夕陽映雪低，曉露和烟滴。", "清修良起予，安可無一日。", "柳條但柔姿，桃李從令色。", "與君期歲寒，勿作春風客。"]'),
('95cc1852-b39f-4625-ae22-e5081bfcded4','洗竹','郭印','宋','宋诗','song-poetry','','[]','林茂竹太繁，汙穢在眼底。',72,'全唐诗/poet.song.95000.json','["林茂竹太繁，汙穢在眼底。", "枯筠與弱幹，兹辰爲一洗。", "萬竿何足惜，惡盡意乃已。", "其餘擢青青，玉立比君子。", "姿色秀可飡，莫道膏粱美。", "我來不忍去，日日對園綺。"]'),
('887ea910-80c8-4af4-be69-662bce70feb9','柳絮','郭印','宋','宋诗','song-poetry','','[]','柳條初弄綠，已覺春風駐。',72,'全唐诗/poet.song.95000.json','["柳條初弄綠，已覺春風駐。", "而今二月尾，滿路團飛絮。", "人生安足恃，忽忽朱顔去。", "飄零未肯休，萍泛知何處。", "見之動中懷，欲寫無佳句。", "歸來宴坐餘，悠然得深趣。"]'),
('d9cff17c-6a39-446c-bfc1-af01836e4f5c','有野人來獻石蟬以二千錢償之因成拙詩','郭印','宋','宋诗','song-poetry','','[]','二儀肅陰氣，草木凋零盡。',96,'全唐诗/poet.song.95000.json','["二儀肅陰氣，草木凋零盡。", "爾生巖石間，叢密不自隕。", "綠葉抽紫莖，族與秋蘭近。", "蟬聮無數花，未覺霜飇緊。", "野人持獻余，千金那敢吝。", "盆崖遂物性，暢茂庶可準。", "吸風噴芳馨，飲露含清潤。", "如聞嘒嘒聲，滿地寒林振。"]'),
('14b3f16c-35e6-4e0d-bbb7-c9c8f657f3cf','詠龜','郭印','宋','宋诗','song-poetry','','[]','泥塗曳尾行，自適幽閑性。',72,'全唐诗/poet.song.95000.json','["泥塗曳尾行，自適幽閑性。", "不食本無營，畏人長縮頸。", "緬思風雨秋，污池亂鼃黽。", "爾亦水中族，胡爲獨沈靜。", "異質天所賦，巢蓮千歲永。", "見夢固不祥，多知慎所逞。"]'),
('19117786-37c4-446c-9fd9-6d74dd5d1b47','蛛網','郭印','宋','宋诗','song-poetry','','[]','我觀昆蟲輩，汝形亦甚微。',120,'全唐诗/poet.song.95000.json','["我觀昆蟲輩，汝形亦甚微。", "吐絲織爲網，元自有真知。", "團團肖車輪，巧妙出天機。", "事成坐其中，功力不浪施。", "羽飛纔一觸，罥罣定無遺。", "正緣有此生，謀食以療饑。", "古先大智人，創作萬世規。", "爲民設佃漁，結繩乃效之。", "仲尼善詞說，姑言取諸離。", "制器尚象耳，一一非妄爲。"]'),
('8a0df675-9e0a-4215-8f8f-db27e7084731','同蕭憲父明舉聮句','郭印','宋','宋诗','song-poetry','','[]','今夕復何夕，邂逅得良集。',72,'全唐诗/poet.song.95000.json','["今夕復何夕，邂逅得良集。", "雲消夜氣澄，月住秋空碧。", "南窗一樽酒，耿耿寒光入。", "浩然起長歎，矯首望東北。", "天涯清景同，誰謂關塞黑。", "躊躇反傷懷，衰草露蟲泣。"]'),
('6769f60e-589a-4df9-b8b1-4aaffeeae19f','和許守豐年行','郭印','宋','宋诗','song-poetry','','[]','園林搖落露寒梢，秋成穰穰彌四郊。',276,'全唐诗/poet.song.95000.json','["園林搖落露寒梢，秋成穰穰彌四郊。", "千里播種無不毛，妻兒溫飽忘啼號。", "餘粒施及禽與猱，有田寧復棄而逃。", "太守牧民如牧馬，宣化承流王澤下。", "欲希禹稷事躬稼，墾畝勸耕謾隙罅。", "召杜龔黄乃其亞，黄雲泱漭覆原野。", "樂爾豐年醉瓊斚，古卭舊敝人人說。", "久困征誅心已折，析家蕩産紛更迭。", "身罹罪罟無從雪，漫道當時富鹽鐵。", "漢志食貨忍重閲，嗟我婦子難全活。", "今年誰料勝常年，入絹得鹽償本錢。", "里絕追呼俗自便，閉門稚耋得安眼。", "十日一風五日雨，鄰村稽首羨兹土。", "白頭半刺才窳苦，賴此賢侯百廢舉。", "空庭吏散鳥馴除，謠聞擊壤同康衢。", "侯於公卿地有餘，利澤行推遍海隅。", "嗚呼利澤行推遍海隅，坐使斯民愁歎爲嬉娛。"]'),
('bcad9001-5e17-4758-951a-0e53d6876b80','和晁子西鈴屬勸農長篇','郭印','宋','宋诗','song-poetry','','[]','使君誠意與天開，呼吸之間爲雲雷。',160,'全唐诗/poet.song.95000.json','["使君誠意與天開，呼吸之間爲雲雷。", "一朝命駕出郊次，遠近爭看髦節來。", "道邊草木盡翔舞，巴峽邇來和氣聚。", "秪從精禱召神靈，五日一風十日雨。", "不有前時愁歎聲，千里相聞雞犬鳴。", "荷鋤執耒舉家出，原野處處催深耕。", "聞說朱轓閲田圃，老稚提攜紛笑語。", "當時惰游今力穡，肯播肯菑勤子父。", "朝廷睿澤浸華夷，良牧承流上所知。", "我欲濡毫頌公德，自慚蕪累不成詩。"]'),
('02982899-8446-4c69-9eff-8a41b4b5d352','故人蒲朝達沿檄道經廣漢留連累日作詩爲别','郭印','宋','宋诗','song-poetry','','[]','憶初鼓篋虞庠日，識面乃喜文章伯。',160,'全唐诗/poet.song.95000.json','["憶初鼓篋虞庠日，識面乃喜文章伯。", "游從不覺化芝蘭，交契懸知定金石。", "蕭條離緒十秋風，天涯等是飄零客。", "雙鱗不到雁無來，月照庭空心若失。", "豈期此地忽相逢，津津喜氣眉間溢。", "口談詩書尚細事，滿腹包羅濟時術。", "轅駒局促思千里，笯鳳葳甤空六翮。", "升沈世態且勿論，執手臨風長太息。", "君今清名塞宇宙，指日雲霄看騰軼。", "平居讜議或可施，肯效無功饕祿秩。"]'),
('7b39db5c-b3d8-4bee-902f-e2ff10d2b14a','别宇文季蒙','郭印','宋','宋诗','song-poetry','','[]','調羹休羨最南枝，國香繼踵開酴醿。',160,'全唐诗/poet.song.95000.json','["調羹休羨最南枝，國香繼踵開酴醿。", "先容豈藉早梅力，到了自結東君知。", "孤芳繚繞春雖晚，典型題在黄金醆。", "一家風骨端不凡，故使天公獨青眼。", "中興英主方急賢，屢辭溫詔挽不前。", "平生忠赤照肝膽，危論鯁諤能迴天。", "左蜀分符尚餘略，浙路霜臺亦輕著。", "朝廷鼎鼐席尚虛，君家况是箇中腳。", "寒儒筦庫埋晨昏，欲排閶闔嗟無門。", "洗眼江淮看騰踏，妖氣一掃清乾坤。"]'),
('3da779ff-8479-4918-8127-8d8f603d170a','送李去病赴召','郭印','宋','宋诗','song-poetry','','[]','五嶽四瀆今異方，東西南北衣冠鄉。',224,'全唐诗/poet.song.95000.json','["五嶽四瀆今異方，東西南北衣冠鄉。", "巽維久挽六龍駕，江浙人物無遯藏。", "參井之區最遐僻，步武難依日月光。", "吾皇側席佇賢俊，紫泥屢下勤搜揚。", "蜀士肯來天顔喜，一一引對羅周行。", "鳥群鸞鳳夐超詣，臺閣禁從森翺翔。", "君今再召歘幡改，愛主憂民心未忘。", "波瀾浩蕩江湖闊，忠信唯將一葦航。", "十年世故已熟講，不到帝所難鋪張。", "當今國病入骨髓，願君審處囊中方。", "參苓芝术固美矣，瞑眩之藥方爲良。", "扁鵲名世解說死，華佗活人須浣腸。", "君其持此拯危急，袪除痼疾針膏肓。", "一身安榮豈足道，要與四海同康強。"]'),
('b9e7b199-f5d1-4c6e-9b3b-fe5852b441e7','送杜安行東上','郭印','宋','宋诗','song-poetry','','[]','憶初謀食廣漢城，同時偶得三益友。',192,'全唐诗/poet.song.95000.json','["憶初謀食廣漢城，同時偶得三益友。", "心將金石許平生，但笑紛紛翻覆手。", "人言兄弟性稍異，朝暮追隨秪詩酒。", "而今星散各參辰，空餘孤月照窗牖。", "少城咫尺有張侯，素書頻得問安否。", "蒲節三月不厮見，夢繞錦屏山下走。", "更憐吾子别經年，幽懷鬰鬰無由剖。", "况兹來書又東去，萬里嚴風吹馬首。", "朝廷多事正求言，自負應云舌在口。", "力陳時策瘳邦國，肯與寒儒較先後。", "男兒立志豈尋常，要使高名齊北斗。", "一科一第奚足道，富貴浮雲非我有。"]'),
('890d6074-1b2c-4747-90e7-c3eba68fb2d3','送王吉先兄弟赴試','郭印','宋','宋诗','song-poetry','','[]','我聞迺翁學汪洋，曾游桂窟攀天香。',119,'全唐诗/poet.song.95000.json','["我聞迺翁學汪洋，曾游桂窟攀天香。", "青袍藍縷窮益剛，更無黄金遺諸郎。", "大兒氣質和而莊，腹有詩書言有章。", "仲子標姿何昻昻，頗聞論議生鋒鋩。", "兩君遊戲翰墨場，乘風鼓翻相翺翔。", "飛上天庭仍引吭，俯視諸子如蜩螗。", "華煜煜春揚芳，綰綬歸來慰北堂，坐令門地增輝光。"]'),
('efaf9b79-31cc-4c2f-a387-6efca5f5a03f','送莫少虛赴省試','郭印','宋','宋诗','song-poetry','','[]','莫君江南佳公子，才華秀拔春蘭馥。',256,'全唐诗/poet.song.95000.json','["莫君江南佳公子，才華秀拔春蘭馥。", "少年意氣壯虹霓，豪邁不入時人目。", "酒量逡巡百盞空，詩鋒頃刻千毫禿。", "我從識面已忻慕，每恨往還心未熟。", "官同古雒豈偶然，一見相忘倒胸腹。", "談道論文俱入妙，夜闌燭短頻更僕。", "聖處玄微得我疑，君獨心通如破竹。", "要將土苴活邦家，條上封章抵車軸。", "嘉謀讜議期見用，不學賈生空痛哭。", "行行提筆戰春闈，篋中尚有三千牘。", "科名唾手真餘事，力轉天迴迺民福。", "當今公道青雲平，忍埋光采甘沈陸。", "欲隨君往路無繇，只欠雙翰來插肉。", "殷勤别酒休辭醉，馬已就銜車已輹。", "蜀山崎嶇秦甸寒，屈指深冬到輦轂。", "焚舟計決攜家去，努力加飡此爲祝。"]'),
('b932ec06-3720-4b46-806c-03304dd29a64','當可以邑士將赴類試作詩饑之因效其體','郭印','宋','宋诗','song-poetry','','[]','丹山采鳳群鳴集，雲外舒張覽輝翼。',128,'全唐诗/poet.song.95000.json','["丹山采鳳群鳴集，雲外舒張覽輝翼。", "錦屏相望不千里，音中簫韶有人識。", "朝家選舉専一科，翰墨之工拔士多。", "好將筆力覷天巧，斡旋正氣回狂波。", "鯨鯢未翦龍移宅，吾皇饑渴人材得。", "雕蟲小技何足論，要吐胸中濟時策。", "吳山遼邈天門高，尺紙輸忠氣自豪。", "程文奏御宸心悦，青紫紛紛換白袍。"]'),
('3b4dfe8b-b7f7-4461-b17b-4001cfab4446','陪程元詔文彧李久善游漢州天寧元詔有詩見遺次韻答之','郭印','宋','宋诗','song-poetry','','[]','四海豈無兄弟親，氣合行須同父母。',176,'全唐诗/poet.song.95000.json','["四海豈無兄弟親，氣合行須同父母。", "相逢坐語忽移時，不覺朝飡輒過午。", "品評人物妙雌黄，議論邦家入覼縷。", "危言齰舌久自吞，幽憤填膺欣欲吐。", "字字珠璣落齒牙，篇篇錦繡裁胸腑。", "已驚大敵森戈矛，端笑羸師卧旗鼓。", "憐君風韻過諸王，顧我才情非小杜。", "何當再訪南歸僧，不恥更問西來祖。", "欲登塔級挽晴雲，更試茶甌潑新乳。", "平生識面有千百，屈指論心無四五。", "偶然流水遇知音，爲抱焦桐弄宮羽。"]'),
('b451702f-5d10-4686-810a-b18ae4d58ccb','感時一首再用前韻呈元詔久善文彧','郭印','宋','宋诗','song-poetry','','[]','我傷天缺無人補，四海嬰兒失其母。',176,'全唐诗/poet.song.95000.json','["我傷天缺無人補，四海嬰兒失其母。", "北人躍馬渡黄河，請和使者空旁午。", "二君北去宗族從，國祚千鈞垂一縷。", "天心保趙有真孤，重雲翳日今復吐。", "萬姓謳歌子啓賢，沈痛脱然離肺腑。", "聞招賢士築層臺，更納直言懸諫鼓。", "彌縫輔贊要真儒，相國豈無房與杜。", "中興之主信非常，睿武英明如太祖。", "巍巍虞舜有重瞳，穆穆文王生四乳。", "鑾輿若返天下安，未說登三并咸五。", "咄嗟廟堂不須憂，行看兩陛舞干羽。"]'),
('8377e7e0-ef0b-41dc-a7e7-355fc919e4fd','次韻李智淵暮行湖上','郭印','宋','宋诗','song-poetry','','[]','晚凉曳杖尋幽絕，怪樹相逢如磬折。',80,'全唐诗/poet.song.95000.json','["晚凉曳杖尋幽絕，怪樹相逢如磬折。", "縈紆小徑渾路迷，突兀高亭補林闕。", "襲人暗遞竹間風，延客長明波底月。", "游魚適性頻往來，歸鳥呼鶵弄清越。", "避炎終夕見天真，脱巾露頂腳不韈。"]'),
('cd09d74b-bf90-4205-8344-1e9bfa18f418','和元汝功江樓待月','郭印','宋','宋诗','song-poetry','','[]','危樓百尺閑臨水，玉宇無雲天萬里。',128,'全唐诗/poet.song.95000.json','["危樓百尺閑臨水，玉宇無雲天萬里。", "悠悠山月湧晴空，舉頭拭目增歡喜。", "魚龍何處深避藏，影落澄江清徹底。", "欲揖嫦娥上廣寒，古來遭遇應無幾。", "吾心空洞與物齊，視我如人人如豕。", "那堪河嶽盡播遷，富貴功名心已死。", "世衰俗薄異炎凉，只有高人興味長。", "此時此樂何不賞，瞥眼餘生飛電光。"]'),
('a4186181-0c8b-4675-9459-baba6b22ba30','中秋待月以星辰避彩乾坤靜爲韻分得避字','郭印','宋','宋诗','song-poetry','','[]','大火西流金用事，四海八荒蟠殺氣。',224,'全唐诗/poet.song.95000.json','["大火西流金用事，四海八荒蟠殺氣。", "風凄露冷雨涔涔，草木山川遍憔悴。", "天公有眼老亦昏，妙手憑誰刮雙翳。", "一年佳月在今夕，可奈太清雲點綴。", "大威神力宰官身，開闔陰陽本游戲。", "晚來微念入何許，頃刻氛霾變澄霽。", "坐客驚起一凭欄，三峨新掃脩眉翠。", "瑤臺飛鏡貼寒空，流水無聲光滿地。", "明吞萬象卻星辰，影落千巖走魑魅。", "樽罍預設衆初疑，喚得嫦娥乃容易。", "良夜沈沈桂樹高，興發卻嗟清影駛。", "此時此樂不長有，一醉已拚那敢避。", "更闌酒盡東方白，望舒迤邐還歸轡。", "我欲從之上廣寒，挹取金波洗塵世。"]'),
('fca9abf7-48c3-4a4d-8e98-88b629bf1b87','和元守中秋月夜韻','郭印','宋','宋诗','song-poetry','','[]','曩爲癡兒未識月，夜明喚作山陰雪。',256,'全唐诗/poet.song.95000.json','["曩爲癡兒未識月，夜明喚作山陰雪。", "翻笑老人立其下，皓彩亭亭映華髮。", "晦朔弦朢總不知，三五那能問盈缺。", "有時暮宿招提境，插天不愛金銀塔。", "壯年觀覽稍好奇，眼看絕景一何稀。", "中秋翫月定忘寢，往往連夕追輕肥。", "歡呼共吸盃中影，旋瞻寶鏡天邊飛。", "欲速嫦娥下霄漢，論心執手與同歸。", "老來愛身如愛國，暑氣藴隆驚吏酷。", "况當夔子瘴癘地，白露漙空尚蒸溽。", "可憐今宵月色凉，灔灔寒光滿坑谷。", "不論貴賤及富貧，茅屋朱門皆變玉。", "我亦乘興上層臺，但無佳客同尊罍。", "坐久歸來略假寐，牀前見月枕還推。", "不知此夜爲誰好，一曲長歌動九垓。", "人生窮達何足算，但把餘齡付酒盃。"]'),
('437cf058-dd03-4e95-a960-caa076188572','和程文彧九日詩','郭印','宋','宋诗','song-poetry','','[]','平生懶惰無拘逼，學道唯將寸陰惜。',192,'全唐诗/poet.song.95000.json','["平生懶惰無拘逼，學道唯將寸陰惜。", "手披目覽不自勤，俯視仰觀如有得。", "王侯螻蟻同丘墟，身外紛紛了無益。", "况值秋風草木枯，仍驚羽檄文書急。", "蕭條情思殊曩時，畏見重陽百憂集。", "花披黄金豈復知，酒送白衣元未識。", "計侯開筵及芳辰，置我坐隅非惡客。", "衰顔不紅鬢失青，一笑頽然倚歡伯。", "醉來說禪傍無人，若道箇中嫌揀擇。", "古今一照事俱空，物我兩忘心自適。", "明朝梅福記新詩，鏘鏗未減金聲擲。", "何如邀我卧東籬，天地從敎爲幕席。"]'),
('218db389-5290-480f-807c-24b4e4f3b8a4','積雪','郭印','宋','宋诗','song-poetry','','[]','一夜蕭蕭灑竹聲，漏水未殘天忽明。',136,'全唐诗/poet.song.95000.json','["一夜蕭蕭灑竹聲，漏水未殘天忽明。", "初疑落月照東榮，樹雞烏鵲紛紛驚。", "起來積雪爛中庭，窪陷汙穢悉已平。", "海水飛波上棟甍，萬瓦堆鹽一尺盈。", "此身恍若游天京，銀樓玉闕爭崢嶸。", "仙人想見冰霜清，園林草木皆瑤瓊。", "尊中有酒且細傾，農家活計在深耕。", "明年歲事欣已成，且把賦餘養殘齡，天邊日望隕欃槍。"]'),
('21901a52-2466-4683-83a8-147a88f3dc03','時升詠雪禁體物矣而彥序復爲之取韻尤嚴勉強攀和','郭印','宋','宋诗','song-poetry','','[]','朔風吹空高岡裂，忍凍幽人心似鐵。',160,'全唐诗/poet.song.95000.json','["朔風吹空高岡裂，忍凍幽人心似鐵。", "今朝雲色一天同，片片如簁墮濃雪。", "影搖寒水照曈曨，聲瀉黄蘆聽騷屑。", "澗谷凝時麕鹿死，園林壓處桑榆折。", "乃知造物本均平，高下不論凹與凸。", "登臨四顧浩漫漫，千村萬落青烟滅。", "憶昔子卿使匈奴，不拜穹廬何勇決。", "漠北酸寒十九年，鬢鬚脱盡形容薾。", "故人今亦在窮荒，高風凜凜皆傳說。", "鴻雁南來好繫書，應念邦家五情熱。"]'),
('ba3e526c-f5e1-438c-92aa-cfaa6215ee4a','眉州太守劉公忽於池中獲東坡所作遠景樓碑鄉人費洪雅有詩美之因率同賦次其韻','郭印','宋','宋诗','song-poetry','','[]','東坡淪没文委地，藝圃書林荒不治。',144,'全唐诗/poet.song.95000.json','["東坡淪没文委地，藝圃書林荒不治。", "遺編禁錮學無師，木不從繩金失礪。", "高樓遠景尚崔嵬，妙琢雄詞非骩骳。", "幾年困厄在污池，照夜寒光空水底。", "有如鐘磬傳不朽，壁間字字搖科斗。", "雷霆破蟄里耳驚，龍蜧蟠泥神物守。", "豐城劍氣異青黄，一遇雷公難祕藏。", "僵碑植立豈偶爾，文章政事兩熒煌。", "舊俗千年蒙敎化，濯以江漢暴秋陽。"]'),
('e7a31e6f-9815-4665-a745-8dc99bb944ec','題史元量芳潤堂','郭印','宋','宋诗','song-poetry','','[]','聖經杲杲日翔空，元與後學開愚蒙。',192,'全唐诗/poet.song.95000.json','["聖經杲杲日翔空，元與後學開愚蒙。", "著述成書不得已，令人誦習知吾宗。", "辭文旨遠非外至，一一流出自胸中。", "如木有根水有源，敷榮浸漬乃無窮。", "此道含靈悉具足，聖人庸人心本同。", "如何異見立仁智，百轍千歧礙不同。", "尋枝逐派遂忘返，癡兒失路迷西東。", "豈無達者爲拈出，抉剔衆瞽刳群聾。", "史侯名堂深意在，眼懸明鏡磨青銅。", "欲將妙義示當世，豈獨用訓垂髫童。", "我初聞之喜擊節，心心相照密沖融。", "作詩粉飾雖贅語，要令萬古還淳風。"]'),
('3edb8984-80de-4da4-b07d-7babb7ff2b99','普慈學官何子固廨舍有溪月軒明復留詩用其韻','郭印','宋','宋诗','song-poetry','','[]','碧霄桂影墮寒溪，賞心正與幽人期。',128,'全唐诗/poet.song.95000.json','["碧霄桂影墮寒溪，賞心正與幽人期。", "憑軒一俯吟思發，雕肝鏤肺成新詩。", "水流月出咸自爾，去來休論東與西。", "句中之眼落第二，紛紛名字俱人爲。", "胡不反觀自已月，照耀古今無遷移。", "有客問我月安在，天上人間總不知。", "光吞萬象竟何有，一語誑人真自欺。", "我欲提此吹毛劍，戮盡叢林多口師。"]'),
('1fbc0d16-8638-4114-812f-80490e3f1364','忘機臺','郭印','宋','宋诗','song-poetry','','[]','累石成臺如蟻垤，對此澄江千丈闊。',166,'全唐诗/poet.song.95000.json','["累石成臺如蟻垤，對此澄江千丈闊。", "春輪旋轉疾如飛，隔岸傳聲無間歇。", "風標公子鏡中來，爲我沙汀凝片雪。", "晚晴更是斜陽好，樹外殘霞紅一抹。", "平生任運息機心，麋鹿可馴禽可狎。", "生憎智巧犯人爲，激水翻車真太黠。", "君不見海上之鷗胡不下，當時妄念差一髮。", "又不見漢陰抱甕用力多，區區反笑桔槔拙。", "我今與物既大同，積刼情塵俱泯絕。", "天機密契有誰知，強立臺名太饒舌。"]'),
('4eec3c83-d1ba-4dc2-8d7f-5c7c5aa42aa6','讀易一首簡劉韶美','郭印','宋','宋诗','song-poetry','','[]','學易不識日月魂，盲人展轉誤銅盆。',80,'全唐诗/poet.song.95000.json','["學易不識日月魂，盲人展轉誤銅盆。", "分陰分陽發天祕，羲文孔子同一門。", "頭童習之老鬅鬙，熙熙未夢春臺登。", "一朝索得乾坤藴，豈但潛龍及履冰。", "與君細評寶花紛，只恐鬼神潛聽聞。"]'),
('55059f01-bad9-4afb-9d18-8d409bfdd682','說禪一首簡劉韶美','郭印','宋','宋诗','song-poetry','','[]','小知小見弄精魂，正似醯雞居覆盆。',80,'全唐诗/poet.song.95000.json','["小知小見弄精魂，正似醯雞居覆盆。", "茫茫大道絕南北，六通四闢初無門。", "不離當處遍高深，誰謂如天莫可登。", "世人聾瞶喚弗譍，執熱爲火寒爲冰。", "雷霆蟋蟀一竅均，觀音不在耳邊聞。"]'),
('139180ba-ec6f-42e7-8eeb-2704e45c6673','劍篇次元汝功韻','郭印','宋','宋诗','song-poetry','','[]','陽金爲魂陰爲魄，百鍊寧容垢膩蝕。',128,'全唐诗/poet.song.95000.json','["陽金爲魂陰爲魄，百鍊寧容垢膩蝕。", "出匣風雲凜凜寒，觀者堵牆皆辟易。", "發硎利刃思一試，佩刀匕首都棄置。", "鯨鯢戮盡四海清，英豪始慰平生志。", "長河喬嶽暗風沙，高山大澤蟠龍蛇。", "君家自有尚方賜，不須嫉世空吁嗟。", "操舟渡江勿虞破，中流斬蛟平地過。", "天下蒼生奈若何，安石且起東山卧。"]'),
('ef477fd7-7d02-487f-bad5-d426bd722169','月下觀梅寄蒲大受','郭印','宋','宋诗','song-poetry','','[]','東君嚴裝行駕車，天遣此花爲前驅。',96,'全唐诗/poet.song.95000.json','["東君嚴裝行駕車，天遣此花爲前驅。", "粉苞五出絳蠟趺，犯寒獨逞冰雪膚。", "幽園邂逅疑仙姝，香飇馥馥浮襟裾。", "天邊流月光彩舒，素娥下與論錙銖。", "遶樹顧影空踟躇，清賞恨無佳人俱。", "一枝遠贈意何如，聊寫殷勤當尺書。"]'),
('a2f8222e-fe69-4344-a226-61583fb3f75f','蘭坡','郭印','宋','宋诗','song-poetry','','[]','梅花掃迹春無光，繼踵惟有幽蘭香。',160,'全唐诗/poet.song.95000.json','["梅花掃迹春無光，繼踵惟有幽蘭香。", "天姿沖澹謝朱粉，睥睨百卉皆優倡。", "高人採擷紉爲佩，養之盆盎移中堂。", "微風馥馥來何所，一干鼻觀尤非常。", "年來屢遭白眼笑，過而不顧夫何傷。", "深山窮谷遂真性，寂寞無人亦自芳。", "憶昔靈均滋九畹，貞潔內守甘退藏。", "衆醉獨醒隘八表，回視俗物都茫茫。", "我今日暮前途窄，握香不羨尚書郎。", "荒坡滿植作知己，從兹身世兩相忘。"]'),
('33e07c27-e5a1-45fd-9449-87c285b26f0c','和時升種竹韻','郭印','宋','宋诗','song-poetry','','[]','何物比君子，猗猗庭前竹。',184,'全唐诗/poet.song.95000.json','["何物比君子，猗猗庭前竹。", "直節虛心人不顧，高標雅態自殊俗。", "千畝碧雲雖未有，數竿清風也自足。", "興來尋訪不知懶，到處敲門忘檢束。", "身居市廛心在野，山林痼疾今彌篤。", "直舍初開露井寛，檀欒只欠森森玉。", "君詩贈我何相知，攝衣起謝容正肅。", "緬思竹林賢，自昔高品目。", "當時昏濁亂一世，七子風流豈容黷。", "衆人皆醉我獨醒，正似霜筠異群木。", "不妨糟丘寄孤根，秋風相伴傾寒醁。", "煩君更作長短句，爲我商聲歌此曲。"]'),
('94e6c060-2d5b-4729-aef7-962946754e21','次韻杜永年東齋種竹','郭印','宋','宋诗','song-poetry','','[]','王郎英骨今已枯，風流聲名渾未除。',160,'全唐诗/poet.song.95000.json','["王郎英骨今已枯，風流聲名渾未除。", "結交斯人千載上，唯君執手同登車。", "平生愛竹遂成癖，竹間醉倒無人扶。", "今日君醒竹還醉，區區手植不暇餔。", "頗懷種柳陶尹令，更慕滋蘭屈大夫。", "况復此君尤灑落，幽齋安可一日無。", "塵埃捶楚縱未免，入門一見心自蘇。", "是中真樂難語俗，耳目已謝聲色娛。", "中虛自有天遊地，應笑勃谿紛婦姑。", "竹葉問君能造否，何時餉我一樽酒。"]'),
('7b83357a-51b4-4975-a613-5f522002ac8c','茶詩一首用南伯建除體','郭印','宋','宋诗','song-poetry','','[]','建置茗飲利無窮，除去睡魔捷如攻。',96,'全唐诗/poet.song.95000.json','["建置茗飲利無窮，除去睡魔捷如攻。", "滿篋龍團重絕品，平視紫笋難爲同。", "定知一啜爽神觀，執熱往往腋生風。", "破碎月輪午窗底，危冠欲墮呼樵童。", "成仁豈憚粉身骨，收取袪煩療疾功。", "開陳作經憶桑苧，閉眼便覺精神通。"]'),
('a0ee6c5e-a2ab-4ede-a8f3-20ba2a30e633','食蝦蟆詩','郭印','宋','宋诗','song-poetry','','[]','蝦蟆胡爲亦水族，形貌百醜誰爾憐。',162,'全唐诗/poet.song.95000.json','["蝦蟆胡爲亦水族，形貌百醜誰爾憐。", "天陰雨濕得快意，鳴聲呷呷何囂喧。", "才離泥淖矜跳躑，腳手那解高攀緣。", "一時鼃蛤結儔侶，紆青拖紫紛駢闐。", "漁童網罩入市賣，痱磊成串不論錢。", "有客殷勤勸我食，犀筯未下嫌腥羶。", "煎膏輭玉定虛語，猘犬所傷或可痊。", "天生此物苦無用，汙穢陂池宜棄捐。", "如何月窟亦容汝，時放饞口傷清圓。", "我願蟈氏灰灑無噍類，免使成精飛上天。"]'),
('823e6d26-5b90-4e62-be11-bbb4e6c2f975','聞車駕幸金陵二首  其一','郭印','宋','宋诗','song-poetry','','[]','強敵憑陵極，神天亦惡盈。',48,'全唐诗/poet.song.95000.json','["強敵憑陵極，神天亦惡盈。", "一人知順動，四海望親征。", "劍戟披霜利，壺漿夾道迎。", "此行如破竹，不戰復三京。"]'),
('844ca59b-a871-4e90-9d99-0dd6e634f6b6','聞車駕幸金陵二首  其二','郭印','宋','宋诗','song-poetry','','[]','暫駐金陵蹕，乘時更北轅。',48,'全唐诗/poet.song.95000.json','["暫駐金陵蹕，乘時更北轅。", "六軍思電擊，萬騎聳雲屯。", "運協中天數，人欣太祖孫。", "重恢文武境，披莽立乾坤。"]'),
('beda75cc-7f38-4338-848b-ce62b82f5062','居官一首呈大受明舉','郭印','宋','宋诗','song-poetry','','[]','未有林泉分，紅塵且強顔。',48,'全唐诗/poet.song.95000.json','["未有林泉分，紅塵且強顔。", "最憐官舍僻，不羡野人閑。", "疏密門前樹，高低城上山。", "偶逢佳客至，縱步得追攀。"]'),
('b6dcbecc-9f13-4b14-a6ed-174974fdcfe8','贈時升','郭印','宋','宋诗','song-poetry','','[]','平生真樂處，了不係窮通。',48,'全唐诗/poet.song.95000.json','["平生真樂處，了不係窮通。", "門對千山雪，家饒四壁風。", "聖功緗帙外，文略絳帷中。", "富貴何爲者，邯鄲一夢空。"]'),
('a585fbfc-07d9-43a7-be48-a7dc13eca516','懷莫少虛','郭印','宋','宋诗','song-poetry','','[]','把酒論文處，操觚草奏時。',48,'全唐诗/poet.song.95000.json','["把酒論文處，操觚草奏時。", "清宵仍夢到，白日更心馳。", "北闕山川邈，西風歲月移。", "歸期今已緩，兩地一相思。"]'),
('eb09e032-ca5b-4309-a455-8ef9bfa40b06','寄馮當可','郭印','宋','宋诗','song-poetry','','[]','合散真堪笑，回頭迹已陳。',48,'全唐诗/poet.song.95000.json','["合散真堪笑，回頭迹已陳。", "交情元共月，樂事不關春。", "委俗終違己，躭經亦醉人。", "行藏隨所遇，了此百年身。"]'),
('9b328b97-6e52-4b06-af95-d6ffe066a74c','寄王褒伯和明舉韻二首  其一','郭印','宋','宋诗','song-poetry','','[]','天涯初得子，氣味巧相如。',48,'全唐诗/poet.song.95000.json','["天涯初得子，氣味巧相如。", "地遠頻勞夢，心通少寄書。", "月亭空想像，風閣屢踟蹰。", "别後無窮意，相逢只挽裾。"]'),
('bd4eccf4-5701-4145-bfea-bc7e39da9183','寄王褒伯和明舉韻二首  其二','郭印','宋','宋诗','song-poetry','','[]','會面知何日，愁懷待一舒。',48,'全唐诗/poet.song.95000.json','["會面知何日，愁懷待一舒。", "吾曹皆委運，世事勿論渠。", "故國有喬木，先人無敝廬。", "岷山思共隱，此計孰云疏。"]'),
('3459239b-1cd0-42b4-9781-1550aa9a6258','贈別何耕道','郭印','宋','宋诗','song-poetry','','[]','又作匆匆别，能忘黯黯愁。',48,'全唐诗/poet.song.95000.json','["又作匆匆别，能忘黯黯愁。", "五年如隔世，一日定三秋。", "曉雨莫驚夢，斜陽休倚樓。", "只憂豺虎横，君去善爲謀。"]'),
('262ed5ba-afe5-4aa2-b12e-607784220312','送贊可參議赴臨安倅三首  其一','郭印','宋','宋诗','song-poetry','','[]','春水歸舟疾，秋天去路高。',48,'全唐诗/poet.song.95000.json','["春水歸舟疾，秋天去路高。", "乍辭王儉幕，行佩呂虔刀。", "畿甸略舒驥，海門須釣鼇。", "平生忠信在，枕席過風濤。"]'),
('ab40eb5c-8250-4a3f-add5-1c918f201ba6','送贊可參議赴臨安倅三首  其二','郭印','宋','宋诗','song-poetry','','[]','紛紛稱别駕，天邑獨爲榮。',48,'全唐诗/poet.song.95000.json','["紛紛稱别駕，天邑獨爲榮。", "日月光偏近，雲霄路正平。", "幾年留楚峽，一旦上蓬瀛。", "廊廟皆知己，彈冠意氣生。"]'),
('a18be763-1c5c-4ac0-ad21-4f8df53b1317','送贊可參議赴臨安倅三首  其三','郭印','宋','宋诗','song-poetry','','[]','亭上銜盃日，江邊摻袂時。',48,'全唐诗/poet.song.95000.json','["亭上銜盃日，江邊摻袂時。", "一年渾共醉，萬里各相思。", "老得青眸顧，心將白首期。", "青雲如在手，故舊莫遐遺。"]'),
('68d7b35b-3f74-4e14-aaca-b604c2fd6917','書懷二首  其一','郭印','宋','宋诗','song-poetry','','[]','奔走塵埃內，拘攣筦庫間。',48,'全唐诗/poet.song.95000.json','["奔走塵埃內，拘攣筦庫間。", "是心能曠適，何地不清閑。", "有客勸投紱，無錢堪買山。", "尚憐耽寸祿，理亂亦相關。"]'),
('77c14d75-24fb-430c-9e9c-bbdee2ffd9eb','書懷二首  其二','郭印','宋','宋诗','song-poetry','','[]','四十行將至，空懷晚歲憂。',48,'全唐诗/poet.song.95000.json','["四十行將至，空懷晚歲憂。", "看書渾欲睡，照鏡秪堪羞。", "開口舌猶在，拂衣心未休。", "西風羡鵰鶚，鼓翮占高秋。"]'),
('20326adb-7a2c-4450-a035-2f7cd3632581','次韻蒲大受書懷十首  其一','郭印','宋','宋诗','song-poetry','','[]','憤時唯泯默，憂國漫咨嗟。',48,'全唐诗/poet.song.95000.json','["憤時唯泯默，憂國漫咨嗟。", "上略思黄石，中原望翠華。", "散才甘社櫟，繫迹類匏瓜。", "世事無窮盡，吾生得有涯。"]'),
('034de5f4-1af9-49f5-aef3-75f4f6324544','次韻蒲大受書懷十首  其二','郭印','宋','宋诗','song-poetry','','[]','時亂那能定，民生不自聊。',48,'全唐诗/poet.song.95000.json','["時亂那能定，民生不自聊。", "鬢霜秋冉冉，心斾日摇摇。", "敢簉鵷鴻侣，空貽猿鶴嘲。", "眼前誰可意，風月是清交。"]'),
('86dca78c-e073-4295-bfeb-af89ecb44229','次韻蒲大受書懷十首  其三','郭印','宋','宋诗','song-poetry','','[]','世業工看卷，天資拙治生。',48,'全唐诗/poet.song.95000.json','["世業工看卷，天資拙治生。", "吏曹容小隱，廪祿代深耕。", "痛飲中賢聖，高吟適性情。", "妻孥隨我慣，自不厭藜羹。"]'),
('66cbae87-0c84-4598-94f7-636731e111ae','次韻蒲大受書懷十首  其四','郭印','宋','宋诗','song-poetry','','[]','物齊人即我，天運古猶今。',48,'全唐诗/poet.song.95000.json','["物齊人即我，天運古猶今。", "但得丹田固，寧憂白髪侵。", "情忘心坦坦，神定息深深。", "卻笑靈均輩，悲哀澤畔吟。"]'),
('14cdd66d-a437-47e1-83a1-a043ba798a00','次韻蒲大受書懷十首  其五','郭印','宋','宋诗','song-poetry','','[]','茅簷同廣廈，野蔌當珍羞。',48,'全唐诗/poet.song.95000.json','["茅簷同廣廈，野蔌當珍羞。", "擬作蓑衣放，寧爲肉食謀。", "沉思如有得，寡欲自無求。", "歎息吾衰甚，年來不夢周。"]'),
('730a8777-96c3-422d-8e00-b964110e80c1','次韻蒲大受書懷十首  其六','郭印','宋','宋诗','song-poetry','','[]','事業乖初願，聰明異昔時。',48,'全唐诗/poet.song.95000.json','["事業乖初願，聰明異昔時。", "病多難止酒，愁極漫哦詩。", "適俗非予好，從人莫己知。", "經營三徑就，安用印纍纍。"]'),
('c8da1f93-553e-4fd2-a0f8-a2fcd52ccb11','次韻蒲大受書懷十首  其七','郭印','宋','宋诗','song-poetry','','[]','州縣徒勞耳，春秋奈老何。',48,'全唐诗/poet.song.95000.json','["州縣徒勞耳，春秋奈老何。", "交游雙寂寞，名利兩蹉跎。", "帙散尤增睡，盃行且強歌。", "故人頻夢見，誰道隔山河。"]'),
('7de8cfec-51ce-4fb0-a619-703aabe86614','次韻蒲大受書懷十首  其八','郭印','宋','宋诗','song-poetry','','[]','日月當頭過，風光轉眼稀。',48,'全唐诗/poet.song.95000.json','["日月當頭過，風光轉眼稀。", "宦游元自薄，生計亦何微。", "要逐時情好，難令野性違。", "富貧同一飽，幸有北山薇。"]'),
('1f35b944-5e71-4b63-837e-1e415802431b','次韻蒲大受書懷十首  其九','郭印','宋','宋诗','song-poetry','','[]','世道交相喪，從誰見典型。',48,'全唐诗/poet.song.95000.json','["世道交相喪，從誰見典型。", "聖賢雖泯没，簡籍尚丁寧。", "學欲追三代，心終醉六經。", "如何資發冢，陂麥詠青青。"]'),
('bfb5b992-3ecd-4755-8b0d-77f6db26e54a','次韻蒲大受書懷十首  其一○','郭印','宋','宋诗','song-poetry','','[]','蒲郎吾畏友，詩句屹長城。',48,'全唐诗/poet.song.95000.json','["蒲郎吾畏友，詩句屹長城。", "道義千鈞重，功名一羽輕。", "鄧攸無後嗣，盧老是前生。", "世路羊腸劇，君心若砥平。"]'),
('66ad200c-3480-48f1-b430-56fa1be2a7af','次韻大受過蘇企道晚飲','郭印','宋','宋诗','song-poetry','','[]','痛飲忘形處，清談得意時。',48,'全唐诗/poet.song.95000.json','["痛飲忘形處，清談得意時。", "爲憐非惡客，還看出新詩。", "交道真難合，人情豈易知。", "林泉他日約，杖屨且相隨。"]'),
('bf1d4f16-7acc-4a96-92a6-de07ee143134','招耕道小飲','郭印','宋','宋诗','song-poetry','','[]','吏曹偷暇日，聊喜一追陪。',48,'全唐诗/poet.song.95000.json','["吏曹偷暇日，聊喜一追陪。", "竹色侵書卷，花光入酒杯。", "紅塵門外惡，白髮鏡中催。", "適意成嬉笑，人生得意回。"]'),
('79740f80-cb21-4ddd-b903-65dd4ac9f7f1','月夜小飲贈别元允','郭印','宋','宋诗','song-poetry','','[]','秋天凝顥氣，雲浄月流空。',48,'全唐诗/poet.song.95000.json','["秋天凝顥氣，雲浄月流空。", "千里幾時共，一樽今夕同。", "此君心似水，照我鬢如蓬。", "别酒那辭醉，行行太白東。"]'),
('4d742b4d-8786-4683-86f7-2aa33d5593ba','次韻曾帥遣意三首  其一','郭印','宋','宋诗','song-poetry','','[]','文章游戲裏，政事笑談餘。',48,'全唐诗/poet.song.95000.json','["文章游戲裏，政事笑談餘。", "種就三田藥，編成一帙書。", "情忘心自適，神定氣長舒。", "四海曾夫子，何人可學歟。"]'),
('c6d26073-c817-4fd2-b660-2b11cea4c086','次韻曾帥遣意三首  其二','郭印','宋','宋诗','song-poetry','','[]','庶民從號令，喜若聽春雷。',48,'全唐诗/poet.song.95000.json','["庶民從號令，喜若聽春雷。", "頓卻寒威退，全呼暖律迴。", "决癰資砭石，調鼎待鹽梅。", "坐看罷癃俗，眉間蹙額開。"]'),
('5ad73ca2-ff85-4790-8946-4b2e03e39803','次韻曾帥遣意三首  其三','郭印','宋','宋诗','song-poetry','','[]','每入先生室，欣聞所未聞。',48,'全唐诗/poet.song.95000.json','["每入先生室，欣聞所未聞。", "心君降六賊，筆陣掃千軍。", "爐鼎無人會，刀圭與客分。", "清齋時隱几，閑看嶺頭雲。"]'),
('16c9de75-0097-43c2-a589-1a41114fb349','次韻李久善近詩四首  其一','郭印','宋','宋诗','song-poetry','','[]','凛凛宸居壯，胡爲殺氣昏。',48,'全唐诗/poet.song.95000.json','["凛凛宸居壯，胡爲殺氣昏。", "姦臣由一轍，亂政出多門。", "天命何曾改，朝綱本自存。", "嗣皇真有志，反手定乾坤。"]'),
('a8ddea96-f929-468d-a8ff-5830aa16ff41','次韻李久善近詩四首  其二','郭印','宋','宋诗','song-poetry','','[]','塵氛蒙帝闕，國難古來稀。',48,'全唐诗/poet.song.95000.json','["塵氛蒙帝闕，國難古來稀。", "惻惻民情見，茫茫天道非。", "愚衷千慮切，孤宦一身微。", "萬里瞻行在，神魂日夜飛。"]'),
('e8bd8b35-bc53-4449-8ac0-839db688a775','次韻李久善近詩四首  其三','郭印','宋','宋诗','song-poetry','','[]','黄葉翻空舞，西風又作寒。',48,'全唐诗/poet.song.95000.json','["黄葉翻空舞，西風又作寒。", "懶將書帙整，愁見酒杯乾。", "物理秋多感，天文夜細看。", "鸞旗猶未返，一介敢偷安。"]'),
('d2c5dbbd-8a7a-4506-92cd-abbf75e2dfee','次韻李久善近詩四首  其四','郭印','宋','宋诗','song-poetry','','[]','高人來折節，不免稻粱謀。',48,'全唐诗/poet.song.95000.json','["高人來折節，不免稻粱謀。", "排悶唯詩卷，消愁只茗甌。", "此時同幕府，何日共仙舟。", "氣味難相得，逢君寫我憂。"]'),
('a07ed134-b0b2-403a-a312-d9c3532889e9','次韻杜安行見寄六首  其一','郭印','宋','宋诗','song-poetry','','[]','世事驚遷改，人生苦别離。',48,'全唐诗/poet.song.95000.json','["世事驚遷改，人生苦别離。", "一年仍異地，千里共勞思。", "雁足傳來信，蠅頭寫到詩。", "丁寧林下意，端不負心期。"]'),
('1f593375-3709-4823-9b54-7ffc2281ecbc','次韻杜安行見寄六首  其二','郭印','宋','宋诗','song-poetry','','[]','佳人秋水遠，思憶破晨昏。',48,'全唐诗/poet.song.95000.json','["佳人秋水遠，思憶破晨昏。", "酒尚無同把，文誰與細論。", "心交神自契，目擊道先存。", "他日如尋訪，柴扉水竹村。"]'),
('63a4264e-3171-4df1-b192-276a95363079','次韻杜安行見寄六首  其三','郭印','宋','宋诗','song-poetry','','[]','擬作淵明去，寧爲祖逖先。',48,'全唐诗/poet.song.95000.json','["擬作淵明去，寧爲祖逖先。", "築廬須近水，賣劍且求田。", "短燭窺今古，清樽樂聖賢。", "卜鄰真有意，相與慶餘年。"]'),
('bfa0135e-e5f1-4d1c-80bc-de15dcdd4bd7','次韻杜安行見寄六首  其四','郭印','宋','宋诗','song-poetry','','[]','華顛何見逼，強半百年身。',48,'全唐诗/poet.song.95000.json','["華顛何見逼，強半百年身。", "眼瞀文書過，心閑藥物親。", "衛生元有術，卻老未逢人。", "此道須君至，寒燈子細陳。"]'),
('d7d2b220-8aa9-4552-9375-7c6405eea5ad','次韻杜安行見寄六首  其五','郭印','宋','宋诗','song-poetry','','[]','蝸居營盖了，一色草茅新。',48,'全唐诗/poet.song.95000.json','["蝸居營盖了，一色草茅新。", "庭砌纔容馬，齋房可授賓。", "竹軒聊寄傲，蔬圃未全貧。", "隣舍逢知己，過從豈厭頻。"]'),
('d09f098d-9c90-4634-ab87-c65bd35f38bd','次韻杜安行見寄六首  其六','郭印','宋','宋诗','song-poetry','','[]','我愛使君直，使君憐我真。',48,'全唐诗/poet.song.95000.json','["我愛使君直，使君憐我真。", "短長才自異，勞逸事還均。", "意在形骸外，人疑手足親。", "共嗟征賦急，無術濟斯民。"]'),
('b055524a-9c72-4d32-b02b-4c753ee8a525','次韻宋正紀見貽','郭印','宋','宋诗','song-poetry','','[]','欲躡神仙境，深窮道德經。',48,'全唐诗/poet.song.95000.json','["欲躡神仙境，深窮道德經。", "坎男元服素，離女自披青。", "有意閑眠日，無心出戴星。", "但令爐竈煖，丹熟自然馨。"]'),
('76389be4-631e-4ccd-83dd-af9828c58ced','次智師韻','郭印','宋','宋诗','song-poetry','','[]','十年流宦海，飄泊一舟輕。',48,'全唐诗/poet.song.95000.json','["十年流宦海，飄泊一舟輕。", "敝屣世間事，浮雲身後名。", "學幾爲俗誤，詩欲鬭僧清。", "塵土非吾志，妻孥強使令。"]'),
('8de4f8ff-f7f9-4e2c-8c1b-44247bb7c0a5','次宋正紀見寄之作','郭印','宋','宋诗','song-poetry','','[]','薄祿謾婆娑，朝家事正多。',48,'全唐诗/poet.song.95000.json','["薄祿謾婆娑，朝家事正多。", "天昏雲障日，風勁葉辭柯。", "黔首難堪命，蒼穹尚薦瘥。", "中原戎馬盛，壯士敢誰何。"]'),
('51fe021b-1a85-491c-a031-049d21ed36ed','次劉子翼韻','郭印','宋','宋诗','song-poetry','','[]','逢迎欣晤語，喜氣破嚴凝。',48,'全唐诗/poet.song.95000.json','["逢迎欣晤語，喜氣破嚴凝。", "汩没歎塵吏，安閑輸野僧。", "宦情元自薄，俗眼莫相憎。", "松竹開三徑，他時我亦能。"]'),
('3a288117-b753-42d6-9f61-624ac43afc72','廣都世真上人南遊回見訪出群公詩見示丐予一語因思世間衲子盡是求佛覓禪底癡漢遂作數語警之','郭印','宋','宋诗','song-poetry','','[]','法象森羅萬，全歸一寸庵。',48,'全唐诗/poet.song.95000.json','["法象森羅萬，全歸一寸庵。", "有佛平生礙，無禪底處參。", "烏玄元自白，荼苦本來甘。", "前日南遊話，看君作麽談。"]'),
('ab4f56ba-9244-4528-b6ae-6f1f016bc003','次韻杜安行嘉陵春日書事十首  其一','郭印','宋','宋诗','song-poetry','','[]','老覺情懷别，愁隨節令來。',48,'全唐诗/poet.song.95000.json','["老覺情懷别，愁隨節令來。", "草茅思雨露，天地漲氛埃。", "屋雀春彌怨，山雲晝不開。", "何人知此意，藜杖獨登臺。"]'),
('83b93c1f-5103-46b3-8434-6ac662fdc777','次韻杜安行嘉陵春日書事十首  其二','郭印','宋','宋诗','song-poetry','','[]','公退幽齋坐，悠然對碧岑。',48,'全唐诗/poet.song.95000.json','["公退幽齋坐，悠然對碧岑。", "吹香花拂拂，圍翠竹森森。", "蝶散紅芳歇，鶯藏綠樹深。", "吾心清似水，塵境勿相侵。"]'),
('faf26227-7c5d-467c-a6eb-b987bf823819','次韻杜安行嘉陵春日書事十首  其三','郭印','宋','宋诗','song-poetry','','[]','雨過川原秀，烟光畫不如。',48,'全唐诗/poet.song.95000.json','["雨過川原秀，烟光畫不如。", "人情花動蕩，春意鳥分疏。", "造化空陳迹，乾坤一廣居。", "小軒聊燕息，夏屋正渠渠。"]'),
('49db274d-5534-451d-ad2d-be04d3a76e9e','次韻杜安行嘉陵春日書事十首  其四','郭印','宋','宋诗','song-poetry','','[]','圓吭高低唱，奇葩赤白章。',48,'全唐诗/poet.song.95000.json','["圓吭高低唱，奇葩赤白章。", "每嗟官束縛，肯放酒顛狂。", "幕燕終難穩，池魚欲自藏。", "宦游何處好，山北是吾鄉。"]'),
('8ec9411d-d5bd-4615-96b9-0a6cf3d1f012','次韻杜安行嘉陵春日書事十首  其五','郭印','宋','宋诗','song-poetry','','[]','弱柳青垂縷，新蒲紫作茸。',48,'全唐诗/poet.song.95000.json','["弱柳青垂縷，新蒲紫作茸。", "風光明老眼，歲月養衰容。", "涸思詩難巧，孤斟酒易供。", "逍遥北山下，一榻傲羲農。"]'),
('40cd644e-772a-49b0-9fe4-818c10093f05','次韻杜安行嘉陵春日書事十首  其六','郭印','宋','宋诗','song-poetry','','[]','江路曾浮宅，懸崖兩壁青。',48,'全唐诗/poet.song.95000.json','["江路曾浮宅，懸崖兩壁青。", "晴烟籠小艇，落照射高亭。", "花簇紅粧岸，鷗群白點汀。", "何時篷底卧，半夜酒初醒。"]'),
('2583b1de-e259-41c3-bab0-436628ce6846','次韻杜安行嘉陵春日書事十首  其七','郭印','宋','宋诗','song-poetry','','[]','誰念疲民瘠，空令戰士肥。',48,'全唐诗/poet.song.95000.json','["誰念疲民瘠，空令戰士肥。", "羽書傳警急，花院鎖芳菲。", "冠屨將身誤，山林與願違。", "兩途俱不遂，衰鬢綠毛稀。"]'),
('68cd5b08-8a50-48b7-ae27-544017f5fd3c','次韻杜安行嘉陵春日書事十首  其八','郭印','宋','宋诗','song-poetry','','[]','舉世趨昏濁，前賢慕獨清。',48,'全唐诗/poet.song.95000.json','["舉世趨昏濁，前賢慕獨清。", "低回從客笑，懷卷待時平。", "彭澤非難學，菟裘且旋營。", "樂哉莘野趣，功業在深耕。"]'),
('8d4b33d8-819a-408e-9818-ce7fff7f1e19','次韻杜安行嘉陵春日書事十首  其九','郭印','宋','宋诗','song-poetry','','[]','良友何年會，書來細作行。',48,'全唐诗/poet.song.95000.json','["良友何年會，書來細作行。", "柏寒知歲晚，花落笑春忙。", "從宦愆行樂，休心得坐忘。", "神爐丹已就，一粒待君嘗。"]'),
('7d07cfd9-e24c-41da-bab4-35329199cdca','次韻杜安行嘉陵春日書事十首  其一○','郭印','宋','宋诗','song-poetry','','[]','聖處沉潛久，心華始發明。',48,'全唐诗/poet.song.95000.json','["聖處沉潛久，心華始發明。", "絕知人事繆，頓覺世緣輕。", "俗薄天難定，時危道不行。", "折腰甘五斗，無意問弓旌。"]'),
('3f481348-a09e-4f10-9d3b-48927aaebcbf','次韻宇文德蒙春日道中二首  其一','郭印','宋','宋诗','song-poetry','','[]','滿目風光麗，春連幾處村。',48,'全唐诗/poet.song.95000.json','["滿目風光麗，春連幾處村。", "江山挑客思，桃李憶家園。", "飄泊流三峽，窮通付一罇。", "菟裘如可老，歸去葺衡門。"]'),
('89202691-2ccd-4cd4-acd6-13e09647d5f7','次韻宇文德蒙春日道中二首  其二','郭印','宋','宋诗','song-poetry','','[]','馬上花明眼，寧知道路遐。',48,'全唐诗/poet.song.95000.json','["馬上花明眼，寧知道路遐。", "山横千百嶺，人住兩三家。", "綠皺吹春水，紅舒抹曉霞。", "箇中佳趣在，何事苦咨嗟。"]'),
('0ab9bac2-67c8-412a-a033-00266e4308bf','感春','郭印','宋','宋诗','song-poetry','','[]','春光不覺老，兀坐掩深扉。',48,'全唐诗/poet.song.95000.json','["春光不覺老，兀坐掩深扉。", "寇盗時聞說，山林未忍歸。", "心驚幽鳥語，眼眩雜花飛。", "何日乾坤静，餘生得所依。"]'),
('e3eb0ecb-46a4-42f6-934a-245b545aad40','又用前韻','郭印','宋','宋诗','song-poetry','','[]','春事關心曲，無人晝款扉。',48,'全唐诗/poet.song.95000.json','["春事關心曲，無人晝款扉。", "鶯猶求友囀，燕亦認巢歸。", "物色濃如酒，風光駛若飛。", "幽齋誰與伴，窗外柳依依。"]'),
('94d8f7a0-7796-4d26-87e3-78db78a7fdb1','次韻邵子文感春之什','郭印','宋','宋诗','song-poetry','','[]','海內風塵漲，人間日月忙。',48,'全唐诗/poet.song.95000.json','["海內風塵漲，人間日月忙。", "鬢霜催晚景，盃蟻負春光。", "聞道花成錦，空憐鳥似簧。", "眼前朱墨亂，無處話愁腸。"]'),
('3df9cc44-0835-46f3-87c1-02d6111c7c65','晚春','郭印','宋','宋诗','song-poetry','','[]','三月韶華破，東君誰送歸。',48,'全唐诗/poet.song.95000.json','["三月韶華破，東君誰送歸。", "浮空新綠漲，舞砌亂紅飛。", "柳絮風初定，桃花水漸肥。", "羲和無計挽，獨立又斜暉。"]'),
('c62daac6-e471-4318-bf37-6814ca426a87','正紀用暮春韻見貽復和三章  其一','郭印','宋','宋诗','song-poetry','','[]','燕坐群魔伏，君心自晏然。',48,'全唐诗/poet.song.95000.json','["燕坐群魔伏，君心自晏然。", "神仙真可學，道術豈無緣。", "健比凌雲鶴，清同飲露蟬。", "後天應不老，何必羡彭年。"]'),
('616fa052-6ed6-4420-8a2c-0bfd24268961','正紀用暮春韻見貽復和三章  其二','郭印','宋','宋诗','song-poetry','','[]','萬形何苦役，兩曜不曾停。',48,'全唐诗/poet.song.95000.json','["萬形何苦役，兩曜不曾停。", "世事風中絮，人生水上萍。", "久能忘蟻慕，聊自學熊經。", "功滿他年後，虬龍定駕青。"]'),
('fa3dadf9-0619-43dd-bbf1-8f0235c71825','正紀用暮春韻見貽復和三章  其三','郭印','宋','宋诗','song-poetry','','[]','自得無爲理，行藏異世人。',48,'全唐诗/poet.song.95000.json','["自得無爲理，行藏異世人。", "片雲塵外侣，流水洞中賓。", "思慮何勞遣，形神已覺親。", "超然閲衆甫，陵谷幾回新。"]'),
('6dd8878e-dad5-43a2-b893-85a90895dc52','三月三十日前人有詩云共君今夜不須睡未到曉鍾猶是春再和前韻二首  其一','郭印','宋','宋诗','song-poetry','','[]','風雨年年横，鶯花處處殘。',49,'全唐诗/poet.song.95000.json','["風雨年年横，鶯花處處殘。", "衰顔隨節變，幽興與春闌。", "俗眼從渠白，孤就衷祇自丹。", "平生知任運，那復較暄寒。"]'),
('b975444c-ac8e-4366-8885-e2bd129e8c6d','三月三十日前人有詩云共君今夜不須睡未到曉鍾猶是春再和前韻二首  其二','郭印','宋','宋诗','song-poetry','','[]','三春渾索寞，百卉任摧殘。',48,'全唐诗/poet.song.95000.json','["三春渾索寞，百卉任摧殘。", "有感詩頻賦，無懽酒易闌。", "調和思玉燭，延駐仗金丹。", "難繫西飛日，吾心一寸寒。"]'),
('5ea2e0ed-8902-4f37-babc-42eb9537094b','五月十二日晚登平雲亭得平字齊字  其一','郭印','宋','宋诗','song-poetry','','[]','路向林端出，雲從屐齒生。',48,'全唐诗/poet.song.95000.json','["路向林端出，雲從屐齒生。", "山風迎夕起，烟樹接天平。", "倚杖聽僧語，窺簷待月明。", "幽禽知客意，時送兩三聲。"]'),
('0f42621f-4c0f-4d7d-94d1-b5d04538550e','五月十二日晚登平雲亭得平字齊字  其二','郭印','宋','宋诗','song-poetry','','[]','磴道穿喬木，危亭喜杖藜。',48,'全唐诗/poet.song.95000.json','["磴道穿喬木，危亭喜杖藜。", "郊原春樹暗，井邑暮烟低。", "日没牛羊下，山空鳥雀啼。", "超然塵世外，身與白雲齊。"]'),
('c163b773-fd78-46e1-a1bf-c9f951f7f814','五月十三日種竹偶成二首  其一','郭印','宋','宋诗','song-poetry','','[]','開拓無多地，栽培只數竿。',48,'全唐诗/poet.song.95000.json','["開拓無多地，栽培只數竿。", "雲分千畝潤，風送一窗寒。", "坐上清陰罩，墻邊野色團。", "課奴勤灌溉，日日報平安。"]'),
('e7ff3edf-7912-434d-add6-7bcd5de4ebb7','五月十三日種竹偶成二首  其二','郭印','宋','宋诗','song-poetry','','[]','園夫扶出徑，元是醉爲媒。',48,'全唐诗/poet.song.95000.json','["園夫扶出徑，元是醉爲媒。", "密葉疏疏理，纖根細細栽。", "捲簾斜日避，倚杖好風來。", "佳客如相顧，還能伴酒盃。"]'),
('11036530-34b1-46c4-8637-677627fa2baa','林下避暑','郭印','宋','宋诗','song-poetry','','[]','行道遭三伏，流年當百殃。',48,'全唐诗/poet.song.95000.json','["行道遭三伏，流年當百殃。", "舌乾元少味，體倦不安床。", "逃暑少寛舍，沃焦無冷漿。", "時依喬木下，俄頃得微凉。"]'),
('29cf1a09-1e73-4bea-8d11-92e66e3d795e','苦熱三首  其一','郭印','宋','宋诗','song-poetry','','[]','纖雲都掃迹，烈日正燔空。',48,'全唐诗/poet.song.95000.json','["纖雲都掃迹，烈日正燔空。", "人立洪爐上，魚遊沸鼎中。", "四山渾束熱，一葉不吹風。", "屈指秋期近，清凉四海同。"]'),
('35bcbf89-abf2-47af-99c3-5453d6b05be9','苦熱三首  其二','郭印','宋','宋诗','song-poetry','','[]','宇宙何蒸溽，山川久旱乾。',48,'全唐诗/poet.song.95000.json','["宇宙何蒸溽，山川久旱乾。", "浹膚惟汗雨，脱腕是冰紈。", "永晝固難避，終宵寧暫安。", "三農憂稼穡，無物可輸官。"]'),
('8f74909e-abe5-4f30-b9ab-cd4bbe948eaa','苦熱三首  其三','郭印','宋','宋诗','song-poetry','','[]','南方炎瘴極，所見異平生。',48,'全唐诗/poet.song.95000.json','["南方炎瘴極，所見異平生。", "日月雙風鞴，乾坤一火坑。", "泉源多水竭，官道少人行。", "卻憶岷山底，蕭然九夏清。"]'),
('12745baf-7f29-467e-8b2c-2f40767e4dc8','熱','郭印','宋','宋诗','song-poetry','','[]','落日暑猶劇，虛亭風不來。',48,'全唐诗/poet.song.95000.json','["落日暑猶劇，虛亭風不來。", "半身流汗雨，兩耳聒蚊雷。", "扇手何曾歇，漿甌未放迴。", "疇能呼屏翳，一霎蕩炎埃。"]'),
('45c1d52c-800f-449e-8936-fda5b69f15e2','三伏不熱','郭印','宋','宋诗','song-poetry','','[]','三伏元無暑，連旬雨復陰。',48,'全唐诗/poet.song.95000.json','["三伏元無暑，連旬雨復陰。", "朝朝閑舊扇，夜夜擁重衾。", "日晦浮雲翳，天愁沴氣侵。", "烽烟猶未息，一念一傷心。"]'),
('717e89d7-99c7-4e9a-90b5-73cf366d757f','立秋日出郊有感','郭印','宋','宋诗','song-poetry','','[]','霽色千山曉，秋聲一葉風。',48,'全唐诗/poet.song.95000.json','["霽色千山曉，秋聲一葉風。", "田原矜雨足，秔芋報年豐。", "甲胄三軍解，車書萬里同。", "黎元如永息，和義有深功。"]'),
('02e658a0-93bf-43c5-9c40-ebf2df3157f2','初秋','郭印','宋','宋诗','song-poetry','','[]','爽氣依辰至，乾坤不可收。',48,'全唐诗/poet.song.95000.json','["爽氣依辰至，乾坤不可收。", "林柯初脱葉，寒雁已賓秋。", "老逼羞看鏡，愁多怯上樓。", "只憂戎馬健，何日隕旄頭。"]'),
('0b4f76e9-9439-4ad0-a068-1bcefd38b567','七月十三日對月小集','郭印','宋','宋诗','song-poetry','','[]','露坐仍盤斚，澄澄夜色清。',48,'全唐诗/poet.song.95000.json','["露坐仍盤斚，澄澄夜色清。", "酒如君子厚，月似故人明。", "短舞天然態，長歌格外聲。", "歡情殊未極，樓鼓發深更。"]'),
('e5b16e81-3220-4c6c-97ae-877d00300a89','七月二十八日蒲大受仲明舉偶來會宿三首  其一','郭印','宋','宋诗','song-poetry','','[]','别袂無多日，愁腸已屢回。',48,'全唐诗/poet.song.95000.json','["别袂無多日，愁腸已屢回。", "未便新舍穩，先喜故人來。", "憂國空千慮，忘懷但一盃。", "相看情意好，歸轡不須催。"]'),
('ef922c72-96a0-44a0-b559-c68f47a84a52','七月二十八日蒲大受仲明舉偶來會宿三首  其二','郭印','宋','宋诗','song-poetry','','[]','少城能款曲，敝館辱留連。',48,'全唐诗/poet.song.95000.json','["少城能款曲，敝館辱留連。", "未攪秋風思，還同夜雨眠。", "烟塵驚絕塞，草木驗流年。", "斗酒君須醉，新詩看百篇。"]'),
('b2692e8a-5465-4772-9871-0c5092b06496','七月二十八日蒲大受仲明舉偶來會宿三首  其三','郭印','宋','宋诗','song-poetry','','[]','秋風今夕好，一笑偶然同。',48,'全唐诗/poet.song.95000.json','["秋風今夕好，一笑偶然同。", "時事囏難際，交情會合中。", "青雲渾作夢，白髮也應公。", "擬卜棲山計，應爲鄰舍翁。"]'),
('7ab61619-be09-432f-86a1-1ea4c1d8f8fe','中秋日赴史漕賞月二首  其一','郭印','宋','宋诗','song-poetry','','[]','秋色平分日，開筵命月輪。',48,'全唐诗/poet.song.95000.json','["秋色平分日，開筵命月輪。", "雲容休妬客，天意解隨人。", "平地鋪寒水，遥空絕點塵。", "素娥來入座，端不負良辰。"]'),
('af8c52ab-159a-412b-ab9a-369ea7985a4b','中秋日赴史漕賞月二首  其二','郭印','宋','宋诗','song-poetry','','[]','此夕非常夕，金波湧碧岑。',48,'全唐诗/poet.song.95000.json','["此夕非常夕，金波湧碧岑。", "一輪初散彩，八表盡傾心。", "永夜真同晝，浮雲不蔽陰。", "主人澄静性，萬古亦常今。"]'),
('065e2920-fe35-4b0a-be3c-ccff8efa7926','中秋日與諸公同遊寶蓮院分韻得塵字','郭印','宋','宋诗','song-poetry','','[]','路出青山近，招提更可人。',48,'全唐诗/poet.song.95000.json','["路出青山近，招提更可人。", "清心鐘磬響，遠迹簿書塵。", "晚日池亭迥，秋風杖屨親。", "頻來一尊酒，不畏老僧嗔。"]'),
('138f1cc6-6882-4305-bc64-412df74d114e','八月十六日觀月段氏亭次王師老韻','郭印','宋','宋诗','song-poetry','','[]','隱映孤亭小，回環萬竹幽。',48,'全唐诗/poet.song.95000.json','["隱映孤亭小，回環萬竹幽。", "水聲喧暗谷，月影淡高秋。", "物與黄昏静，人隨白日流。", "一椽堪送老，何必仲宣樓。"]'),
('fa0309b4-6f12-4b1a-8558-16226ff502da','山中九日','郭印','宋','宋诗','song-poetry','','[]','信馬幽尋慣，重陽未及家。',48,'全唐诗/poet.song.95000.json','["信馬幽尋慣，重陽未及家。", "清游貪翠巘，素約負黄花。", "縱目心先折，經秋鬢欲華。", "因循時節過，底處覓流霞。"]'),
('b3412fff-744b-447e-b41f-8ea14d5bd386','秋夜','郭印','宋','宋诗','song-poetry','','[]','萍梗何時定，愁懷與夜長。',48,'全唐诗/poet.song.95000.json','["萍梗何時定，愁懷與夜長。", "新秋猶逆旅，故國似他鄉。", "老馬頻嘶草，寒蛩空殷床。", "思歸不成夢，展轉及晨光。"]'),
('f54cd06a-ddd0-4a5a-bbc8-24745ec877c6','次韻費夢得晚秋感懷三首  其一','郭印','宋','宋诗','song-poetry','','[]','日落秋風晚，孤心正北飛。',48,'全唐诗/poet.song.95000.json','["日落秋風晚，孤心正北飛。", "地寒戎馬健，天闊塞鴻稀。", "翠葆幾時復，青山百匝圍。", "何當身傅羽，絕域問龍衣。"]'),
('81b3671c-e024-4904-b7b3-f15a4221f585','次韻費夢得晚秋感懷三首  其二','郭印','宋','宋诗','song-poetry','','[]','摇落秋風晚，凄凉又一秋。',48,'全唐诗/poet.song.95000.json','["摇落秋風晚，凄凉又一秋。", "漢家元再造，杞國謾多憂。", "七廟存餘澤，諸公合遠謀。", "痛心何日定，直待太平休。"]'),
('7edda156-9260-45c1-8a23-6a95eeac9fb6','次韻費夢得晚秋感懷三首  其三','郭印','宋','宋诗','song-poetry','','[]','摇落秋風晚，吾衰已一翁。',48,'全唐诗/poet.song.95000.json','["摇落秋風晚，吾衰已一翁。", "不堪居世上，寧忍卧山中。", "帷幄人焉用，塵埃帝尚蒙。", "仰天無計出，老淚濺寒空。"]'),
('688ee24c-476f-426b-847c-55dd90e0e2ea','早起待明詩','郭印','宋','宋诗','song-poetry','','[]','夜闌呼僕起，四視有無雲。',48,'全唐诗/poet.song.95000.json','["夜闌呼僕起，四視有無雲。", "天際星猶爛，山頭樹未分。", "蟲鳴何限苦，雞唱不曾聞。", "欲騐東方白，頻看掌上文。"]'),
('ed12e1e2-a4a4-4e82-9f04-fb5e9c84d374','曉','郭印','宋','宋诗','song-poetry','','[]','客宵無一事，達曉夢魂安。',48,'全唐诗/poet.song.95000.json','["客宵無一事，達曉夢魂安。", "窗隙簷光入，更籌漏水乾。", "田園終計决，游宦久心闌。", "懶起趨朝謁，從渠困馬鞍。"]'),
('b9471233-56d5-4dc4-a825-d1c0023a92df','朝來','郭印','宋','宋诗','song-poetry','','[]','朝來仍獨坐，心事有誰知。',48,'全唐诗/poet.song.95000.json','["朝來仍獨坐，心事有誰知。", "啅鵲傳枝喜，鳴鳩喚雨悲。", "整冠驚髮短，覽鏡覺顔衰。", "白日堂堂去，長繩不可羈。"]'),
('f2286cd7-c5ec-451c-acd4-08f2d88cf056','晝眠','郭印','宋','宋诗','song-poetry','','[]','齋館蕭然静，從容得晝眠。',48,'全唐诗/poet.song.95000.json','["齋館蕭然静，從容得晝眠。", "夢魂隨栩栩，晝腹任便便。", "不把分陰惜，能令雜慮捐。", "覺來神觀爽，依舊閲陳編。"]'),
('3b99eeb0-ebb0-46e9-8443-e6a83fa1574c','不寐','郭印','宋','宋诗','song-poetry','','[]','自憐聞道晚，習氣誤平生。',48,'全唐诗/poet.song.95000.json','["自憐聞道晚，習氣誤平生。", "詩債幾時盡，睡魔終夕輕。", "語言空自苦，德業竟何成。", "誓欲抛書冊，茅簷適性情。"]'),
('ac54ceb1-1c65-4bae-b17c-92be11c129d6','新浴','郭印','宋','宋诗','song-poetry','','[]','新向蘭湯浴，塵埃一洗清。',48,'全唐诗/poet.song.95000.json','["新向蘭湯浴，塵埃一洗清。", "振衣心自喜，出戶體還輕。", "沂水當年樂，驪山往事驚。", "昔人因悟道，妙觸永宣明。"]'),
('1a72b5de-21ba-4f07-ba4e-c9f5854b30c4','夏夜喜雨詩','郭印','宋','宋诗','song-poetry','','[]','夜坐飛蚊息，凉生戶牖中。',48,'全唐诗/poet.song.95000.json','["夜坐飛蚊息，凉生戶牖中。", "稍披風力快，俄聽雨聲雄。", "癘疫千家净，炎蒸一夕空。", "安眼知處處，端的謝天公。"]'),
('4cfabcea-5a5c-498a-8a0a-07ebf02a0dfb','值雨','郭印','宋','宋诗','song-poetry','','[]','慘慘雲頭暗，繩繩雨腳垂。',48,'全唐诗/poet.song.95000.json','["慘慘雲頭暗，繩繩雨腳垂。", "定應來洒道，不是故催詩。", "熱解非無益，凉生正所宜。", "多情如屏翳，相戲即相知。"]'),
('da66278f-2e6b-48a9-97e5-41df25b24f6a','久雨','郭印','宋','宋诗','song-poetry','','[]','四旬常苦雨，秋令歎先行。',48,'全唐诗/poet.song.95000.json','["四旬常苦雨，秋令歎先行。", "滴滴天垂淚，昏昏日翳睛。", "敢言頻屋漏，深恐害粢盛。", "換甲明朝是，人人望快晴。"]'),
('d0f61b56-07ba-4444-ab2d-1bf18e6e8f80','雨後','郭印','宋','宋诗','song-poetry','','[]','氣候西南異，山川自一方。',48,'全唐诗/poet.song.95000.json','["氣候西南異，山川自一方。", "暑殘秋更熱，雨過夜初涼。", "燈火容緗帙，詩書有錦囊。", "更深猶不寐，暗露襲衣裳。"]'),
('bcdde85d-475f-4404-a253-09bdf6538ca8','和趙彦和祈晴','郭印','宋','宋诗','song-poetry','','[]','靈宇祈昭霽，還車已報晴。',48,'全唐诗/poet.song.95000.json','["靈宇祈昭霽，還車已報晴。", "高空開曠蕩，遠樹見疏明。", "踴躍增行旅，歌謡徧耦耕。", "今年書大有，香飯亦炊秔。"]'),
('8f443ac5-6b3a-4007-a78c-2b0a8370a917','喜晴','郭印','宋','宋诗','song-poetry','','[]','淫雨何淹久，朝陽四望晴。',48,'全唐诗/poet.song.95000.json','["淫雨何淹久，朝陽四望晴。", "雲收山骨露，江落水痕生。", "豁豁知人意，欣欣見物情。", "天公因屏翳，勿使再縱横。"]'),
('f0f1c9ab-266a-46bc-9f4c-2448ffc02e64','朝霞詩','郭印','宋','宋诗','song-poetry','','[]','矯矯明天末，誰將絳帳供。',48,'全唐诗/poet.song.95000.json','["矯矯明天末，誰將絳帳供。", "陰雲收薄翳，晴日放先鋒。", "道路看行旅，田疇驗老農。", "乾坤今日意，群目散愁容。"]'),
('e7b883b0-0310-4c6e-99dd-3e21d8df06b7','晚意','郭印','宋','宋诗','song-poetry','','[]','睡起書齋寂，疏簾獨上鈎。',48,'全唐诗/poet.song.95000.json','["睡起書齋寂，疏簾獨上鈎。", "雨餘鵶噪晚，天濶雁横秋。", "物色供吟賦，功名歎滯留。", "兵戈今未息，回首不堪愁。"]'),
('dee74ee5-3f7e-4cc0-be6b-c621ad85fb55','秋陰','郭印','宋','宋诗','song-poetry','','[]','天宇秋雲濶，愁多日日陰。',48,'全唐诗/poet.song.95000.json','["天宇秋雲濶，愁多日日陰。", "山川相慘淡，物色自蕭森。", "雁失空中影，鐘沉風外音。", "分明含雨意，何事不爲霖。"]'),
('4be9c6bf-9c58-4ac4-897c-7f3ef9f761ca','十二月十三日喜雪二首  其一','郭印','宋','宋诗','song-poetry','','[]','蜀雪古來少，天雲今始同。',48,'全唐诗/poet.song.95000.json','["蜀雪古來少，天雲今始同。", "霏微初带雨，凌亂更從風。", "練欲拖平野，鹽疑撒遠空。", "小民咸喜見，誰復怨高穹。"]'),
('5b1bc4e8-1b45-4e49-abb8-a8f31434abfb','十二月十三日喜雪二首  其二','郭印','宋','宋诗','song-poetry','','[]','繽紛飛六出，景色兔園同。',48,'全唐诗/poet.song.95000.json','["繽紛飛六出，景色兔園同。", "桂樹非摧月，楊花不起風。", "布銀成世界，屑玉滿虛空。", "此地知豐樂，如何答上穹。"]'),
('4c9a99a8-58bb-401d-97e8-765b31e8540f','次韻史才孺詠雪四首  其一','郭印','宋','宋诗','song-poetry','','[]','始賀今朝雪，隆寒特地嚴。',48,'全唐诗/poet.song.95000.json','["始賀今朝雪，隆寒特地嚴。", "莫愁窮戶閉，還喜大田霑。", "黄竹歌休唱，紅爐火屢添。", "華顛應處處，早得是山尖。"]'),
('2770f1bd-0195-4bda-8a5d-83e2875ace89','次韻史才孺詠雪四首  其二','郭印','宋','宋诗','song-poetry','','[]','凍雲誰剪下，天地已凝嚴。',48,'全唐诗/poet.song.95000.json','["凍雲誰剪下，天地已凝嚴。", "試看郊原潤，何如雨露霑。", "漁蓑寒愈重，客舍恨猶添。", "曉起空庭步，深埋屐齒尖。"]'),
('4446b55f-9e6c-47eb-b976-524345077ca1','次韻史才孺詠雪四首  其三','郭印','宋','宋诗','song-poetry','','[]','陰陰彌宇宙，黯黯一天同。',48,'全唐诗/poet.song.95000.json','["陰陰彌宇宙，黯黯一天同。", "初訝銀爲界，元非玉散空。", "夜迷連皎月，曉舞助嚴風。", "真宰憑誰問，年來物未豐。"]'),
('6d1243b4-3b5c-482c-8056-5bbceb437952','次韻史才孺詠雪四首  其四','郭印','宋','宋诗','song-poetry','','[]','怪得天飛雪，寒威曉不同。',48,'全唐诗/poet.song.95000.json','["怪得天飛雪，寒威曉不同。", "練光鋪迥野，玉屑下長空。", "片片梅花雨，團團柳絮風。", "人間呈瑞應，還喜兆年豐。"]'),
('149d9970-9082-412b-82bc-34d5a881965d','出郭','郭印','宋','宋诗','song-poetry','','[]','步屧尋春去，郊原協氣薫。',48,'全唐诗/poet.song.95000.json','["步屧尋春去，郊原協氣薫。", "野花隨路見，幽鳥隔山聞。", "興遠連芳草，心閑對白雲。", "匆匆殊未愜，落日噪鴉群。"]'),
('b2b87ddc-19ef-46c1-8698-bb9fc43badaf','出郊','郭印','宋','宋诗','song-poetry','','[]','官曹拘束久，出郭便忘歸。',48,'全唐诗/poet.song.95000.json','["官曹拘束久，出郭便忘歸。", "江濶風烟澹，山稠草木稀。", "客情隨處好，鷗鳥自由飛。", "塵事聊相放，吾心一寸微。"]'),
('d762dd0e-eabe-41ae-9ec5-f08547839977','留宿田家','郭印','宋','宋诗','song-poetry','','[]','遲落前溪水，田家借一椽。',48,'全唐诗/poet.song.95000.json','["遲落前溪水，田家借一椽。", "容身函丈地，闔眼濕薪烟。", "馬飼牛欄下，人眠狗竇邊。", "此行頻窘澁，吾意亦安然。"]'),
('6f887530-a238-4c6b-887d-904be0bc6792','晚望江南','郭印','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','野豁長江外，人家各自村。',48,'全唐诗/poet.song.95000.json','["野豁長江外，人家各自村。", "水光秋蘸樹，雲色晚封門。", "引眺頻搔首，行吟只斷魂。", "可憐新月上，烟靄又昏昏。"]'),
('af3b3539-42f8-414c-8ca2-05b5264adcb7','再用前韻四首  其一','郭印','宋','宋诗','song-poetry','','[]','瀼界東西境，人分遠近村。',48,'全唐诗/poet.song.95000.json','["瀼界東西境，人分遠近村。", "關頭千古路，夾口百川門。", "風定江知性，雲開日返魂。", "客愁秋更劇，一望一神昏。"]'),
('492851b1-9b1a-4b62-b9cc-67c27b42adae','再用前韻四首  其二','郭印','宋','宋诗','song-poetry','','[]','殘日銜西嶺，輕烟幕晚村。',48,'全唐诗/poet.song.95000.json','["殘日銜西嶺，輕烟幕晚村。", "朝宗奔衆水，設險壯重門。", "恍惚襄王夢，淒涼蜀相魂。", "山川長不改，人意自朝昏。"]'),
('0a6867f1-9633-48fa-90b5-1ade38859de5','再用前韻四首  其三','郭印','宋','宋诗','song-poetry','','[]','身留瘴癘地，家住水雲村。',48,'全唐诗/poet.song.95000.json','["身留瘴癘地，家住水雲村。", "何事懷三徑，無才叩九門。", "秋風吹旅思，夜雨滴歸魂。", "目斷岷峨路，烟深夕照昏。"]'),
('09375610-8a12-4346-bbca-3cfa65ed3c87','再用前韻四首  其四','郭印','宋','宋诗','song-poetry','','[]','學道與時背，從人笑我村。',48,'全唐诗/poet.song.95000.json','["學道與時背，從人笑我村。", "太清元有路，大易豈無門。", "把定金公性，收還木女魂。", "屯蒙循兩卦，返照驗晨昏。"]'),
('b43c9a97-5230-4e9a-891a-a20038370e6d','楊村道中偶晴','郭印','宋','宋诗','song-poetry','','[]','童僕喧喧語，籃輿十里輕。',48,'全唐诗/poet.song.95000.json','["童僕喧喧語，籃輿十里輕。", "雨收沙路净，溪漲石灘平。", "疊嶂千峰秀，殘霞數道明。", "秋容誰可狀，一洗客心清。"]'),
('29e2aad6-8e65-4a0a-ad0d-abc67ae483f0','次韻南伯唐福道中','郭印','宋','宋诗','song-poetry','','[]','宿雨郊原潤，晨風草木涼。',48,'全唐诗/poet.song.95000.json','["宿雨郊原潤，晨風草木涼。", "村醪饒客醉，山鳥笑人忙。", "石罅泉能潔，籬根笋自香。", "箯輿終日倦，惆悵舊林塘。"]'),
('009a2034-c08b-4e37-bac9-6ead49f73490','留雲安驛詩','郭印','宋','宋诗','song-poetry','','[]','五日留山驛，塵無一點新。',48,'全唐诗/poet.song.95000.json','["五日留山驛，塵無一點新。", "瓜虀惟有醬，麴米不成春。", "默坐深調息，狂吟枉費神。", "箇中真趣在，略得自由身。"]'),
('268bd022-d829-4e81-ba32-4a971faf3d39','過銅梁縣有感爲住半日','郭印','宋','宋诗','song-poetry','','[]','攝職臨兹邑，于今五十年。',48,'全唐诗/poet.song.95000.json','["攝職臨兹邑，于今五十年。", "吏胥都往矣，井邑尚依然。", "指目身曾見，談論口但傳。", "人情猶可喜，能不爲留連。"]'),
('66aff5ea-b732-43e1-9214-afababc86c26','到巴川縣日熾不可行遂留宿用明復留題韻','郭印','宋','宋诗','song-poetry','','[]','避暑巴川館，憑欄瞰水濆。',48,'全唐诗/poet.song.95000.json','["避暑巴川館，憑欄瞰水濆。", "馬牛紛浴汗，鵝鴨亂翻紋。", "潦濁難爲鑑，天昏不辨雲。", "清泉何處是，一卓飯吾軍。"]'),
('4775be53-61a1-44f3-8ce4-ba5b52d55495','遂寧縣道中路平日熾','郭印','宋','宋诗','song-poetry','','[]','赤日射平地，青天卷片雲。',48,'全唐诗/poet.song.95000.json','["赤日射平地，青天卷片雲。", "汗流疑是浴，氣烈正如焚。", "食鼎荷湯鑊，輿衣蒙火裙。", "幸哉無內熱，不使躁爲君。"]'),
('165127af-ded5-4fe3-b107-12beb9f17570','未歸','郭印','宋','宋诗','song-poetry','','[]','宇縣干戈滿，何人不念歸。',48,'全唐诗/poet.song.95000.json','["宇縣干戈滿，何人不念歸。", "死生雖有命，進退合知幾。", "巖壑空摇頰，塵埃少拂衣。", "吾今同一轍，慚負故山薇。"]'),
('924a10ef-f101-46f2-ab79-291bc30d8dea','將歸','郭印','宋','宋诗','song-poetry','','[]','兩載春風客，翩翩憶舊棲。',48,'全唐诗/poet.song.95000.json','["兩載春風客，翩翩憶舊棲。", "林深喧鳥雀，水暖亂鳬鷖。", "到處宜傾榼，逢人數杖藜。", "荷花難負約，飛語報雲溪。"]'),
('f7519ced-24cd-4bd4-83c7-99c14411a468','離三節鎮日色正盛頃間雲起陽烏不見終日清涼','郭印','宋','宋诗','song-poetry','','[]','忽訝雲峰合，渾忘暑氣侵。',48,'全唐诗/poet.song.95000.json','["忽訝雲峰合，渾忘暑氣侵。", "垂天真有意，籠日豈無心。", "行旅人人悦，空山處處陰。", "更期頭上黑，相送到溪林。"]'),
('6adbc7db-de45-4173-a309-9fc245a6ffb7','舟中早起','郭印','宋','宋诗','song-poetry','','[]','迤邐東方白，猶餘數點星。',48,'全唐诗/poet.song.95000.json','["迤邐東方白，猶餘數點星。", "亂鴉啼古木，宿鷺起寒汀。", "日襯殘雲赤，烟含遠岫青。", "江山無限思，不覺是飄零。"]'),
('5697c81d-20e0-4c76-95e7-e2f345d3e3cb','舟中遇雨','郭印','宋','宋诗','song-poetry','','[]','小舟初别岸，一雨送斜風。',48,'全唐诗/poet.song.95000.json','["小舟初别岸，一雨送斜風。", "點點圓生暈，聲聲碎打篷。", "雲山交慘淡，烟樹遠冥濛。", "有客披蓑坐，憑誰作畫工。"]'),
('904da797-5d4e-4868-a2a4-f4cd8b9406a0','舟中雨霽','郭印','宋','宋诗','song-poetry','','[]','雨聲收淅瀝，霽色起曈曨。',48,'全唐诗/poet.song.95000.json','["雨聲收淅瀝，霽色起曈曨。", "山頂雲蒸白，江心日射紅。", "澄波還古岸，宿霧掃遥空。", "更喜前程快，扁舟得順風。"]'),
('75d40a6e-4035-401d-a853-47da290390f5','舟中見月','郭印','宋','宋诗','song-poetry','','[]','濮上今秋月，於人太有情。',48,'全唐诗/poet.song.95000.json','["濮上今秋月，於人太有情。", "銀盤隨水湧，素練截江横。", "岸濶天猶近，船虛夜自明。", "寒光連上下，萬里一心清。"]'),
('84d983d6-5e4c-496a-b4f7-a496bac74044','和榮安中月明夜行','郭印','宋','宋诗','song-poetry','','[]','驅車夜出城，佳月傍人明。',48,'全唐诗/poet.song.95000.json','["驅車夜出城，佳月傍人明。", "始向山頭見，還同水面行。", "問途幾一舍，投宿已三更。", "露濕衣裘冷，吾生笑自輕。"]'),
('078455f2-49e8-4038-a05f-48aee9b43dc1','過石門灘','郭印','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','長江風雨急，巨石虎狼蹲。',48,'全唐诗/poet.song.95000.json','["長江風雨急，巨石虎狼蹲。", "水自分三道，舟唯過一門。", "細觀真眩目，平下亦銷魂。", "忠信知堪仗，兒曹不用喧。"]'),
('92ee25db-5751-4b90-a73e-59e30f8cffb4','栗鼻峽遇風','郭印','宋','宋诗','song-poetry','','[]','平生知任運，一切聽天公。',48,'全唐诗/poet.song.95000.json','["平生知任運，一切聽天公。", "身世浮江木，功名水上風。", "聖人齊覺夢，俗士較窮通。", "眼底無窮事，飛花本自空。"]'),
('c9b8b1f6-d604-466d-b7c6-5b2459c1e26f','檥舟','郭印','宋','宋诗','song-poetry','','[]','裊裊垂楊岸，無人獨檥舟。',48,'全唐诗/poet.song.95000.json','["裊裊垂楊岸，無人獨檥舟。", "風波嘗險阻，身世任沉浮。", "邃徑中間接，寒溪左右流。", "冥心來宴坐，浩蕩得天遊。"]'),
('a1465a8c-e57f-4c6e-8183-b7f701ca347f','雲溪雜詠  其一','郭印','宋','宋诗','song-poetry','','[]','入門何所有，彌望祇林泉。',48,'全唐诗/poet.song.95000.json','["入門何所有，彌望祇林泉。", "塵垢人間世，雲霞洞裏天。", "閑亭藏復見，小徑絕仍連。", "勿說桃源地，幽深自一川。"]'),
('7d453694-c658-47c1-a16c-5d3c7f4ce493','雲溪雜詠  其二','郭印','宋','宋诗','song-poetry','','[]','俗客尋常少，珍禽自在啼。',48,'全唐诗/poet.song.95000.json','["俗客尋常少，珍禽自在啼。", "一溪如練浄，萬竹與雲齊。", "縱目心貪看，回頭路卻迷。", "清游殊未足，日下小橋西。"]'),
('03ee2edc-0d55-4fd8-9465-9b581321ffa4','雲溪雜詠  其三','郭印','宋','宋诗','song-poetry','','[]','好景發天祕，幽情得快哉。',48,'全唐诗/poet.song.95000.json','["好景發天祕，幽情得快哉。", "亭從江上見，路向竹間開。", "有客相將入，無人獨自來。", "芒鞋元凖擬，和雨踏蒼苔。"]'),
('59251128-ac28-4534-a62e-9933670cce7b','雲溪雜詠  其四','郭印','宋','宋诗','song-poetry','','[]','門前車馬跡，籬內水雲鄉。',48,'全唐诗/poet.song.95000.json','["門前車馬跡，籬內水雲鄉。", "分委江流駛，通幽徑路長。", "一池擎菡蓞，萬竹聳篬筤。", "誰謂蓬壺遠，紅塵官道傍。"]'),
('d5d8ccdb-df5c-47dd-a12a-b9a15859d157','雲溪雜詠  其五','郭印','宋','宋诗','song-poetry','','[]','林園無俗物，滿目是琅玕。',48,'全唐诗/poet.song.95000.json','["林園無俗物，滿目是琅玕。", "非霧晝常晦，不風夏亦寒。", "流塵終日背，歸鳥一枝安。", "但看青青節，肯隨黄葉殘。"]'),
('40903004-3f91-4180-8e45-cd54228bcbb7','雲溪雜詠  其六','郭印','宋','宋诗','song-poetry','','[]','竹色琅玕立，花光錦繡舒。',48,'全唐诗/poet.song.95000.json','["竹色琅玕立，花光錦繡舒。", "物情奚得喪，人意妄分疏。", "汙浄川同納，媸妍鑑本虛。", "和光聊復爾，看取未形初。"]'),
('99ca2a1b-5077-463a-bedd-59670fc25ee0','雲溪雜詠  其七','郭印','宋','宋诗','song-poetry','','[]','步屧尋幽勝，亭邊水竹饒。',48,'全唐诗/poet.song.95000.json','["步屧尋幽勝，亭邊水竹饒。", "地令人事遠，江遣客愁銷。", "自是塵難近，誰云隱可招。", "洞天無别景，於此日逍遥。"]'),
('85e5aa63-7a59-4513-904e-b204881617a5','雲溪雜詠  其八','郭印','宋','宋诗','song-poetry','','[]','小橋藏曲折，幽徑一溪分。',48,'全唐诗/poet.song.95000.json','["小橋藏曲折，幽徑一溪分。", "旭日篩金影，春流展縠文。", "周遭無限玉，參錯幾重雲。", "覿面融真意，相知祇此君。"]'),
('8cde3593-51d3-40de-92db-fbfb664b33bb','雲溪雜詠  其九','郭印','宋','宋诗','song-poetry','','[]','竹裏虹橋見，葱葱翠氣浮。',48,'全唐诗/poet.song.95000.json','["竹裏虹橋見，葱葱翠氣浮。", "枝交籠短岸，葉落赴寒流。", "索莫終年計，徘徊竟月留。", "清凉宜避熱，風色晚颼颼。"]'),
('94e87d32-7213-49c2-b045-e5db22ef0470','雲溪雜詠  其一○','郭印','宋','宋诗','song-poetry','','[]','一到平橋上，蕭然浄客心。',48,'全唐诗/poet.song.95000.json','["一到平橋上，蕭然浄客心。", "兩邊風細細，四面竹森森。", "更喜清流駛，寧容畏暑侵。", "我來歸不去，日永鎮長陰。"]'),
('c759175c-4bbf-4410-8177-90452ce9f69f','雲溪雜詠  其一一','郭印','宋','宋诗','song-poetry','','[]','虛舟横沼面，窗戶四玲瓏。',48,'全唐诗/poet.song.95000.json','["虛舟横沼面，窗戶四玲瓏。", "絳宇三山上，青天一鏡中。", "夜深楊柳月，日永芰荷風。", "公退渾無事，江湖興莫窮。"]'),
('2c417128-decb-4df8-bda5-37c818e9cdfc','雲溪雜詠  其一二','郭印','宋','宋诗','song-poetry','','[]','小閣供遐眺，凝眸萬景閑。',48,'全唐诗/poet.song.95000.json','["小閣供遐眺，凝眸萬景閑。", "江流連曠野，林杪出遥山。", "思遠憑欄外，吟成倚杖間。", "乾坤無盡藏，造物豈容慳。"]'),
('af466356-dbdc-41d3-b2d6-f4acdbcd609a','雲溪雜詠  其一三','郭印','宋','宋诗','song-poetry','','[]','道眼全無障，機心了不生。',48,'全唐诗/poet.song.95000.json','["道眼全無障，機心了不生。", "園亭如著意，物色豈留情。", "水鳥元相狎，淵魚自勿驚。", "超然忘我見，萬化各天成。"]'),
('496cecc8-43fb-405d-871f-7f29095b15a6','雲溪雜詠  其一四','郭印','宋','宋诗','song-poetry','','[]','寒潭深百尺，潛物晦其真。',48,'全唐诗/poet.song.95000.json','["寒潭深百尺，潛物晦其真。", "雨施時爲潤，淵居每自珍。", "飛騰應有道，變化豈無神。", "直待功成日，驅雲上紫宸。"]'),
('f832fe43-f23a-4f99-b07b-81d92c806026','雲溪雜詠  其一五','郭印','宋','宋诗','song-poetry','','[]','生植依山谷，移根伴此君。',48,'全唐诗/poet.song.95000.json','["生植依山谷，移根伴此君。", "叢中抽紫幹，幽處吐清芬。", "入室能俱化，同心自遠聞。", "靈均元不試，委佩楚江濆。"]'),
('153e26cd-1c89-4267-9ae5-dae838a1f36c','和韓道濟見示雲溪之什','郭印','宋','宋诗','song-poetry','','[]','水竹吾廬勝，幽遐不用尋。',48,'全唐诗/poet.song.95000.json','["水竹吾廬勝，幽遐不用尋。", "秋江分浩渺，夏日閟沉陰。", "野客敲門看，騷人倚杖吟。", "僉言清入骨，坐久髮毛森。"]'),
('3883ffac-bdf2-4ece-835b-bb38df3a3211','劉誼夫見寄雲溪之什用前韻  其一','郭印','宋','宋诗','song-poetry','','[]','閑情從杖屨，幽意滿林塘。',48,'全唐诗/poet.song.95000.json','["閑情從杖屨，幽意滿林塘。", "秋近氣先冷，春來風自香。", "芷蘭成佩玉，茅葦當雕梁。", "一念渾枯木，能隨柳絮狂。"]'),
('56f986a6-a1b2-41a8-8cce-a426a9648d34','劉誼夫見寄雲溪之什用前韻  其二','郭印','宋','宋诗','song-poetry','','[]','身墮樊籠裏，心遊浦溆邊。',48,'全唐诗/poet.song.95000.json','["身墮樊籠裏，心遊浦溆邊。", "晚風傳牧笛，落日漾漁船。", "山接無窮樹，江連不盡天。", "憑誰圖此景，髣髴似斜川。"]'),
('f6bba4af-36f0-45f8-9186-0120cc979251','歸雲溪三首  其一','郭印','宋','宋诗','song-poetry','','[]','才入雲溪境，欣然面故人。',48,'全唐诗/poet.song.95000.json','["才入雲溪境，欣然面故人。", "江郊寧改舊，竹樹更增新。", "泉石重爲伴，樵漁永作鄰。", "丁寧魚與鳥，久出幸無嗔。"]'),
('f53a1624-f1cb-4975-82ed-b43116cee840','歸雲溪三首  其二','郭印','宋','宋诗','song-poetry','','[]','林園三載别，相見不相猜。',48,'全唐诗/poet.song.95000.json','["林園三載别，相見不相猜。", "燕雀垂空下，龜魚近水來。", "但辜新笋約，猶及白蓮開。", "從此休官去，風光日共陪。"]'),
('783fdb9f-7752-470b-90f3-69b8c0b586ec','歸雲溪三首  其三','郭印','宋','宋诗','song-poetry','','[]','蜀道溪林勝，無如此地先。',48,'全唐诗/poet.song.95000.json','["蜀道溪林勝，無如此地先。", "兩溪光練練，萬竹翠涓涓。", "世謂齊盤谷，人言過輞川。", "吾生聊樂耳，何必問前賢。"]'),
('67a22c8a-8726-414d-aa4d-2a6d7650c598','題謝園二首  其一','郭印','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','邂逅成幽討，徘徊慰賞心。',48,'全唐诗/poet.song.95000.json','["邂逅成幽討，徘徊慰賞心。", "長江連遠色，喬木借清陰。", "亭暗蘿垂幄，林明竹散金。", "爛游須愛日，羲馭去駸駸。"]'),
('53a00232-26ef-4d98-8922-54c8a8162c74','題謝園二首  其二','郭印','宋','宋诗','song-poetry','','[]','林柯初脱葉，江國便知秋。',48,'全唐诗/poet.song.95000.json','["林柯初脱葉，江國便知秋。", "雁過如將信，鷗眠不避舟。", "一丘終未遂，五斗秪堪羞。", "不有樽中物，憑誰破客愁。"]'),
('42b1e2da-ba99-44f2-8939-398ade9cfa6a','和仲明舉幽居','郭印','宋','宋诗','song-poetry','','[]','薄遊心已倦，幽築興何長。',48,'全唐诗/poet.song.95000.json','["薄遊心已倦，幽築興何長。", "夜雨千畦菊，春風五畝桑。", "雞豚還自樂，人我亦相忘。", "黄卷皆吾友，何憂日面墻。"]'),
('18f74c67-e5bd-4d42-b784-fbb0e97c4bcd','歳寒堂','郭印','宋','宋诗','song-poetry','','[]','草木摧枯盡，窮冬獨後凋。',48,'全唐诗/poet.song.95000.json','["草木摧枯盡，窮冬獨後凋。", "堅姿工傲雪，直幹上凌霄。", "煙色蒙高蓋，風聲漲晚潮。", "只憐桃與李，一向媚春韶。"]'),
('95086fad-0dd7-4388-81b6-285bbce9c372','貴和堂','郭印','宋','宋诗','song-poetry','','[]','臨池高拓地，軒檻直前開。',48,'全唐诗/poet.song.95000.json','["臨池高拓地，軒檻直前開。", "樹影簾中入，荷香坐上來。", "吏閑休案牘，客好共樽罍。", "再稔民和樂，嘉名亦稱哉。"]'),
('78bb100e-ad56-4cec-999a-dfa32ff166c3','獨有堂','郭印','宋','宋诗','song-poetry','','[]','至道渾疑獨，頭頭豈或遺。',48,'全唐诗/poet.song.95000.json','["至道渾疑獨，頭頭豈或遺。", "塵中如默契，聖處自深知。", "一體珠同貫，多方路益歧。", "未能融物我，難與話希夷。"]'),
('fbdc9d77-e35a-4688-b54a-e4b0151f9718','題費氏清餘軒','郭印','宋','宋诗','song-poetry','','[]','聞說南軒下，澄然洗客心。',48,'全唐诗/poet.song.95000.json','["聞說南軒下，澄然洗客心。", "不風蘭自馥，非霧竹常陰。", "簷影閑雲過，櫺光淡月侵。", "興來誰與語，撫弄膝間琴。"]'),
('08009dc8-cf44-4769-b91d-811b417e9348','卭州西巖軒閣陋甚掄仲知府舍人侍殿撰公來游惜其頽敝乃更新之既成以書招印同游因成一章','郭印','宋','宋诗','song-poetry','','[]','鶴山争攬勝，此地獨超然。',48,'全唐诗/poet.song.95000.json','["鶴山争攬勝，此地獨超然。", "秀巘脩屏立，枯崖半屋懸。", "團雲饒翠竹，鳴玉落清泉。", "自得高人賞，佳名日益傳。"]'),
('b47d1154-ed11-4c2c-898a-899c81924e0b','酴醿閣','郭印','宋','宋诗','song-poetry','','[]','春風高閣上，雪片又能香。',48,'全唐诗/poet.song.95000.json','["春風高閣上，雪片又能香。", "琢玉全天質，施朱笑晚粧。", "梅花如許瘦，柳絮不勝狂。", "況此偏宜釀，逢人問酒方。"]'),
('2451c43b-d833-43cd-ae64-b9b68e9523a7','諸葛公則延登書閣出示焦丈通直洎諸公所贈詩因成四韻','郭印','宋','宋诗','song-poetry','','[]','落泊粗官冷，婆娑小閣深。',48,'全唐诗/poet.song.95000.json','["落泊粗官冷，婆娑小閣深。", "身勞常簿領，興在即山林。", "幽砌封苔暈，虛櫺過竹陰。", "眼前無限意，清賞得知心。"]'),
('b5dd897f-687e-4fd1-b987-1d8a5f552e38','野亭','郭印','宋','宋诗','song-poetry','','[]','一到幽亭上，蕭然浄客心。',48,'全唐诗/poet.song.95000.json','["一到幽亭上，蕭然浄客心。", "竹深風細細，柏古氣森森。", "畏日背斜照，珍禽共好音。", "未能還小隱，即此是山林。"]'),
('6d62c5a3-d7f9-428f-8a35-f815bda760cf','繞紅亭','郭印','宋','宋诗','song-poetry','','[]','燕脂新染出，剪刻費天工。',48,'全唐诗/poet.song.95000.json','["燕脂新染出，剪刻費天工。", "葉少何妨綠，枝繁不厭紅。", "綺霞當眼爛，風雨轉頭空。", "唯有亭前竹，青青四季同。"]'),
('843d15cc-7125-4f52-bc6e-5b260dc076bc','陪元允大受游天寧寺三首  其一','郭印','宋','宋诗','song-poetry','','[]','炎暑何從避，城隅古刹幽。',48,'全唐诗/poet.song.95000.json','["炎暑何從避，城隅古刹幽。", "故人今再會，勝地昔曾遊。", "雲合天容暝，風來客意秋。", "歸途催暮雨，回首不能休。"]'),
('a0ead117-7b75-456c-a816-7c0ac4fb4325','陪元允大受游天寧寺三首  其二','郭印','宋','宋诗','song-poetry','','[]','拉客遊蕭寺，徘徊及暮還。',48,'全唐诗/poet.song.95000.json','["拉客遊蕭寺，徘徊及暮還。", "自非歸沐假，那得片時閑。", "閲世真成夢，爲官祇強顔。", "老僧應笑我，何日遠塵寰。"]'),
('72125e71-c971-4744-aec2-4f6580b866e9','陪元允大受游天寧寺三首  其三','郭印','宋','宋诗','song-poetry','','[]','古人來會合，蕭寺喜粗連。',48,'全唐诗/poet.song.95000.json','["古人來會合，蕭寺喜粗連。", "久坐頻更僕，留言悉契禪。", "塔高延晚照，楠密易昏煙。", "欲去仍回首，西風爲慘然。"]'),
('bde4cff1-02c7-4891-aa4c-522259b7ddef','天寧晚集','郭印','宋','宋诗','song-poetry','','[]','僧寮便坐卧，觸目興何窮。',48,'全唐诗/poet.song.95000.json','["僧寮便坐卧，觸目興何窮。", "庭竹留斜日，瓶花怯晚風。", "分無依寶社，心已脱塵籠。", "回首人間世，枯榮一夢中。"]'),
('936672d5-cba7-4540-9312-07fb67fe7da2','遊金地寺  其一','郭印','宋','宋诗','song-poetry','','[]','山行無近遠，絕頂是休程。',48,'全唐诗/poet.song.95000.json','["山行無近遠，絕頂是休程。", "度石籃輿怯，穿雲履屐輕。", "林篁當路迸，泉水落溪鳴。", "更宿招提夜，寥然一境清。"]'),
('45673868-1382-4605-9cef-2dc89b9837a6','遊金地寺  其二','郭印','宋','宋诗','song-poetry','','[]','得得來幽寺，山靈爲洒塵。',48,'全唐诗/poet.song.95000.json','["得得來幽寺，山靈爲洒塵。", "談禪饒釋子，覓句讓詩人。", "好癖疑驚俗，機忘始見真。", "平生丘壑志，舍此更何親。"]'),
('2bfede53-fe9a-4ba2-a697-9356ca22662e','下巖寺','郭印','宋','宋诗','song-poetry','','[]','雲安欣及境，小刹爲徘徊。',48,'全唐诗/poet.song.95000.json','["雲安欣及境，小刹爲徘徊。", "殿閣隨巖展，軒窗向水開。", "僧雖持鉢出，客自艤舟回。", "欲住無留計，幽懷亦暢哉。"]'),
('642ebbca-dab6-45a9-a395-33586f83ec77','遊靈泉寺','郭印','宋','宋诗','song-poetry','','[]','人日訪山寺，春風能借温。',48,'全唐诗/poet.song.95000.json','["人日訪山寺，春風能借温。", "柳橋通一水，柏徑隱重門。", "泉竇來何處，梅花别有村。", "從容尋後約，假榻卧雲根。"]'),
('3419aee8-4749-4466-9d53-686b5961fad2','再和','郭印','宋','宋诗','song-poetry','','[]','四面林巒匝，風喧未覺温。',48,'全唐诗/poet.song.95000.json','["四面林巒匝，風喧未覺温。", "曉晴雲度嶺，夜静月侵門。", "地秀古今樹，人嬉遠近村。", "細觀群動性，各各自歸根。"]'),
('2f57bf59-e976-4cbb-a810-74b2b7315d09','宿大明寺','郭印','宋','宋诗','song-poetry','','[]','歷覽成終日，禪房處處深。',48,'全唐诗/poet.song.95000.json','["歷覽成終日，禪房處處深。", "野僧應怪見，俗客可幽尋。", "煙竹寒垂幄，風松静鼓琴。", "清談不知寐，明月到天心。"]'),
('1dfec7d8-19fe-4c42-9900-3f2fcc137c44','游涪州普浄院','郭印','宋','宋诗','song-poetry','','[]','城郭欹斜建，人家高下居。',48,'全唐诗/poet.song.95000.json','["城郭欹斜建，人家高下居。", "扁舟挨古岸，别棹過僧廬。", "祠識伊川像，堂標魯直書。", "惜哉横一水，游子亦來疏。"]'),
('6c02c5b4-e8af-4a5d-8fdf-cca955ca2a16','次韻明法游法相院二首  其一','郭印','宋','宋诗','song-poetry','','[]','市近清江隔，林深古寺幽。',48,'全唐诗/poet.song.95000.json','["市近清江隔，林深古寺幽。", "竹光濃欲滴，山色翠交浮。", "咫尺人稀到，尋常客共遊。", "機心吾已息，來往不驚鷗。"]'),
('2c6a5dd4-a11c-422b-9ed2-ced2a83d7af5','次韻明法游法相院二首  其二','郭印','宋','宋诗','song-poetry','','[]','禪扉塵不雜，景趣自然幽。',48,'全唐诗/poet.song.95000.json','["禪扉塵不雜，景趣自然幽。", "黛色排軒入，仙香繞殿浮。", "傍林滋野興，出郭契清游。", "歸路風埃起，眠沙愧白鷗。"]'),
('b4906145-b2f1-49c3-84e6-e90e2f64c73f','次韻蒲大受瀛游富仁院二首  其一','郭印','宋','宋诗','song-poetry','','[]','衲子幽棲地，青山繞四旁。',48,'全唐诗/poet.song.95000.json','["衲子幽棲地，青山繞四旁。", "林昏知暝靄，溪暖覺遲陽。", "泉石關心久，風光引興長。", "春雲多變態，天末淡微茫。"]'),
('383a1ddc-f219-4ca3-89d3-b6e7c97a7a4f','次韻蒲大受瀛游富仁院二首  其二','郭印','宋','宋诗','song-poetry','','[]','脱屣塵埃外，結廬猿鳥旁。',48,'全唐诗/poet.song.95000.json','["脱屣塵埃外，結廬猿鳥旁。", "松門深掩月，花塢静含陽。", "欹枕泉春急，焚香晝景長。", "我無林壑分，世路祇茫茫。"]'),
('37c3b01a-c102-43bb-872a-5ffba1d63f94','宿香蓋院','郭印','宋','宋诗','song-poetry','','[]','溪横門半掩，日暮客來過。',48,'全唐诗/poet.song.95000.json','["溪横門半掩，日暮客來過。", "翠竹庵前密，青山閣上多。", "景宜閑裏覓，詩向醉中哦。", "回首風塵滿，明朝事若何。"]'),
('4fbb4089-8b86-46ea-a85d-2d30a36864b5','過謙上人房','郭印','宋','宋诗','song-poetry','','[]','小房藏曲折，客至不譍門。',48,'全唐诗/poet.song.95000.json','["小房藏曲折，客至不譍門。", "種竹無多地，分蘭卻數盆。", "禪心初默契，道學更深論。", "世路悲流浪，因君一反源。"]'),
('079f2dd9-c2e9-47c1-8064-c43021fd2ebf','僧房午睡','郭印','宋','宋诗','song-poetry','','[]','客館饒秋思，僧房愜晝眠。',48,'全唐诗/poet.song.95000.json','["客館饒秋思，僧房愜晝眠。", "納涼仍古殿，濯熱更清泉。", "得失渾關命，行藏只聽緣。", "安能隨世態，膏火日相煎。"]'),
('c96b081d-7def-4a58-beec-939b9f79e9e8','游酆都觀二首  其一','郭印','宋','宋诗','song-poetry','','[]','兩漢神仙宅，千年道德鄉。',48,'全唐诗/poet.song.95000.json','["兩漢神仙宅，千年道德鄉。", "祥雲連野潤，巨柏亘天長。", "陳迹遺蕭爽，高風接混茫。", "凝情丹竈冷，無處問真方。"]'),
('22561d6a-52a3-440c-bd32-5e23119df508','游酆都觀二首  其二','郭印','宋','宋诗','song-poetry','','[]','仙籍平都化，今晨喜一過。',48,'全唐诗/poet.song.95000.json','["仙籍平都化，今晨喜一過。", "彩雲空洞穴，古木上藤蘿。", "龍勢山盤轉，禽聲日咏歌。", "我來思際遇，亭下久婆娑。"]'),
('9600b41e-04c8-4fad-b204-a19b260d0e32','游思安鳳凰巖','郭印','宋','宋诗','song-poetry','','[]','山腳清江轉，巖腰細路通。',48,'全唐诗/poet.song.95000.json','["山腳清江轉，巖腰細路通。", "飛泉忽濺雨，陰壑自吟風。", "寺隱烟雲裏，人行竹柏中。", "野僧無箇在，幽鳥爲談空。"]'),
('e12f8cf0-117b-4a0b-97de-cdbec3f2214d','合州濮巖','郭印','宋','宋诗','song-poetry','','[]','背郭二三里，林巒迥出群。',48,'全唐诗/poet.song.95000.json','["背郭二三里，林巒迥出群。", "千巖蹲古佛，萬木駐寒雲。", "樓閣侵天際，烟霞謝世紛。", "登臨不忍去，回首日西曛。"]'),
('b289cd02-7410-4d06-9f3f-e7df1a275197','題岑公洞','郭印','宋','宋诗','song-poetry','','[]','岑公來避世，甲子十周年。',48,'全唐诗/poet.song.95000.json','["岑公來避世，甲子十周年。", "夏屋虛巖豁，神芝結乳懸。", "木喬從昔種，香信至今傳。", "學道能堅忍，何人不得仙。"]'),
('ab81d746-29e9-4f20-b0da-8786d6e934c6','采真洞','郭印','宋','宋诗','song-poetry','','[]','竹洞深深處，斯游契采真。',48,'全唐诗/poet.song.95000.json','["竹洞深深處，斯游契采真。", "故來非俗客，同道是幽人。", "日暗能休影，風清不受塵。", "行行無限意，滿目漲脩筠。"]'),
('4048d1e1-5fce-4241-943e-f324b905dbfd','和張方回西湖二首  其一','郭印','宋','宋诗','song-poetry','','["\u897f\u6e56"]','房公巧栽植，花發四時春。',48,'全唐诗/poet.song.95000.json','["房公巧栽植，花發四時春。", "有竹能環水，無風不動蘋。", "人亡留粉像，客至謝紅塵。", "梅柳年年色，相看白髪新。"]'),
('c9708647-cc97-492f-87ea-6af7fffc284a','和張方回西湖二首  其二','郭印','宋','宋诗','song-poetry','','["\u897f\u6e56"]','叢篁深翳景，草木未知春。',48,'全唐诗/poet.song.95000.json','["叢篁深翳景，草木未知春。", "晴漏林間日，寒生水上蘋。", "縈紆通邃徑，寂歷遠囂塵。", "更渡長橋去，無邉物色新。"]'),
('a1ef12fd-4921-4c01-87fb-9cb7a99fe191','和何子應遊金璧池二首  其一','郭印','宋','宋诗','song-poetry','','[]','才華思哲匠，魂夢繞幽塘。',48,'全唐诗/poet.song.95000.json','["才華思哲匠，魂夢繞幽塘。", "舊館隨人勝，新荷特地香。", "煙深喧脆管，水浄蘸浮梁。", "安得雙飛翼，尊前一醉狂。"]'),
('93115086-1b5a-4813-9bdf-1cc4df2e17e2','和何子應遊金璧池二首  其二','郭印','宋','宋诗','song-poetry','','[]','徜徉清水曲，盼戀綠楊邊。',48,'全唐诗/poet.song.95000.json','["徜徉清水曲，盼戀綠楊邊。", "欲並師商席，同登傅說船。", "萬荷齊舞扇，一葦獨行天。", "滿目江湖趣，無勞涉大川。"]'),
('66aaeb99-2401-4484-8ccd-80d4e123b335','和元汝功登城有感','郭印','宋','宋诗','song-poetry','','[]','荒城緣蔓草，峭壁累鹹鹺。',48,'全唐诗/poet.song.95000.json','["荒城緣蔓草，峭壁累鹹鹺。", "山木秋尤少，江雲晚更多。", "寺烏千點集，塞雁一聲過。", "錦水歸心切，漁衣負綠蓑。"]'),
('18b62f61-8c38-4884-9a79-e14485f4ab9e','城上','郭印','宋','宋诗','song-poetry','','[]','晚目層城上，山川自吐吞。',48,'全唐诗/poet.song.95000.json','["晚目層城上，山川自吐吞。", "斷雲孤嶺秀，漲潦一溪渾。", "煙起誰家樹，人歸何處村。", "不堪東北望，回首又黄昏。"]'),
('ed65b870-43dd-4a71-8b9f-ddaa6e47dc49','登咒土寺東臺','郭印','宋','宋诗','song-poetry','','[]','尋幽通野寺，訪古得危亭。',48,'全唐诗/poet.song.95000.json','["尋幽通野寺，訪古得危亭。", "木偃千年蓋，山圍一面屏。", "登臨徐發興，蕭散偶忘形。", "倚郭繁華地，斯游喜屢經。"]'),
('ddc8148c-cfad-44eb-833b-2e2e807cd1c6','書臺','郭印','宋','宋诗','song-poetry','','[]','崛起扶劉氏，兼資將相才。',48,'全唐诗/poet.song.95000.json','["崛起扶劉氏，兼資將相才。", "臣心雖自切，天命若爲猜。", "古壁空遺像，荒榛只舊臺。", "斯人今不見，落日更徘徊。"]'),
('79633c72-3fff-4a6d-af6e-ef239e9d7b1d','西臺','郭印','宋','宋诗','song-poetry','','[]','高臺垂四顧，遺冢閲千年。',48,'全唐诗/poet.song.95000.json','["高臺垂四顧，遺冢閲千年。", "烟樹孤城外，雲山落照邊。", "崢嶸餘巨石，慘淡接平川。", "往事誰能說，憑欄一悵然。"]'),
('d2c5655d-5bdc-469c-a77a-62e8d7c820a1','凌虛臺','郭印','宋','宋诗','song-poetry','','[]','高臺收晚照，遠思浩無窮。',48,'全唐诗/poet.song.95000.json','["高臺收晚照，遠思浩無窮。", "竹裏清飈泛，山高翠靄蒙。", "九層平可上，一徑曲能通。", "誰揭凌虛字，名浮亦未公。"]'),
('d1ca3e4a-5608-44a5-9602-fe2990d0188d','御風橋','郭印','宋','宋诗','song-poetry','','[]','此地多虛曠，飄然欲御風。',48,'全唐诗/poet.song.95000.json','["此地多虛曠，飄然欲御風。", "雙鳬疑到闕，一鳥似翔空。", "本是仙家事，元非幻術功。", "金丹成就日，白晝自飛沖。"]'),
('0fccbb42-3962-4e26-8154-fef0807f3b75','衆香橋','郭印','宋','宋诗','song-poetry','','[]','標名何所謂，物色正相當。',48,'全唐诗/poet.song.95000.json','["標名何所謂，物色正相當。", "堆雪酴醿潔，披風菡蓞香。", "菊從秋後發，梅向臘前芳。", "眼界無多地，縱横亘十方。"]'),
('474541be-c47d-46d6-8454-f190f10b5aab','無盡橋','郭印','宋','宋诗','song-poetry','','[]','曳杖徜徉去，仙家洞府中。',48,'全唐诗/poet.song.95000.json','["曳杖徜徉去，仙家洞府中。", "寒流清自繞，幽徑密相通。", "著處亭皆穩，看來景不同。", "是名無盡藏，具眼悉和融。"]'),
('0116150d-59fd-4828-862d-075191e63d2a','張持道生辰三首  其一','郭印','宋','宋诗','song-poetry','','[]','妙喜生摩詰，長庚夢謫仙。',48,'全唐诗/poet.song.95000.json','["妙喜生摩詰，長庚夢謫仙。", "寶階三道降，涼月九分圓。", "黑髪功名地，紅塵世俗緣。", "乾坤思整頓，休慕竹林賢。"]'),
('ad26021e-331d-40b7-9527-8c828295bfac','張持道生辰三首  其二','郭印','宋','宋诗','song-poetry','','[]','幾下陳蕃榻，常窺孔氏墻。',48,'全唐诗/poet.song.95000.json','["幾下陳蕃榻，常窺孔氏墻。", "玄通融釋老，廓落傲羲皇。", "永祝千齡壽，從今一瓣香。", "玉枝長不汗，莫問鬢邉霜。"]'),
('f1606736-e985-4bc8-ad1f-f3db57d84764','張持道生辰三首  其三','郭印','宋','宋诗','song-poetry','','[]','咫尺桃源路，乘閑許杖藤。',48,'全唐诗/poet.song.95000.json','["咫尺桃源路，乘閑許杖藤。", "高談六十刼，闇室百千燈。", "邀月公揮手，眠雲我曲肱。", "洞門初不鎖，俗客豈容登。"]'),
('d2861f31-f3d8-47bd-a3f4-5a486bddf76d','輓故楊叔強承事詞','郭印','宋','宋诗','song-poetry','','[]','家事毋關我，心君日日休。',48,'全唐诗/poet.song.95000.json','["家事毋關我，心君日日休。", "陰功歸子息，賢德視交游。", "彛鼎千年古，圖書一室幽。", "榮封胡不早，只許到郊丘。"]'),
('34761f4d-6c2d-4c0e-a591-b9d454e96cd7','故于泰和輓詞','郭印','宋','宋诗','song-poetry','','[]','藝圃收名早，如何亟賦歸。',48,'全唐诗/poet.song.95000.json','["藝圃收名早，如何亟賦歸。", "肩摩青佩久，心念白雲飛。", "屋有詩書潤，家因孝友肥。", "二雛行展翮，休復憤儒衣。"]'),
('13872a0f-1e38-4cee-bf54-87aba5e23362','夫人輓詞二首  其一','郭印','宋','宋诗','song-poetry','','[]','孌彼閨房秀，泠然玉雪容。',48,'全唐诗/poet.song.95000.json','["孌彼閨房秀，泠然玉雪容。", "月簫難擇對，石窌侈疏封。", "涵泳詩書習，扶持扇枕供。", "三荆方擢秀，雲壑卧雙松。"]'),
('93ef0006-6f57-49da-97bb-c0becac0dbb4','夫人輓詞二首  其二','郭印','宋','宋诗','song-poetry','','[]','熊軾人將達，魚軒樂未央。',48,'全唐诗/poet.song.95000.json','["熊軾人將達，魚軒樂未央。", "遽令雙劍化，併作一丘藏。", "筆絕先秋句，衣緘故篋香。", "未應林下女，千古擅清芳。"]'),
('12ef7aea-0b0f-4bec-b60f-f199bede4847','明復作文房四物詩因用其韻  其一','郭印','宋','宋诗','song-poetry','','[]','鋭精文字裏，今古歎毛錐。',48,'全唐诗/poet.song.95000.json','["鋭精文字裏，今古歎毛錐。", "職在中書貴，功因大手奇。", "楮君頻借重，墨客最相知。", "絕迹頭童日，麟經萬世師。"]'),
('b50a602c-ad5c-4959-a2d0-ce42cc4398ec','明復作文房四物詩因用其韻  其二','郭印','宋','宋诗','song-poetry','','[]','琢就陰崖骨，良工用意勤。',48,'全唐诗/poet.song.95000.json','["琢就陰崖骨，良工用意勤。", "沼心初受水，鏡面已生雲。", "自比珪璋質，能成翰墨勳。", "千金酬重價，端石世傳聞。"]'),
('6609aa79-f69f-49e5-89d0-644b497d9764','明復作文房四物詩因用其韻  其三','郭印','宋','宋诗','song-poetry','','[]','結繩嗟已遠，書尺濟斯民。',48,'全唐诗/poet.song.95000.json','["結繩嗟已遠，書尺濟斯民。", "汗竹功猶淺，香皮世益珍。", "廉方能潔己，舒卷解隨人。", "一自逢毛穎，交情日日親。"]'),
('a3148fb2-53f3-43f9-b269-d358b28fe0fc','明復作文房四物詩因用其韻  其四','郭印','宋','宋诗','song-poetry','','[]','筆陣須鍪甲，輕煙久祕藏。',48,'全唐诗/poet.song.95000.json','["筆陣須鍪甲，輕煙久祕藏。", "犀文誇妙手，魚腹驗真方。", "製就玄圭象，磨成點漆光。", "東齊吾注易，誰遺一丸香。"]'),
('1daf44e4-3194-48df-8842-881ddc3334fb','竹杖','郭印','宋','宋诗','song-poetry','','[]','長短身爲度，洪纖節自明。',48,'全唐诗/poet.song.95000.json','["長短身爲度，洪纖節自明。", "時時勤執捉，處處伴經行。", "峻岅腰能直，危橋步亦輕。", "化龍他日事，靈壽若爲榮。"]'),
('36714351-7bf0-474b-8ba0-6c7336b3dfef','竹夫人','郭印','宋','宋诗','song-poetry','','[]','林下風流在，收歸枕簟傍。',48,'全唐诗/poet.song.95000.json','["林下風流在，收歸枕簟傍。", "冰肌元本浄，玉骨自然凉。", "最是虛心好，由來正節剛。", "炎天長作伴，書夜不能忘。"]'),
('a4feb79c-20a2-484f-9bf8-56e94d36b39a','藤枕','郭印','宋','宋诗','song-poetry','','[]','剡藤新織就，一榻共清涼。',48,'全唐诗/poet.song.95000.json','["剡藤新織就，一榻共清涼。", "琥珀珍難得，龍頭貴莫當。", "不辭拳石冷，寧羨錦囊香。", "夢覺華胥樂，神怡四體康。"]'),
('efae82da-ff39-435a-984d-b31b4252fc28','蘆簟','郭印','宋','宋诗','song-poetry','','[]','炎方需此物，收蓄遍家家。',48,'全唐诗/poet.song.95000.json','["炎方需此物，收蓄遍家家。", "致用同桃竹，勞工笑象牙。", "雖無花色麗，卻見水紋斜。", "展卧南窗下，蕭然興莫加。"]'),
('1c5911aa-fc16-4894-8853-df246e9c20d5','棕拂','郭印','宋','宋诗','song-poetry','','[]','一色棕櫚造，收成掌握中。',48,'全唐诗/poet.song.95000.json','["一色棕櫚造，收成掌握中。", "青蠅應退舍，白鳥敢爭雄。", "便作龜毛用，寧殊麈尾功。", "世情分美醜，達者自圓通。"]'),
('c3ef667e-d7f0-463d-a717-9c8aca472f89','紙扇','郭印','宋','宋诗','song-poetry','','[]','裁成方絮後，涼意便相親。',48,'全唐诗/poet.song.95000.json','["裁成方絮後，涼意便相親。", "烈日工遮影，飛塵少汙人。", "襟披殊覺快，掌運莫辭頻。", "紈綺徒觀美，論功曷比倫。"]'),
('5aaf3389-e4d8-410d-8bcb-b0c7cc2c28be','見墻間竹影擬而畫之終不近也','郭印','宋','宋诗','song-poetry','','[]','東墻纔過午，寫此此君真。',48,'全唐诗/poet.song.95000.json','["東墻纔過午，寫此此君真。", "日翳倐無跡，雲開俄有神。", "因緣咸自爾，形似竟誰親。", "筆墨有非僞，天公恐笑人。"]'),
('4338cb90-1124-4aef-bb1d-b2f7b5b2afb3','孤雁','郭印','宋','宋诗','song-poetry','','[]','誤逐衡陽暖，輕逃塞北寒。',48,'全唐诗/poet.song.95000.json','["誤逐衡陽暖，輕逃塞北寒。", "偶分千里伴，翻羨一枝安。", "兄弟今何許，家鄉路若干。", "飄零歸未得，淺渚戢脩翰。"]'),
('679726b5-aa9d-4774-935c-187c95af82b8','蟋蟀','郭印','宋','宋诗','song-poetry','','[]','秋蟲推爾傑，風韻太粗生。',48,'全唐诗/poet.song.95000.json','["秋蟲推爾傑，風韻太粗生。", "衰草年年恨，寒砧夜夜聲。", "軸閑催婦織，衣薄念夫征。", "誰謂心如石，欹眠不掛情。"]'),
('355245e5-38d0-4244-9edd-c163ef9140ca','山茶','郭印','宋','宋诗','song-poetry','','[]','嚴冬能獨秀，渾不藉春風。',48,'全唐诗/poet.song.95000.json','["嚴冬能獨秀，渾不藉春風。", "葉自經霜碧，花應鬭日紅。", "望中幾眩眼，高處欲燔空。", "安得栽培手，移根向邑中。"]'),
('16182839-54ea-485f-b650-db181c7df3e2','上政府五首  其一','郭印','宋','宋诗','song-poetry','','[]','王室當年若綴旒，片言戡定出奇謀。',64,'全唐诗/poet.song.95000.json','["王室當年若綴旒，片言戡定出奇謀。", "臨機勇決千鈞弩，濟險優游萬斛舟。", "掌上回旋皆造化，毫端升黜是春秋。", "蟲魚盡喜乾坤泰，宇縣寧聞杞國憂。"]'),
('4e67e10e-e8d6-48b9-b493-17c48dd1768f','上政府五首  其二','郭印','宋','宋诗','song-poetry','','[]','塞上煙塵永不揚，邊民戍卒盡耕桑。',64,'全唐诗/poet.song.95000.json','["塞上煙塵永不揚，邊民戍卒盡耕桑。", "抗言用武真非策，唾手扶危别有方。", "須信精誠能感格，由來道德本安強。", "恩沾動植知多少，天使千秋保熾昌。"]'),
('d9abfc53-35c0-497a-95c9-c9e3c86e4f32','上政府五首  其三','郭印','宋','宋诗','song-poetry','','[]','政和乙未對彤庭，袖筆曾陪四海英。',64,'全唐诗/poet.song.95000.json','["政和乙未對彤庭，袖筆曾陪四海英。", "三十七年渾夢境，六千餘里邈神京。", "大鈞播物無垠際，小錄搜才有姓名。", "屈指西南存者幾，成都首縣一孤生。"]'),
('2f82e9bf-2fc1-4d06-bf26-7ba0aa309bc6','上政府五首  其四','郭印','宋','宋诗','song-poetry','','[]','三紀徒勞祇療饑，年踰耳順已知非。',64,'全唐诗/poet.song.95000.json','["三紀徒勞祇療饑，年踰耳順已知非。", "行藏有定隨緣過，功業無成與願違。", "里閈儻能乘駟入，君門便欲掛冠歸。", "交朋親戚猶相慶，要看桑榆晚日暉。"]'),
('5b7ac222-2133-41ca-bf98-ccbfa6a9f0d9','上政府五首  其五','郭印','宋','宋诗','song-poetry','','[]','起家白屋忝爲郎，俯視同儕道亦光。',64,'全唐诗/poet.song.95000.json','["起家白屋忝爲郎，俯視同儕道亦光。", "已幸十年紆赤紱，猶期一日坐黄堂。", "紛紛奔競真成笑，兀兀憃愚但守常。", "不是坤輿能厚載，敢干斧鑕獻猖狂。"]'),
('5ed70baa-b54f-483f-9767-832dc2ced5d4','上曾安撫二首  其一','郭印','宋','宋诗','song-poetry','','[]','萬口爭稱好使君，攜持踴躍看朱輪。',64,'全唐诗/poet.song.95000.json','["萬口爭稱好使君，攜持踴躍看朱輪。", "入門便灑隨車雨，到處真成有腳春。", "魚鳥一時生意氣，江山千里有精神。", "大賢易鎮朝廷重，巴峽窮愁要撫循。"]'),
('36d8d503-14fe-4b2e-a700-e432c3c2ed1c','上曾安撫二首  其二','郭印','宋','宋诗','song-poetry','','[]','聖門鼓瑟妙難窺，今日風流親見之。',64,'全唐诗/poet.song.95000.json','["聖門鼓瑟妙難窺，今日風流親見之。", "五紀光陰驚電掣，一生忠孝仗天知。", "老莊座下須聞道，李杜壇邊敢說詩。", "晚景功名非所慕，摳衣深喜得宗師。"]'),
('095bfd18-68a8-43ce-938a-e6c5b97fe633','寄何修撰','郭印','宋','宋诗','song-poetry','','[]','向來祇欲返荆扉，老大趨時意頗微。',64,'全唐诗/poet.song.95000.json','["向來祇欲返荆扉，老大趨時意頗微。", "官路波濤猶洶洶，家山桃李自依依。", "刳心擬出陰陽表，委質難逃造化機。", "寄語當年蓑笠友，樵漁素約敢相違。"]'),
('b93bc88e-acba-40e9-a2bd-3ceb5167e19d','上鄭漕二首  其一','郭印','宋','宋诗','song-poetry','','[]','窮經好客舊時聲，千載遺風見典型。',64,'全唐诗/poet.song.95000.json','["窮經好客舊時聲，千載遺風見典型。", "忠孝家傳心自赤，功名路穩鬢方青。", "傅巖欲作商霖雨，蜀道猶觀漢使星。", "小益提封重試可，定膺鋒召入堯庭。"]'),
('b47076c8-e39e-4522-b3db-784e7e606ad0','上鄭漕二首  其二','郭印','宋','宋诗','song-poetry','','[]','孤迹平生似轉蓬，少而豪邁老羈窮。',64,'全唐诗/poet.song.95000.json','["孤迹平生似轉蓬，少而豪邁老羈窮。", "榮華路上黄粱夢，英俊叢中白髪翁。", "身墮窮山三峽裏，心隨流水大江東。", "夤緣展翅斜陽晚，須仗扶搖一鶚風。"]'),
('3ac50475-1b00-4dff-993e-00d98925256d','送張道從上行起復帥夔二首  其一','郭印','宋','宋诗','song-poetry','','[]','初辭丘隴重哀榮，斾卷春風第一程。',64,'全唐诗/poet.song.95000.json','["初辭丘隴重哀榮，斾卷春風第一程。", "帝委才猷專外閫，人推勇略過長城。", "孤忠炯炯能移孝，温詔諄諄遽奪情。", "三峽壺漿應滿道，江山草木舊知名。"]'),
('f0a72d2f-f7b6-4685-b137-7f7e2a1d6719','送張道從上行起復帥夔二首  其二','郭印','宋','宋诗','song-poetry','','[]','白帝層城統十連，肘聯荆屬阻山川。',64,'全唐诗/poet.song.95000.json','["白帝層城統十連，肘聯荆屬阻山川。", "翠華久睠舟車會，紫詔先收柱石賢。", "雪凈已通梁閣道，浪平空艤漢樓船。", "不妨腰絰登廊廟，典故先朝尚宛然。"]'),
('68a1e170-991e-4e93-af4c-598ca94f42b2','送鄭宣撫三首  其一','郭印','宋','宋诗','song-poetry','','[]','棹發嘉陵即帝庭，山川草木若爲情。',64,'全唐诗/poet.song.95000.json','["棹發嘉陵即帝庭，山川草木若爲情。", "忠嘉但有三千牘，威愛猶傳十萬兵。", "天象共符虛右席，坤維一带失長城。", "西南所繫安危大，何止雪山分重輕。"]'),
('9b6cbb69-75b5-415a-85f4-dd5e42b6251e','送鄭宣撫三首  其二','郭印','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','凛凛風霜鎮玉關，文經武略自優閑。',64,'全唐诗/poet.song.95000.json','["凛凛風霜鎮玉關，文經武略自優閑。", "蟠胸浩氣吞雲夢，蓋世英名重泰山。", "憂國屢形詩句裏，折衝長在笑談間。", "四川父老攀依切，猶問牙檣幾日還。"]'),
('b241b261-cfcc-426a-ae70-722a3dd834bb','送鄭宣撫三首  其三','郭印','宋','宋诗','song-poetry','','[]','朝路年來似奕棋，惟公出入倍光輝。',64,'全唐诗/poet.song.95000.json','["朝路年來似奕棋，惟公出入倍光輝。", "昔時裴度臨軒遣，今日曹參促詔歸。", "蜀棧雲横星騎動，楚江天闊錦帆飛。", "祇應太史朝朝奏，迤邐台星近紫微。"]'),
('8ee81f82-9d43-4460-b79e-fcb7cabc9174','送戴子厚赴張夔州之辟','郭印','宋','宋诗','song-poetry','','[]','半世婆娑厭宦途，時危結綬計何迂。',64,'全唐诗/poet.song.95000.json','["半世婆娑厭宦途，時危結綬計何迂。", "非干避地遊巫峽，且欲從軍捍蜀都。", "巴水秋深添别恨，金陵天近試雄圗。", "平心勿管風濤惡，陰有神明巨力扶。"]'),
('47521be0-a3b2-4635-9885-fff1c001da36','送邵公濟溥赴省二首  其一','郭印','宋','宋诗','song-poetry','','[]','天府登賢策馬東，似君人物許誰同。',64,'全唐诗/poet.song.95000.json','["天府登賢策馬東，似君人物許誰同。", "文章小技出兒戱，道德微言餘祖風。", "有路青霄元自别，無情白髪向來公。", "平生醖藉唯經國，唾手先收第一功。"]'),
('d6894411-5652-40a0-86a1-20666f451f4c','送邵公濟溥赴省二首  其二','郭印','宋','宋诗','song-poetry','','[]','凛凛霜威撲撲塵，不堪曉騎送行人。',64,'全唐诗/poet.song.95000.json','["凛凛霜威撲撲塵，不堪曉騎送行人。", "雲山萬點遠連蜀，煙樹兩行初過秦。", "風厚正能扶大翼，浪高端足化脩鱗。", "聖君急士思調鼎，喜見寒梅漏洩春。"]'),
('7c5d7589-d54c-4e4f-a848-f704cfdcdd86','次韻喻存道二首  其一','郭印','宋','宋诗','song-poetry','','[]','訪道尋師積有年，晚逢夫子嘆高堅。',64,'全唐诗/poet.song.95000.json','["訪道尋師積有年，晚逢夫子嘆高堅。", "玄關啟處功深矣，妙指傳來意豁然。", "氣會三宫馳聖轂，理歸一轍棄塵編。", "工夫到後神明出，奪得天機運用權。"]'),
('09d73b08-8f00-47ce-bb0c-f3796159a0de','次韻喻存道二首  其二','郭印','宋','宋诗','song-poetry','','[]','神龍一去渺無蹤，落日孤雲爲慘容。',64,'全唐诗/poet.song.95000.json','["神龍一去渺無蹤，落日孤雲爲慘容。", "溪遶練光秋更白，黛横山色晚尤濃。", "細看風物曾經眼，深達根源自點胸。", "寄宿僧寮清不寐，一輪明月掛枯松。"]'),
('b48941a4-ce8c-4742-b04c-1bd2bc5b35f1','次元汝功韻贈王恭之','郭印','宋','宋诗','song-poetry','','[]','四海車書未混同，憂懷都付酒盃中。',64,'全唐诗/poet.song.95000.json','["四海車書未混同，憂懷都付酒盃中。", "雲雷自昔開屯難，天地于今合泰通。", "濁酒寒燈招舊友，清江小艇憶詩翁。", "人生會面真難得，莫遣行裝犯曉風。"]'),
('5508537e-f762-4a9a-9be8-5dac2d68b513','次宋正紀韻','郭印','宋','宋诗','song-poetry','','[]','釋耒隨人干斗祿，因循五閲閏餘年。',64,'全唐诗/poet.song.95000.json','["釋耒隨人干斗祿，因循五閲閏餘年。", "折腰每效官三品，餬口深慚食萬錢。", "未夢登天生羽八，肯希舐痔得車千。", "求田早決歸耕計，種秫何妨釀酒泉。"]'),
('7670deeb-c4c4-46bf-ab0f-bc387521d7d5','次韻正紀見寄','郭印','宋','宋诗','song-poetry','','[]','栖栖奔走不知春，日月無停疾轉輪。',64,'全唐诗/poet.song.95000.json','["栖栖奔走不知春，日月無停疾轉輪。", "塵土強顔成俗吏，林泉放意屬高人。", "書題繾綣情何切，詩律雄遒語不陳。", "引起歸心千萬緒，向來夢寐幾翻新。"]'),
('59161336-e691-48e7-94c8-df9fff49bf3b','次韻正紀見貽之什','郭印','宋','宋诗','song-poetry','','[]','解紱歸來旋葺居，身安環堵不求餘。',64,'全唐诗/poet.song.95000.json','["解紱歸來旋葺居，身安環堵不求餘。", "粗羹糲飯偏知味，談話寒燈勝讀書。", "情竇欲開先自窒，心田已浄弗須鋤。", "親朋有酒且呼喚，萬事何妨一破除。"]'),
('3774d020-5700-447a-af89-5e1bc6ca6d1f','次韻嵩師彦正留别','郭印','宋','宋诗','song-poetry','','[]','兩公清氣入人肝，玉樹森森逼我寒。',64,'全唐诗/poet.song.95000.json','["兩公清氣入人肝，玉樹森森逼我寒。", "揮麈繽紛驚落屑，和詩來往疾跳丸。", "興餘不管牙籤亂，坐久翻憂蠟炬殘。", "輕别莫言吾所諱，重逢應作老翁看。"]'),
('726a4990-04be-4795-98ab-c59b9393079b','次韻余時升見招','郭印','宋','宋诗','song-poetry','','[]','老大逢春意轉微，追隨不復似當時。',64,'全唐诗/poet.song.95000.json','["老大逢春意轉微，追隨不復似當時。", "憐君舊已開三徑，顧我今方卜一枝。", "近水遥山元自好，暖風遲日更相宜。", "便當乘興尋花去，免使園林恨失期。"]'),
('ae294676-fc34-4bcc-93d2-25b93effd993','和趙茂州即事六首  其一','郭印','宋','宋诗','song-poetry','','[]','千巖萬壑最幽深，玉壘西邉古茂林。',64,'全唐诗/poet.song.95000.json','["千巖萬壑最幽深，玉壘西邉古茂林。", "仕宦不妨真大隱，風流無伴只孤斟。", "多情竹色朝侵几，適意松聲夜入琴。", "莫道使君無一事，每勞幽思發清吟。"]'),
('ed180f46-c79f-4d67-b42c-e589029d8f63','和趙茂州即事六首  其二','郭印','宋','宋诗','song-poetry','','[]','邉城贏得自由身，富有江山豈是貧。',64,'全唐诗/poet.song.95000.json','["邉城贏得自由身，富有江山豈是貧。", "水榭晴雲來几席，月庭香霧濕衣巾。", "已邀松竹爲三友，更列圖書作四鄰。", "不會世間機巧事，無思無慮樂天真。"]'),
('05d095ab-c545-47d5-9f0a-a63bc0706b2a','和趙茂州即事六首  其三','郭印','宋','宋诗','song-poetry','','[]','人事都無喜宴安，懶於喧處競追攀。',64,'全唐诗/poet.song.95000.json','["人事都無喜宴安，懶於喧處競追攀。", "驚殘午夢風推戶，壓盡炎威雪滿山。", "無主巖花時解笑，近人林鳥亦知還。", "應憐朝市區區者，方寸何曾頃刻閑。"]'),
('d8b4c631-69cd-4aa7-b912-b1b784c4baaf','和趙茂州即事六首  其四','郭印','宋','宋诗','song-poetry','','[]','官居閴寂似僧居，坐卧行藏得自如。',64,'全唐诗/poet.song.95000.json','["官居閴寂似僧居，坐卧行藏得自如。", "爽氣逼人千畝竹，清風滿室一床書。", "心游淡泊能調馬，意絕貪求豈羨魚。", "即此便同三徑隱，未須投紱賦歸歟。"]'),
('d752cbb3-aff0-4cc3-9741-5a887215e08b','和趙茂州即事六首  其五','郭印','宋','宋诗','song-poetry','','[]','前世愚夫哂鄧通，即山鼓鑄死饑窮。',64,'全唐诗/poet.song.95000.json','["前世愚夫哂鄧通，即山鼓鑄死饑窮。", "貪名勿羨青雲士，守道甘爲白髪翁。", "日月奔馳駒過隙，乾坤跼蹐鳥居籠。", "反觀自有超然地，能使淵明立下風。"]'),
('0f6017f7-c15e-4cb0-8c32-2212d000671e','和趙茂州即事六首  其六','郭印','宋','宋诗','song-poetry','','[]','所欲誰能矩不踰，人生七十在須叟。',64,'全唐诗/poet.song.95000.json','["所欲誰能矩不踰，人生七十在須叟。", "縱横竊鄙張儀詐，懷卷終思甯武愚。", "幸有精神延短景，了無才力奮雄圖。", "手提造化非難事，井底寒蛙祗自居。"]'),
('1c91c641-acdb-443c-a50d-639363f43f6a','諸友和章及性宗用韻二首  其一','郭印','宋','宋诗','song-poetry','','[]','服田力穯是良農，鹵莽耕耘報亦同。',64,'全唐诗/poet.song.95000.json','["服田力穯是良農，鹵莽耕耘報亦同。", "得道正從勤苦裏，了心只在刹那中。", "六通四闢非關學，萬别千差不見功。", "法法滿前供受用，更於何處覓家風。"]'),
('411a6c57-1c66-49a0-ac2c-78a4bc991b71','諸友和章及性宗用韻二首  其二','郭印','宋','宋诗','song-poetry','','[]','千花百草鬭青春，法界誰知本一真。',64,'全唐诗/poet.song.95000.json','["千花百草鬭青春，法界誰知本一真。", "生滅去來渾妙用，洪纖曲直現全身。", "參同聊示師資契，授受寧論父子親。", "直下承當猶自錯，可憐舍己更從人。"]'),
('27e71a0f-47ff-4bcb-a1cb-f145078b1703','宋子淵有詩及性宗事用韻寄之二首  其一','郭印','宋','宋诗','song-poetry','','[]','還淳反樸似山農，與物相忘即大同。',64,'全唐诗/poet.song.95000.json','["還淳反樸似山農，與物相忘即大同。", "造理自超言意表，發機不離見聞中。", "批雲切月能無事，轉地回天别有功。", "公案見成何必舉，請君於此嗣宗風。"]'),
('c17b6fb9-4ed8-48cd-9bcb-f9ac788f015e','宋子淵有詩及性宗事用韻寄之二首  其二','郭印','宋','宋诗','song-poetry','','[]','枯大寒巖但不春，直經千刼未爲真。',64,'全唐诗/poet.song.95000.json','["枯大寒巖但不春，直經千刼未爲真。", "一門超邈難尋軌，萬象森羅獨露身。", "田地穩時行便到，工夫盡處見方親。", "韓盧逐兔紛紛是，言語支離最誤人。"]'),
('38ce3872-0b62-476f-b346-7037457048b9','康子思二詩有問道之意和其韻  其一','郭印','宋','宋诗','song-poetry','','[]','稟生太極本純全，七尺身中豁一天。',64,'全唐诗/poet.song.95000.json','["稟生太極本純全，七尺身中豁一天。", "妙道高深從俗笑，至言微密向誰傳。", "何須青簡書勳業，賴有丹臺集聖賢。", "諸子但論時世事，令人懶語益思眠。"]'),
('bbe30047-80b3-4306-8c8c-f9bf426ac4ed','康子思二詩有問道之意和其韻  其二','郭印','宋','宋诗','song-poetry','','[]','要作通天一大儒，措心寥廓未爲迂。',64,'全唐诗/poet.song.95000.json','["要作通天一大儒，措心寥廓未爲迂。", "神機應變無多子，聖域知歸不遠塗。", "哮吼定應潛百獸，啁啾終是笑群雛。", "吾今欲覓衣中寶，活計須教一物無。"]'),
('813b277d-27ba-4c2b-8cf8-8047699c4acf','贈王君詔道人','郭印','宋','宋诗','song-poetry','','[]','潤屋金多笑不居，卻從象罔索玄珠。',64,'全唐诗/poet.song.95000.json','["潤屋金多笑不居，卻從象罔索玄珠。", "千年古鏡心長静，萬里飛雲身自孤。", "空裏結空空復有，夢中占夢夢元無。", "休將此語輕傳泄，舉世冥行少丈夫。"]'),
('ed555e71-0d63-424b-b3f9-d7c37119abcc','卜居','郭印','宋','宋诗','song-poetry','','[]','只憂短髪變星星，早葺生涯寄暮齡。',64,'全唐诗/poet.song.95000.json','["只憂短髪變星星，早葺生涯寄暮齡。", "二頃可能輕相印，一區聊欲著玄經。", "不嫌野水侵扉綠，更喜寒筠遶屋青。", "投紱歸來成底事，要驅龍虎遁天刑。"]'),
('74983ca0-b62f-4130-8b2a-6bb86adcfef7','次韻楊信仲見貽郊居二首  其一','郭印','宋','宋诗','song-poetry','','[]','平生不喜入州閭，林下江邊謾卜居。',64,'全唐诗/poet.song.95000.json','["平生不喜入州閭，林下江邊謾卜居。", "解榻延賓同笑語，杜門教子讀詩書。", "最憐舍後蔬盈圃，只欠庭前水繞除。", "官路嶮巇端可畏，茅茨固就早懸車。"]'),
('c0cbe3dc-2f0d-4f43-a7e0-bdb334629270','次韻楊信仲見貽郊居二首  其二','郭印','宋','宋诗','song-poetry','','[]','野老樵夫作比閭，儒宫一畝亦安居。',64,'全唐诗/poet.song.95000.json','["野老樵夫作比閭，儒宫一畝亦安居。", "澆愁剰買村前酒，引睡頻拈架上書。", "江近雲煙長到戶，人稀鳥鵲自馴除。", "不才已分時流棄，猶幸能延長者車。"]'),
('a1fc558b-b04b-49be-9012-fbc2d4929c25','次韻王德夫晚晴郊行之作','郭印','宋','宋诗','song-poetry','','[]','天含愁思雨冥冥，晚色雲銷萬里青。',64,'全唐诗/poet.song.95000.json','["天含愁思雨冥冥，晚色雲銷萬里青。", "幾點沙鷗臨水鏡，數重煙樹簇山屏。", "雅聞樵採能談道，欲耦鋤耰更問經。", "藜杖芒鞋先有約，相從避世免深刑。"]'),
('fd8a0100-f9c5-40de-801c-3de7f46ffca7','次韻師時發溪橋晚眺','郭印','宋','宋诗','song-poetry','','[]','卧溪古木勢蜿蜒，佇立斜陽旅思寛。',64,'全唐诗/poet.song.95000.json','["卧溪古木勢蜿蜒，佇立斜陽旅思寛。", "湍没岸痕知漲溢，風生水面覺清寒。", "静容桃李敷濃蔭，暖放鳬鷖浴短翰。", "隱約渭濱真髣髴，行藏都付一漁竿。"]'),
('c265d50b-75b8-4fd1-b7a5-c25b0a369948','和師時發荷亭晚飲','郭印','宋','宋诗','song-poetry','','[]','榴花灼爍半空開，天外薫風入座來。',64,'全唐诗/poet.song.95000.json','["榴花灼爍半空開，天外薫風入座來。", "雨掠南塘荷蓋凈，雲埋西嶺日車頹。", "物情榮謝看詩句，時世安危付酒杯。", "好是溪橋最清絕，淡烟寒水一遲回。"]'),
('758d1b6c-94c4-42b6-8e95-b210484f3287','憲司後園葺舊亭榜以明秀元少監有詩次韻','郭印','宋','宋诗','song-poetry','','[]','爛漫煙光一目收，危亭葺就壯岑樓。',64,'全唐诗/poet.song.95000.json','["爛漫煙光一目收，危亭葺就壯岑樓。", "三巴故國山川在，萬古長空日月流。", "江水奔騰無晝夜，石田耕穫漫春秋。", "興來笻竹隨兒輩，徑路平生不慣由。"]'),
('40b14b7b-73df-4214-ba1b-360018002605','再和四首  其一','郭印','宋','宋诗','song-poetry','','[]','萬象森羅不可收，一亭覽盡勝高樓。',64,'全唐诗/poet.song.95000.json','["萬象森羅不可收，一亭覽盡勝高樓。", "塗山南覲尊喬嶽，渝水東朝合衆流。", "煙起人家天欲暮，雲歸海嶠月當秋。", "此時此景尤佳絕，約客重來信有由。"]'),
('a157f8a9-a63e-4440-aeab-df9002b65603','再和四首  其二','郭印','宋','宋诗','song-poetry','','[]','東皇物色未全收，山半登臨當倚樓。',64,'全唐诗/poet.song.95000.json','["東皇物色未全收，山半登臨當倚樓。", "錦里煙光渾在眼，雲溪花片亦隨流。", "夕陽正好無多景，春序纔移已復秋。", "卻憶故園林壑美，乘風欲去問何由。"]'),
('d8ec4c90-60d0-424c-8e91-a2f1f250afc9','再和四首  其三','郭印','宋','宋诗','song-poetry','','[]','皇家故境未能收，愁絕登城與上樓。',64,'全唐诗/poet.song.95000.json','["皇家故境未能收，愁絕登城與上樓。", "目斷東吳心已往，神馳西洛淚先流。", "江山環合成兹邑，霧雨溟濛即是秋。", "賴有聖賢同一中，忍將時事說元由。"]'),
('899fb42b-fc79-4fc8-b277-44935238310c','再和四首  其四','郭印','宋','宋诗','song-poetry','','[]','天際油雲不肯收，全妨寓目向層樓。',64,'全唐诗/poet.song.95000.json','["天際油雲不肯收，全妨寓目向層樓。", "日車難把長繩挽，春事渾同去水流。", "可奈餘寒猶作沴，懸知徂暑未能秋。", "此方記得偏炎熱，路入夔門一再由。"]'),
('e0f6965a-e50d-4099-b3be-ae5d24218284','仁壽縣後有亭余名之曰明遠賦詩二首  其一','郭印','宋','宋诗','song-poetry','','[]','虛亭突兀枕崇岡，玉宇無風秋自凉。',64,'全唐诗/poet.song.95000.json','["虛亭突兀枕崇岡，玉宇無風秋自凉。", "地濶群山爭逶迤，天低遠樹立微茫。", "陰晴易辨雲霞色，曉夕常吞日月光。", "我亦清心官事省，葛巾藜杖得徜徉。"]'),
('d977b643-8989-45d6-b2d7-9bf77e27ab64','仁壽縣後有亭余名之曰明遠賦詩二首  其二','郭印','宋','宋诗','song-poetry','','[]','小邦人物大邦同，萬屋鱗鱗氣鬰葱。',64,'全唐诗/poet.song.95000.json','["小邦人物大邦同，萬屋鱗鱗氣鬰葱。", "誰挈神峰離海底，幻將廛市納壺中。", "垂簾擬學山陰畫，飛舄難乘葉縣風。", "舉首穹旻纔一尺，敢憑正直謝天公。"]'),
('a1307d41-16d7-412f-b190-7d2ac32c9abd','爽襟亭','郭印','宋','宋诗','song-poetry','','[]','西岡獨上每春容，天接危亭四面風。',64,'全唐诗/poet.song.95000.json','["西岡獨上每春容，天接危亭四面風。", "萬室鱗鱗歸眼底，一峰岌岌倚雲中。", "地靈人勝風流古，石秀山回氣象雄。", "曳杖頻來無别意，喜觀禾麥又年豐。"]'),
('7fdbfc33-2de7-4c9a-a2b1-081822993d1e','次韻劉文饒題絕塵亭','郭印','宋','宋诗','song-poetry','','[]','江白風清古寺虛，客來蕭散興何殊。',64,'全唐诗/poet.song.95000.json','["江白風清古寺虛，客來蕭散興何殊。", "水涵疏樹千尋浄，塵到幽亭一點無。", "天際昏烟迷小艇，林端落日射浮圖。", "欲添楚嶼深秋意，好向沙洲養橘奴。"]'),
('770bf793-8837-4aa0-bb40-197082ea59e4','雙清亭','郭印','宋','宋诗','song-poetry','','[]','鑿開蒼翠著幽亭，正取澄江一鏡平。',64,'全唐诗/poet.song.95000.json','["鑿開蒼翠著幽亭，正取澄江一鏡平。", "嘉木千章垂倒影，支流三道咽寒聲。", "橋横古路肩相屬，雲襯斜陽眼自明。", "竹色波光交借重，照人心骨有餘清。"]'),
('f7b737ea-d970-4bd7-b415-695b33dcab59','龍淵橋亭新成','郭印','宋','宋诗','song-poetry','','[]','溪淺橋横趣自幽，坐來風色晚颼颼。',64,'全唐诗/poet.song.95000.json','["溪淺橋横趣自幽，坐來風色晚颼颼。", "寒泉有韻石間出，遠水多情竹外流。", "地僻蛟龍時隱見，天晴鸂鶒亂沈浮。", "見聞總是吾家物，好景何須著意求。"]'),
('8a074a6a-a4ff-40bb-99b5-ccf2cfa3e573','次韻文士穎留題李子充雙寂軒詩','郭印','宋','宋诗','song-poetry','','[]','默默幽軒祗自知，天人一理未容欺。',64,'全唐诗/poet.song.95000.json','["默默幽軒祗自知，天人一理未容欺。", "簷光坐揖青山入，窗影閑看白日移。", "休道囂塵侵晏宅，由來表裏湛黄陂。", "思惟泯處全真現，存得靈龜笑朵頤。"]'),
('cb313b29-ebbc-4c5b-ba98-4996dc88045e','諸葛公則延登書閣出示焦丈通直洎諸公所贈詩因成四韻','郭印','宋','宋诗','song-poetry','','[]','諸城葛氏久湮沈，清尚知君獨遠尋。',64,'全唐诗/poet.song.95000.json','["諸城葛氏久湮沈，清尚知君獨遠尋。", "席卷承家猗頓術，日明好古子雲心。", "珍藏高閣輕三篋，善購多門小萬金。", "曾見墨莊耕穫利，行看杞梓秀家林。"]'),
('ce88810b-0548-48f9-a919-4a5c6430797d','同神泉縣尉遊海惠院登三惠閣有懷漢州同官','郭印','宋','宋诗','song-poetry','','[]','出郭幽尋偶一欣，初來猶未歎離群。',64,'全唐诗/poet.song.95000.json','["出郭幽尋偶一欣，初來猶未歎離群。", "誰知蕭寺懸荒野，卻有層樓插暮雲。", "煙外遥岑仍隱隱，風邊落葉更紛紛。", "天寒日薄牛羊下，遶樹歸鵶不忍聞。"]'),
('fa775a9f-c865-4c2e-938c-9db8e111839b','題遠色閣','郭印','宋','宋诗','song-poetry','','[]','倚杖從容日未曛，望中一洗兩眸昏。',64,'全唐诗/poet.song.95000.json','["倚杖從容日未曛，望中一洗兩眸昏。", "晴雲放出千尋嶺，喬木團成幾處村。", "東去西來長道路，春耕秋穫換郊原。", "無窮物象相吞吐，妙趣誰知在不言。"]'),
('94045bf8-160e-4020-af2f-5e84bc9be9eb','次韻蒲大受同遊龍洞之什','郭印','宋','宋诗','song-poetry','','[]','尋幽一訪洞中天，路遶青溪水遶山。',64,'全唐诗/poet.song.95000.json','["尋幽一訪洞中天，路遶青溪水遶山。", "翠徑崎嶇行竹裏，紅塵咫尺背人間。", "侵裾爽氣冷冰雪，潄玉寒流鏘珮環。", "更問石庵窺勝迹，斯遊豈復倦躋攀。"]'),
('d4d7a9fb-fca9-4bcc-9a1c-b29bae2a42c2','次韻董守流杯池','郭印','宋','宋诗','song-poetry','','[]','巧思潛窺造化兒，更依曲水鑿方池。',64,'全唐诗/poet.song.95000.json','["巧思潛窺造化兒，更依曲水鑿方池。", "靈鼇上釣喧紅粉，輕鷁浮觴趁彩旗。", "落澗寒聲泉㶁㶁，弄花斜日影遲遲。", "分明作箇山陰會，仍有當時幼婦辭。"]'),
('615b9b39-8313-4630-a515-874a79ff0fd3','歸雲溪','郭印','宋','宋诗','song-poetry','','[]','九夏何知暑令行，輕風拂拂水泠泠。',64,'全唐诗/poet.song.95000.json','["九夏何知暑令行，輕風拂拂水泠泠。", "只憑藜杖穿幽徑，還喜蒲團憩小亭。", "散誕竹邉梳白髪，徘徊江上誦黄庭。", "人間無此清涼處，亦許兒童共乞靈。"]'),
('afa52030-f759-43ff-b5c3-25dac1fcfe4f','忠州懷古','郭印','宋','宋诗','song-poetry','','[]','連日追遊笑語同，一樽能遣百愁空。',64,'全唐诗/poet.song.95000.json','["連日追遊笑語同，一樽能遣百愁空。", "唐賢閣上秋風冷，巴子臺邊夕照紅。", "木落荒坡思白傅，草深頹墓憶宣公。", "只憐地狹難成市，依舊沙頭作小叢。"]'),
('18a15508-5d95-49e3-8f39-24cdd0a8231d','留雲安驛詩','郭印','宋','宋诗','song-poetry','','[]','孤館幽幽一境清，晝長無事亦無營。',64,'全唐诗/poet.song.95000.json','["孤館幽幽一境清，晝長無事亦無營。", "睡頻推枕仍重起，坐久抛書卻再行。", "静看簷頭蛛結網，細聽屋角鳥翻聲。", "閑邊日月元如此，須信人間有赤城。"]'),
('c51d31cc-25ed-4e68-9173-3113faaee1b8','八陣臺','郭印','宋','宋诗','song-poetry','','[]','八陣臺前水急流，纍纍石塚界沙洲。',64,'全唐诗/poet.song.95000.json','["八陣臺前水急流，纍纍石塚界沙洲。", "機深已盡吞吳策，事變空成守蜀謀。", "江月四時猶耿耿，雲山千古謾悠悠。", "天公若遂興劉願，功烈應非管樂儔。"]'),
('46bbf999-f7d2-48c0-ba10-58294a51996c','過小漢壩','郭印','宋','宋诗','song-poetry','','[]','地豁天開眼界寛，兩山相對列巑岏。',64,'全唐诗/poet.song.95000.json','["地豁天開眼界寛，兩山相對列巑岏。", "多情煙樹連村暗，不事沙鷗照水寒。", "立馬躊躇饒野興，抗塵奔走尚粗官。", "歸來凖擬江湖計，不負蓑衣與釣竿。"]'),
('4050c905-1b76-4f14-8144-2ab8e4694040','漢州塔二首  其一','郭印','宋','宋诗','song-poetry','','[]','萬象森羅眼底明，倚天高處喜重經。',64,'全唐诗/poet.song.95000.json','["萬象森羅眼底明，倚天高處喜重經。", "逶迤江練秋逾白，峛崺山屏晚更青。", "望盡平原煙冉冉，愁深古塞雨冥冥。", "躊躇欲看千燈後，手撥浮雲正極星。"]'),
('ac7a9b00-cc54-4a9b-ba7e-62082550f1cf','漢州塔二首  其二','郭印','宋','宋诗','song-poetry','','[]','相隨步屧轉穹隆，萬室鱗鱗指顧中。',64,'全唐诗/poet.song.95000.json','["相隨步屧轉穹隆，萬室鱗鱗指顧中。", "自笑情懷非曠士，誰知筋力已衰翁。", "吟餘尚惜西山日，立久翻憂北戶風。", "從此不須攀絕頂，雲深無處認鼇宫。"]'),
('d3b1f5e7-fd6e-4f49-8328-e2f3908ed29a','陪元允大受遊天寧寺詩','郭印','宋','宋诗','song-poetry','','[]','寂寂禪林繞篆香，長廊古殿總虛涼。',64,'全唐诗/poet.song.95000.json','["寂寂禪林繞篆香，長廊古殿總虛涼。", "楩柟蔽日空交影，烏鵲馴除不亂行。", "滅想自成清浄界，争機端作是非場。", "灼然祖意休生解，炯炯寒燈一點光。"]'),
('6d680c41-3a9f-47e3-8394-de31310907a4','總持院','郭印','宋','宋诗','song-poetry','','[]','曉霽同登古息臺，雨師先爲洒塵埃。',64,'全唐诗/poet.song.95000.json','["曉霽同登古息臺，雨師先爲洒塵埃。", "紋楸戰罷仙蹤杳，清磬音傳佛寺開。", "門外老松迎客入，竹邊高閣放山來。", "逡巡攬盡風光去，寄語三官不用猜。"]'),
('131103df-0086-4a1a-a2e2-07d735252743','合州菩提院和嚴夢錫韻','郭印','宋','宋诗','song-poetry','','[]','小刹遲留爲覓船，欲憑一葦下長川。',64,'全唐诗/poet.song.95000.json','["小刹遲留爲覓船，欲憑一葦下長川。", "磬傳清韻每知曉，柏偃樛枝休問年。", "末路風埃埋日月，故園松竹老雲煙。", "由來行止皆天定，遇坎乘流只信緣。"]'),
('4d5d4197-063d-4575-a5a4-543d159d6666','宿覺空院用壁間韻寄王巨山','郭印','宋','宋诗','song-poetry','','[]','度壠穿雲十里遥，招提蹲踞亂山坳。',64,'全唐诗/poet.song.95000.json','["度壠穿雲十里遥，招提蹲踞亂山坳。", "地靈潛隱聖賢宅，林静俯闚烏鵲巢。", "萬法豈從心外有，一真還向夢中交。", "世間出世元無别，塵俗紛紛不用抛。"]'),
('61fc0112-f76b-4889-b31e-91640686d611','元日有感呈正紀','郭印','宋','宋诗','song-poetry','','[]','情緒長隨節物遷，老逢元日更悽然。',64,'全唐诗/poet.song.95000.json','["情緒長隨節物遷，老逢元日更悽然。", "春風未省摇心曲，臘雪空留點鬢邊。", "加我四年終易學，長君一歲尚塵緣。", "何當同伏嵌巖下，添取爐中住世鉛。"]'),
('9298aae0-9b03-4cf5-bb91-b1ce9c1d4b0e','立春','郭印','宋','宋诗','song-poetry','','[]','頗恨東風巧入簾，不論朱戶與茅簷。',64,'全唐诗/poet.song.95000.json','["頗恨東風巧入簾，不論朱戶與茅簷。", "青春處處爲誰好，白髮年年空自嫌。", "市酒豈能供燕笑，官娃無復問穠纖。", "強隨兒輩追時節，菜壓香盤未損廉。"]'),
('09551a7b-c814-4fa8-97fe-a3c18040a60e','正月八日至十二日雪不止和施仲任韻','郭印','宋','宋诗','song-poetry','','[]','天雨寶花呈上瑞，不同常歲旋能乾。',64,'全唐诗/poet.song.95000.json','["天雨寶花呈上瑞，不同常歲旋能乾。", "癡兒詫見鹽成糝，戲僕圓搓玉作團。", "漏屋茅簷垂欲壓，華筵酒椀正禁寒。", "懸知片片非他物，落處應須子細看。"]'),
('d032d97d-403d-47be-a2ea-34842ccafe7e','和錢叔凭長官京師新春即事','郭印','宋','宋诗','song-poetry','','[]','青門冠蓋近迎春，物態天容旦暮新。',64,'全唐诗/poet.song.95000.json','["青門冠蓋近迎春，物態天容旦暮新。", "日暖御溝初破凍，雪消馳道未生塵。", "曉煙暗綠金條眼，佳氣晴浮碧瓦鱗。", "唯有紙鳶堪一噱，掠天翔泳不由身。"]'),
('4aa97c72-601b-4b98-8e2e-bc950d1f472c','上巳曲水','郭印','宋','宋诗','song-poetry','','[]','良辰元巳惜芳菲，一笑林亭挽落暉。',64,'全唐诗/poet.song.95000.json','["良辰元巳惜芳菲，一笑林亭挽落暉。", "圓吭高低齊獻曲，濃陰遠近密成圍。", "縠翻細浪環池轉，羽挾清觴傍席飛。", "不爲不祥來祓濯，欲因流水送春歸。"]'),
('f552ff4c-f680-4dec-b9bb-b0d580a17370','次韻袁德夫春日書事二首  其一','郭印','宋','宋诗','song-poetry','','[]','公餘蕭散步晴暉，正是韶光懶困時。',64,'全唐诗/poet.song.95000.json','["公餘蕭散步晴暉，正是韶光懶困時。", "官事暫能逃倥偬，物情深覺變神奇。", "風傳小樹香浮砌，水接平湖綠滿池。", "春草怪來成好夢，西堂句法少人知。"]'),
('3df10837-1722-4826-a073-f5e287c63fc3','次韻袁德夫春日書事二首  其二','郭印','宋','宋诗','song-poetry','','[]','滿眼煙光困不勝，群紅委地綠堆林。',64,'全唐诗/poet.song.95000.json','["滿眼煙光困不勝，群紅委地綠堆林。", "空庭鳥下簿書退，小院燕歸簾幙深。", "千里故人縈午夢，一樽新酒隔春岑。", "多情柳外鶯聲囀，似向東風寫客心。"]'),
('1b508eff-ad13-4687-89b4-0c4b78be9229','和喻迪孺郎中春日書事二首  其一','郭印','宋','宋诗','song-poetry','','[]','春風不入鬢邊青，羞逐兒童趁晚晴。',64,'全唐诗/poet.song.95000.json','["春風不入鬢邊青，羞逐兒童趁晚晴。", "花欲近人顔色好，鳥來窺戶語音清。", "鈎簾静院山相顧，散策高亭月共行。", "自斷窮通天已定，休勞占數向枯莖。"]'),
('eb099b14-f3f4-4a9c-a945-56b57899cf0a','和喻迪孺郎中春日書事二首  其二','郭印','宋','宋诗','song-poetry','','[]','人間春思漫紛爭，祗把新詩喚曉鶯。',64,'全唐诗/poet.song.95000.json','["人間春思漫紛爭，祗把新詩喚曉鶯。", "妙處鐫鑱應鬼泣，醉中揮灑自風生。", "誰知雅道當今絕，獨與騷人並駕行。", "尺紙飛來光照夜，小窗申誦到參横。"]'),
('9159258c-8477-4371-b221-f356ee3cea5a','春日雲溪即事二首  其一','郭印','宋','宋诗','song-poetry','','[]','乞得筋骸伴老農，一丘春興有誰同。',64,'全唐诗/poet.song.95000.json','["乞得筋骸伴老農，一丘春興有誰同。", "禽聲路入笙簧裏，花色人行錦繡中。", "薙草養蘭修故事，鑿渠引水著新功。", "羲和叱馭應難挽，愁見顛狂柳絮風。"]'),
('d03e5bc8-218d-4dc6-8481-6faa529e6af1','春日雲溪即事二首  其二','郭印','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','林壑棲遲兩見春，一笻一麈任天真。',64,'全唐诗/poet.song.95000.json','["林壑棲遲兩見春，一笻一麈任天真。", "鶯花世界無停晷，電露光陰莫負身。", "蟻戰蝸爭那復問，魚浮鳥戲自相親。", "長江不日桃花浪，築石牢堤急倩人。"]'),
('adb150ed-7f2d-4e1a-a5c2-d253ca96326d','春晴二首  其一','郭印','宋','宋诗','song-poetry','','[]','春工又是一番新，滿目韶光欲醉人。',64,'全唐诗/poet.song.95000.json','["春工又是一番新，滿目韶光欲醉人。", "風喚鳴禽爭暖日，雨粘飛絮著香塵。", "老來情緒元知别，酒後形神始覺親。", "獨向小齋書咄咄，無端燕子往來頻。"]'),
('de716baf-a40d-489b-94e9-287239911b9f','春晴二首  其二','郭印','宋','宋诗','song-poetry','','[]','二月垂楊長綠柯，漁村春塢景融和。',64,'全唐诗/poet.song.95000.json','["二月垂楊長綠柯，漁村春塢景融和。", "沙邊細浪摇芳藻，水上紅雲映綠波。", "風裊釣絲時蕩漾，日移花影更婆娑。", "徑須展此連鼇手，且向樽前醉倒歌。"]'),
('875e2944-c9fd-428d-9643-3d15602660ac','道中得雨','郭印','宋','宋诗','song-poetry','','[]','暖律潛開四序先，土牛何處不施鞭。',64,'全唐诗/poet.song.95000.json','["暖律潛開四序先，土牛何處不施鞭。", "道逢宿雨連新雨，人說今年勝舊年。", "和氣薰蒸還率土，湛恩汪濊仰高天。", "甲兵一洗成豐稔，從此邊陲定帖然。"]'),
('08891115-0dc1-43a5-aa53-71a0c95248fa','孫希汲出示所和杜允迪二詩因次韻并寄允迪以當别後一笑','郭印','宋','宋诗','song-poetry','','[]','草木藏春柳報先，誰将蒼馭快如鞭。',64,'全唐诗/poet.song.95000.json','["草木藏春柳報先，誰将蒼馭快如鞭。", "夜中一雨知無價，陌上三農慶有年。", "玉糝寒林梅委地，浪翻平野麥連天。", "陰陽燮理非吾事，新歲調和豈偶然。"]'),
('946297ca-c9ad-40cd-a914-7618cae82ea2','和余時升周子美江雨有懷雨不絕詩韻各賦一首  其一','郭印','宋','宋诗','song-poetry','','[]','天作淫雨似秋中，沾濕恐侵河伯宫。',64,'全唐诗/poet.song.95000.json','["天作淫雨似秋中，沾濕恐侵河伯宫。", "螟螣欲傷禾黍秀，黿鼉尚快波濤風。", "誰驅天際亂雲墨，且放山巔晴日紅。", "有酒亟來相就飲，流光一去大江東。"]'),
('a677f136-1a1d-4bb4-8f4a-c840e4422f12','和余時升周子美江雨有懷雨不絕詩韻各賦一首  其二','郭印','宋','宋诗','song-poetry','','[]','簷前萬點落珠璣，乳燕梁間嫩學飛。',64,'全唐诗/poet.song.95000.json','["簷前萬點落珠璣，乳燕梁間嫩學飛。", "水匯百川人迹絕，苔封三徑馬蹄稀。", "田塍湓溢禾生耳，薜荔芊綿垣有衣。", "江上何人清興盡，卻乘新漲棹舟歸。"]'),
('6f8ff12e-13bf-4f27-a727-317e9dbaa6ec','次韻邵子文感春之什','郭印','宋','宋诗','song-poetry','','[]','池塘不似昔年春，蝶亂蜂狂更惱人。',64,'全唐诗/poet.song.95000.json','["池塘不似昔年春，蝶亂蜂狂更惱人。", "莫傍花叢看婉娩，且懷詩卷誦清新。", "山林祗管縈魂夢，寰宇無端變刼塵。", "遥想江東憂未歇，可能熟醉巧謀身。"]'),
('3ed62d83-4a83-4ecb-bd59-bce78bc33948','送春','郭印','宋','宋诗','song-poetry','','[]','春色忽隨流水去，人間誰解絆風光。',64,'全唐诗/poet.song.95000.json','["春色忽隨流水去，人間誰解絆風光。", "一聲杜宇乾坤隘，萬點飛花日月忙。", "道阻豈能游上苑，年衰無復夢幽塘。", "蜂情蝶意都蕭索，難化吾心一寸剛。"]'),
('b4a7a2d5-b82e-4892-8636-57bf259b2240','次韻時升春盡之作','郭印','宋','宋诗','song-poetry','','[]','送春仍恨酒盃乾，今夕休眠到漏殘。',64,'全唐诗/poet.song.95000.json','["送春仍恨酒盃乾，今夕休眠到漏殘。", "歌舞縱無供笑語，賓朋猶有近門闌。", "傷心已訝千林綠，轉眼還看萬葉丹。", "節去節來君莫問，詩盟從此勿令寒。"]'),
('1430d3f6-f95b-48d9-883f-a51b3feb58b8','再和','郭印','宋','宋诗','song-poetry','','[]','紛紛滿地落紅乾，杜宇聲中春正殘。',64,'全唐诗/poet.song.95000.json','["紛紛滿地落紅乾，杜宇聲中春正殘。", "詩酒情懷公事汩，干戈時節賞心闌。", "生憎蔓草緣堦碧，卻喜含桃向日丹。", "萬里吳天飛不到，劍光空射斗牛寒。"]'),
('f036e02d-3050-45e5-9587-644ef558b587','和史守八月十四日月二首  其一','郭印','宋','宋诗','song-poetry','','[]','月蘸澄江上下天，波光桂魄兩依然。',64,'全唐诗/poet.song.95000.json','["月蘸澄江上下天，波光桂魄兩依然。", "喜延嘉客樓同倚，貪吸清輝席屢前。", "萬里無雲秋更濶，千門不夜曉相連。", "嫦娥且駐來宵駕，玉宇年年不列仙。"]'),
('47bed910-020f-4934-a3e8-68a6f53c2755','和史守八月十四日月二首  其二','郭印','宋','宋诗','song-poetry','','[]','半秋雲物掃遥天，對月凭欄一憮然。',64,'全唐诗/poet.song.95000.json','["半秋雲物掃遥天，對月凭欄一憮然。", "明夜半規應盡滿，此時清賞更無前。", "瓊樓頗覺三山近，玉斧誰将七寶連。", "我欲乘風霄漢上，坐令凡骨變真仙。"]'),
('677d7f17-fd91-4c07-83d1-10d57f122fd9','中秋佳月懷杜安行馮當可二首  其一','郭印','宋','宋诗','song-poetry','','[]','西風捲盡片雲浮，天宇團圓素月流。',64,'全唐诗/poet.song.95000.json','["西風捲盡片雲浮，天宇團圓素月流。", "玉斧修成三夜景，銀盤賽過十年秋。", "佳人渺邈心相照，羈客徘徊影共愁。", "安得仙娥一招手，驅鸞駕鶴上瓊樓。"]'),
('bc1efd5d-0724-424f-9f40-0b424864b688','中秋佳月懷杜安行馮當可二首  其二','郭印','宋','宋诗','song-poetry','','[]','絕勝尋常三五盈，魄成金氣自然清。',64,'全唐诗/poet.song.95000.json','["絕勝尋常三五盈，魄成金氣自然清。", "煙雲斂迹秋空濶，星斗沉光夜色明。", "璧墮江心隨浪湧，鏡飛天面逐人行。", "四方萬里同清賞，大地今成白玉京。"]'),
('e0759b21-1083-444b-b209-6cb3f15be8fb','再和前韻  其一','郭印','宋','宋诗','song-poetry','','[]','陰陽升降定沉浮，九候之前大火流。',64,'全唐诗/poet.song.95000.json','["陰陽升降定沉浮，九候之前大火流。", "人遠祗同千里月，天高誰放一輪秋。", "飛螢眇眇何時見，驚鵲紛紛特地愁。", "陋屋窮簷無不照，清光豈獨射高樓。"]'),
('317debb0-f301-4131-a26b-67b23573827e','再和前韻  其二','郭印','宋','宋诗','song-poetry','','[]','淅淅乾坤灝氣盈，多情明月共秋清。',64,'全唐诗/poet.song.95000.json','["淅淅乾坤灝氣盈，多情明月共秋清。", "且将照席銀缸背，自有窺簷寶鑑明。", "但喜人心都愛好，誰知天度不留行。", "反身一視真奇特，夜夜神光莫與京。"]'),
('4bd03af9-4b83-4943-96b5-cde0e71d83fd','次元守中秋觀月韻','郭印','宋','宋诗','song-poetry','','[]','青霄萬里絕纖毫，海上仙人獨釣鼇。',64,'全唐诗/poet.song.95000.json','["青霄萬里絕纖毫，海上仙人獨釣鼇。", "蕩蕩性天元廓落，亭亭心月本孤高。", "寒光破碎穿幽徑，素影飛翻入怒濤。", "但挹金波還洗滌，不須遥望日生高。"]'),
('c9435163-d34b-481e-87a7-9dea4fab6a36','八月十四至十六日無月二首  其一','郭印','宋','宋诗','song-poetry','','[]','秋中景色正蕭森，月色超然重古今。',64,'全唐诗/poet.song.95000.json','["秋中景色正蕭森，月色超然重古今。", "要使萬方傾素采，那知三日翳重陰。", "晦冥欲害天公眼，想像難忘海宇心。", "決斷浮雲須好手，明年此夕要追尋。"]'),
('8523be85-3a8f-43b1-ac9b-a3d99b310e2f','八月十四至十六日無月二首  其二','郭印','宋','宋诗','song-poetry','','[]','不見團圓桂景森，清輝一片本常今。',64,'全唐诗/poet.song.95000.json','["不見團圓桂景森，清輝一片本常今。", "欲看静夜千家晝，先掃長空萬里陰。", "宇宙光明思佛掌，兒童嚬蹙見人心。", "茫茫千里憑誰問，每使良辰罷訪尋。"]'),
('2c5799a7-9a34-42f3-aa15-31ef43d30f7d','十七日夜當可同去非觀月而子儀進道與僕皆不在焉當可有詩輒次韻','郭印','宋','宋诗','song-poetry','','[]','月過中秋色尚鮮，賞心未厭惜流年。',64,'全唐诗/poet.song.95000.json','["月過中秋色尚鮮，賞心未厭惜流年。", "瓊杯不許三人共，桂魄難同兩夜圓。", "碧落無雲星避彩，清輝滿座燭銷煙。", "新詩唱罷應愁絕，影入珠簾照客眠。"]'),
('11337c0e-3177-4d29-b312-5a86f0e36abd','當可觀月有歸來清絕不成眠之句因廣其意作五十六字','郭印','宋','宋诗','song-poetry','','[]','一别嬋娟便隔秋，寒光今夕爲誰流。',64,'全唐诗/poet.song.95000.json','["一别嬋娟便隔秋，寒光今夕爲誰流。", "萬家窗戶人推枕，千里關山客倚樓。", "酒欲忘懷難解醉，詩将遣興卻添愁。", "空堂耿耿渾無寐，曉鏡看來易白頭。"]'),
('548a7663-5221-4e40-8295-d0ef56aa4da7','秋懷二首  其一','郭印','宋','宋诗','song-poetry','','[]','西風獵獵動天關，底事縈心撥棄難。',64,'全唐诗/poet.song.95000.json','["西風獵獵動天關，底事縈心撥棄難。", "夜枕蛩聲連曉急，暮樓鴻影落江寒。", "遣懷樽酒渾消得，遮眼文書亦倦看。", "物理盈虛元已定，傷時何苦淚闌干。"]'),
('11ecd3c8-9494-4712-827f-dbe03c827fc1','秋懷二首  其二','郭印','宋','宋诗','song-poetry','','[]','窗戶寒生不幕羅，無邊愁緒費長哦。',64,'全唐诗/poet.song.95000.json','["窗戶寒生不幕羅，無邊愁緒費長哦。", "有情尚覺天公老，不飲争如月色何。", "歲序峥嶸雙鬢改，乾坤離亂一身多。", "年來懶讀悲秋賦，忍聽商聲入詠歌。"]'),
('0b8ae387-1fea-4ee9-a99f-ccc376ede967','和元守重陽和韻','郭印','宋','宋诗','song-poetry','','[]','空樽獨把送斜陽，九日何憂酒中傷。',64,'全唐诗/poet.song.95000.json','["空樽獨把送斜陽，九日何憂酒中傷。", "客裏吟情尤寞寞，夢中歸意亦茫茫。", "楓飄丹葉隨流水，菊吐黄花犯早霜。", "惟有堅心松柏在，四時不改色蒼蒼。"]'),
('c3281118-83b5-42c6-a78b-b430ef3b1260','謝道守董朝散臘日分惠採魚','郭印','宋','宋诗','song-poetry','','[]','臘日公塘命矢魚，親迂五馬過康衢。',64,'全唐诗/poet.song.95000.json','["臘日公塘命矢魚，親迂五馬過康衢。", "分波短艇金梭疾，綴網圓鬐玉葉粗。", "滋味盡教沾掾屬，割烹不獨侑賓厨。", "從今下客休彈鋏，不似馮諼恨食無。"]'),
('7b414883-d13d-4230-85de-64af64432f54','臘雪','郭印','宋','宋诗','song-poetry','','[]','好雪還從臘日飛，空庭委積路淋漓。',64,'全唐诗/poet.song.95000.json','["好雪還從臘日飛，空庭委積路淋漓。", "寒深閉戶難延客，興發乘舟欲訪誰。", "沒谷沉崖真快意，撒鹽飛絮敢言詩。", "兒童詫見千山縞，來歲豐登定可期。"]'),
('e26d7a85-c8f7-4fb5-875a-628e5a323455','詠雪','郭印','宋','宋诗','song-poetry','','[]','上天連日擁愁雲，曉起聯翩瑞色新。',64,'全唐诗/poet.song.95000.json','["上天連日擁愁雲，曉起聯翩瑞色新。", "入麥未多三日雨，著梅先報萬家春。", "興來賴有乘舟客，喜極寧爲閉戶人。", "安得梁王相命賦，兔園避席少逡巡。"]'),
('566aba8d-12a4-4643-a356-fb0e080e8948','次韻李堯俞良臣論交一首','郭印','宋','宋诗','song-poetry','','[]','深知不作昌時瑞，成繭那能效野蠶。',64,'全唐诗/poet.song.95000.json','["深知不作昌時瑞，成繭那能效野蠶。", "世態如雲從自薄，交情若水定非甘。", "最憐炊黍張生約，勿笑分財管仲貪。", "欲結他年漁釣友，江湖舍我復誰堪。"]'),
('27aeae31-2c79-4c00-adb1-1bfe57504f94','郭有道先生知命錄喜其擺落世塵去來自在真神仙中人也用余時升韻附於群公詩後','郭印','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','高標百世可廉頑，喧處亡心心自閑。',64,'全唐诗/poet.song.95000.json','["高標百世可廉頑，喧處亡心心自閑。", "小院客來風掃地，涼宵人静月窺關。", "了知游戱夢蝴蝶，聊學逍遥歌泰山。", "須信先生今未死，青冥鶴駕眇難攀。"]'),
('b93fba7b-c3d6-46e2-9f83-038e38e357f5','老境','郭印','宋','宋诗','song-poetry','','[]','怪來齒髮日凋疏，坐閱春秋六十餘。',64,'全唐诗/poet.song.95000.json','["怪來齒髮日凋疏，坐閱春秋六十餘。", "鬢雪難消休把鏡，眼花易發廢觀書。", "身邊賴有三田實，世上須知一夢虛。", "只辦此心贏造化，浮漚起滅不關渠。"]'),
('c07ddf7e-cf39-4ac2-b6e7-5eccf2d59533','張持道生辰二首  其一','郭印','宋','宋诗','song-poetry','','[]','來自仙家白玉京，秋穹灝氣欲平分。',64,'全唐诗/poet.song.95000.json','["來自仙家白玉京，秋穹灝氣欲平分。", "人間莫道無先覺，天下須知有達尊。", "豈但期頤稱上壽，行看嬉戲弄仍孫。", "三溪自是蓬萊境，陵谷遷移此獨存。"]'),
('8b806f63-7b1d-4c5d-b14e-cd817744dbae','張持道生辰二首  其二','郭印','宋','宋诗','song-poetry','','[]','西南英譽滿簮紳，安富尊滎孰儗倫。',64,'全唐诗/poet.song.95000.json','["西南英譽滿簮紳，安富尊滎孰儗倫。", "世上種成無限果，人間贏得自由身。", "手提日月超千刼，心隘乾坤等一塵。", "應笑盈庭爭祝頌，兒童猶復詠松椿。"]'),
('1163ff71-2a5b-4b9b-bc5f-a3c3ffd2df70','壽湯總領  其一','郭印','宋','宋诗','song-poetry','','[]','春色平分又六宵，天生良弼佐皇朝。',64,'全唐诗/poet.song.95000.json','["春色平分又六宵，天生良弼佐皇朝。", "豸冠凜凜周行肅，虎節煌煌蜀地饒。", "已喜月卿還舊物，更看斗極轉高標。", "仁人自合超諸數，鶴算龜齡未是遥。"]'),
('62924a20-fc78-44ff-9b78-080a73c3c234','壽湯總領  其二','郭印','宋','宋诗','song-poetry','','[]','睿主寛仁徧九垓，西南總計屬英才。',64,'全唐诗/poet.song.95000.json','["睿主寛仁徧九垓，西南總計屬英才。", "一犂雨向田間足，萬里春從天際來。", "洗盡瘡痍憑藥石，調成鼎鼐得鹽梅。", "赤松有約應難老，未信人間白髮催。"]'),
('213fae68-86be-4677-97da-2faa7cd32763','宋正紀輓詞二首  其一','郭印','宋','宋诗','song-poetry','','[]','振羽曾參上國鴻，偶飛不到廣寒宫。',64,'全唐诗/poet.song.95000.json','["振羽曾參上國鴻，偶飛不到廣寒宫。", "詩書教子心尤切，孝友承家德自豐。", "一命未酬耽學志，半途何負攝生功。", "新阡鬰鬰今埋骨，想見哀吟萬國風。"]'),
('5614f301-66a7-4e5b-829d-3756a6df5694','宋正紀輓詞二首  其二','郭印','宋','宋诗','song-poetry','','[]','姻好通來十八春，酒盃詩卷最相親。',64,'全唐诗/poet.song.95000.json','["姻好通來十八春，酒盃詩卷最相親。", "休心失約尋真侣，轉首誰知作古人。", "庵畔松篁長泣雨，室中書史暗凝塵。", "我嘗一訪經行處，白日蕭條倍愴神。"]'),
('67343672-08d3-4101-b4fa-2b6bacfc7f9d','范深父察推輓詞','郭印','宋','宋诗','song-poetry','','[]','榮國諸孫迥不同，妙年英氣吐長虹。',64,'全唐诗/poet.song.95000.json','["榮國諸孫迥不同，妙年英氣吐長虹。", "聖經每陋三家學，文陣平收一戰功。", "可但芹宫滋教雨，更看花縣暢仁風。", "詩書滿腹成何事，惆悵舟移夜壑空。"]'),
('6aee13fc-3ce5-45fa-9111-624fc5972336','弔宇文道可','郭印','宋','宋诗','song-poetry','','[]','居閑共喜迹相親，桑戶誰知遽反真。',64,'全唐诗/poet.song.95000.json','["居閑共喜迹相親，桑戶誰知遽反真。", "三紀周旋渾作夢，一樽離别倍傷神。", "舊邦猶憶江山主，新圃俄摧草木春。", "陰德降祥天報定，高車駟馬豈無人。"]'),
('5b84018c-0285-4aae-8eac-723ec2f38914','彭公堂','郭印','宋','宋诗','song-poetry','','[]','一瞻遺像起遐思，慶歷風流想見之。',64,'全唐诗/poet.song.95000.json','["一瞻遺像起遐思，慶歷風流想見之。", "政化寛平無後日，文詞純質似當時。", "溪山寂寂人何在，林沼依依澤未衰。", "堂共灘名俱不朽，十年清節斗星垂。"]'),
('8ace421b-e6db-4aca-bddd-9431a3f6c762','王夫人輓詞','郭印','宋','宋诗','song-poetry','','[]','吁嗟蘭德已雲翩，空見佳城在九原。',64,'全唐诗/poet.song.95000.json','["吁嗟蘭德已雲翩，空見佳城在九原。", "無祿久虛南澗藻，有姑誰慰北堂萱。", "苦荼獨御安天命，曒日同歸信誓言。", "諸子欲知遺恨事，隴頭長聽水潺湲。"]'),
('3ad3059b-8887-42d6-a8e7-7063e426d983','申夫人輓詞','郭印','宋','宋诗','song-poetry','','[]','鳳去鸞隨事可傷，唯傳婦道式閨房。',64,'全唐诗/poet.song.95000.json','["鳳去鸞隨事可傷，唯傳婦道式閨房。", "紫簫吹月元同上，寶劍凌波亦並藏。", "南澗蘋餘空自老，北堂萱在爲誰芳。", "幸哉有子遵遺計，外氏猶能謹祭嘗。"]'),
('479b6138-78e2-4396-8538-f9e00ac32a0f','明上人感棋不已作詩贈之','郭印','宋','宋诗','song-poetry','','[]','未然一著最玄微，黑白分明會者稀。',64,'全唐诗/poet.song.95000.json','["未然一著最玄微，黑白分明會者稀。", "但向死中求活路，莫於平處鬭玄機。", "勢強失利緣輕敵，力困收功爲解圍。", "勝負紛紛成底事，不如完璧早還歸。"]'),
('a60b6976-9c9f-4285-abd1-bb5d0a537e9b','再用前韻','郭印','宋','宋诗','song-poetry','','[]','禪宗詩律造精微，眼底紛紛識者稀。',64,'全唐诗/poet.song.95000.json','["禪宗詩律造精微，眼底紛紛識者稀。", "舉世何人談大道，憐君與我叩玄機。", "休誇修煉飛金闕，勿笑沉淪陷鐵圍。", "善惡兩途俱是錯，堂堂日用要知歸。"]'),
('edcbc293-c74b-4365-bae2-818e0bf8ceff','和許覺民麈尾笻竹杖','郭印','宋','宋诗','song-poetry','','[]','拂穢清塵志自殊，斯文危弱更當扶。',64,'全唐诗/poet.song.95000.json','["拂穢清塵志自殊，斯文危弱更當扶。", "嘉言亹亹手嘗御，高步徐徐身與俱。", "驅犢幾曾遭戲笑，化龍應亦在斯須。", "龜毛兔角人人用，莫道吾家此物無。"]'),
('64f678de-d7cf-4f2a-ab3e-33da2c6f52d4','和榮安中道中見梅','郭印','宋','宋诗','song-poetry','','[]','春來無奈客愁新，一破衰顔粉面勻。',64,'全唐诗/poet.song.95000.json','["春來無奈客愁新，一破衰顔粉面勻。", "笑折繁枝頭带雪，想成青子頰生津。", "真香未許蘭爲佩，仙質何妨縞作巾。", "勿怪天公多著意，爲憐風韻冠群倫。"]'),
('3a2d0ead-a9a6-4237-a595-a21812976b47','再和','郭印','宋','宋诗','song-poetry','','[]','雪裏寒梅歲又新，粘枝的皪已開勻。',64,'全唐诗/poet.song.95000.json','["雪裏寒梅歲又新，粘枝的皪已開勻。", "行人邂逅先傳信，枯卉逡巡欲問津。", "他日調羹憑傅鼎，此時漉酒借陶巾。", "粉腮紅跗休輕放，醉賞從人笑伯倫。"]'),
('c50a549e-601e-43e6-bd93-46de6786b5ab','紅梅','郭印','宋','宋诗','song-poetry','','[]','姿韻清高自一家，不将夭艷喚蜂衙。',64,'全唐诗/poet.song.95000.json','["姿韻清高自一家，不将夭艷喚蜂衙。", "衝寒萬木渾無葉，回暖孤根獨放花。", "要與雪霜争皎潔，肯隨桃李趁繁華。", "更看結實調羹在，疏影寒香未足誇。"]'),
('d32a1019-3102-4440-8f5a-bfec3a7e9357','山茶','郭印','宋','宋诗','song-poetry','','[]','枯林獨秀染胭脂，不使群芳次第窺。',64,'全唐诗/poet.song.95000.json','["枯林獨秀染胭脂，不使群芳次第窺。", "月桂殷勤來並色，江梅寂寞許同時。", "霜飛雪舞終難挫，蝶隱蜂逃各未知。", "折得一枝聊慰眼，兒童拍手誤春期。"]'),
('aa92f282-2327-4dd0-b232-31637d45f236','上邵尚書','郭印','宋','宋诗','song-poetry','','[]','康節名天下，流芳到子孫。',204,'全唐诗/poet.song.95000.json','["康節名天下，流芳到子孫。", "素風門戶遠，皇極典型存。", "萬邑紛戎馬，十年辭帝閽。", "家艱俄茹苦，國難更堪論。", "上念長城寄，兵分細柳屯。", "紫泥頒詔綍，墨絰總戎軒。", "權重將軍幕，忠求孝子門。", "江朝南海濶，星拱北辰尊。", "智勇張良足，詩書郄縠敦。", "邊儲裁冗蠧，邦本厚黎元。", "士仰蘇天覆，人依趙日暄。", "勢增師旅氣，威礱虎狼魂。", "帳幄稽前箸，山河暫偃藩。", "精誠扶日月，談笑整乾坤。", "賤子欣蒙庇，先君舊感恩。", "駕轅憐病馬，投木笑窮猿。", "扶摇如可借，短翮待騰騫。"]'),
('5d25b784-cc38-4892-9246-7c0b74d946b3','和時升貽齋閣十韻','郭印','宋','宋诗','song-poetry','','[]','吏塗何就窘，士節要安常。',120,'全唐诗/poet.song.95000.json','["吏塗何就窘，士節要安常。", "逐物終迷路，看書免面牆。", "借鄰通隙地，對壁敞幽房。", "架插三冬史，爐薰一炷香。", "叢蘭分晚吹，疏竹罅晨光。", "濟難嗟無策，攻愁賴有方。", "稍知休簿領，誰暇剡封章。", "池草春成夢，案螢秋滿囊。", "良朋來款曲，佳句爲鋪張。", "功業奚須問，前賢擬杜康。"]'),
('88ae1fd2-7a12-4f56-a2cb-52f31d5f212b','時升詠雪效前人體盡禁比類顔色等字率予同賦用其韻','郭印','宋','宋诗','song-poetry','','[]','豐年真可必，時雪降今冬。',120,'全唐诗/poet.song.95000.json','["豐年真可必，時雪降今冬。", "飛霰紛紛集，同雲羃羃重。", "爐深添熾炭，寺遠隔疏鐘。", "先壓窗前竹，難分嶺上松。", "畫樓欺酒力，幽徑滅樵蹤。", "蓑笠看漁父，鉏犁慰老農。", "穿簷寒正苦，布野潤宜濃。", "梁苑思重賦，袁門想半封。", "龍沙猶張王，虎士莫驕慵。", "吾土端無恙，天公久見容。"]'),
('c1d8fb2c-a2b7-4d84-9599-6c79d4fd7739','春日即事','郭印','宋','宋诗','song-poetry','','[]','鳥詠短長句，花呈赤白章。',24,'全唐诗/poet.song.95000.json','["鳥詠短長句，花呈赤白章。", "化工非不巧，閑客笑春忙。"]'),
('6a54f02a-c398-4db1-8f11-85518f646cfd','苦熱和袁應祥用韋蘇州喬木生夏涼流雲吐華月爲題十小詩  其一','郭印','宋','宋诗','song-poetry','','[]','旱魃難除遣，南箕未可招。',24,'全唐诗/poet.song.95000.json','["旱魃難除遣，南箕未可招。", "安能颺雙舄，飛去學王喬。"]'),
('5e24dc96-ae76-4aff-9aef-853ba2d687d3','苦熱和袁應祥用韋蘇州喬木生夏涼流雲吐華月爲題十小詩  其二','郭印','宋','宋诗','song-poetry','','[]','山深隱䴥麏，江寒亂鷗鶩。',24,'全唐诗/poet.song.95000.json','["山深隱䴥麏，江寒亂鷗鶩。", "我欲從之遊，形骸元土木。"]'),
('5f94d11d-9eae-4e81-a11a-40d3a21aef27','苦熱和袁應祥用韋蘇州喬木生夏涼流雲吐華月爲題十小詩  其三','郭印','宋','宋诗','song-poetry','','[]','黄昏蚊撲撲，白晝蠅營營。',24,'全唐诗/poet.song.95000.json','["黄昏蚊撲撲，白晝蠅營營。", "天地一紅爐，幾人得聊生。"]'),
('ded08eda-3f2b-45b5-b525-ed226af5383b','苦熱和袁應祥用韋蘇州喬木生夏涼流雲吐華月爲題十小詩  其四','郭印','宋','宋诗','song-poetry','','[]','桃源渺何所，不知有冬夏。',24,'全唐诗/poet.song.95000.json','["桃源渺何所，不知有冬夏。", "堪笑市朝兒，炎涼爭代謝。"]'),
('e96859b5-1c54-4351-b172-4db1fc3b7656','苦熱和袁應祥用韋蘇州喬木生夏涼流雲吐華月爲題十小詩  其五','郭印','宋','宋诗','song-poetry','','[]','倚杖長松底，無風晝自涼。',24,'全唐诗/poet.song.95000.json','["倚杖長松底，無風晝自涼。", "吾廬傍林壑，嘉木聳千章。"]'),
('b2d84e09-1cee-43c7-8423-ac9397d2d747','苦熱和袁應祥用韋蘇州喬木生夏涼流雲吐華月爲題十小詩  其六','郭印','宋','宋诗','song-poetry','','[]','酷熱無從避，天風幾日秋。',24,'全唐诗/poet.song.95000.json','["酷熱無從避，天風幾日秋。", "寸陰不知惜，大火急西流。"]'),
('7702baf3-5f78-4b98-9066-15130bca5406','苦熱和袁應祥用韋蘇州喬木生夏涼流雲吐華月爲題十小詩  其七','郭印','宋','宋诗','song-poetry','','[]','赤日爍行路，青天絕片雲。',24,'全唐诗/poet.song.95000.json','["赤日爍行路，青天絕片雲。", "安得一丸藥，立返暍死魂。"]'),
('315a5bf7-8603-49a0-938c-d011c881125d','苦熱和袁應祥用韋蘇州喬木生夏涼流雲吐華月爲題十小詩  其八','郭印','宋','宋诗','song-poetry','','[]','中扃自清涼，穿鑿多門戶。',24,'全唐诗/poet.song.95000.json','["中扃自清涼，穿鑿多門戶。", "神凝一氣歸，陋哉勤納吐。"]'),
