('8d7feb5e-b59f-4cfc-9144-a0c104d311e4','鴉','郭印','宋','宋诗','song-poetry','','[]','勞生日日带煙歸，繞樹呼鳴擇一枝。',32,'全唐诗/poet.song.96000.json','["勞生日日带煙歸，繞樹呼鳴擇一枝。", "素月流天元未曉，何須半夜苦驚疑。"]'),
('725fbd5f-4be4-4d94-92b0-6886a608ab73','蛛網','郭印','宋','宋诗','song-poetry','','[]','結網謀生用意深，可憐微物有機心。',32,'全唐诗/poet.song.96000.json','["結網謀生用意深，可憐微物有機心。", "世間欺奪休驚詫，鬭巧争奇古至今。"]'),
('25b844f6-4252-4a2e-85e5-c7a8f21c6986','和曾端伯安撫勸道歌','郭印','宋','宋诗','song-poetry','','[]','保形保生保命，戒色戒酒戒茶。',238,'全唐诗/poet.song.96000.json','["保形保生保命，戒色戒酒戒茶。", "夜氣若要長在，晚食尤宜減些。", "養心莫如寡欲，存誠唯是閑邪。", "辨得天清地濁，吞取日精月華。", "寒灰便是發焰，枯根立可生芽。", "學者捨本逐末，病眼執著空花。", "罔窮聖道一轍，徒誦丹書五車。", "正似鍊和金鑛，何殊嚼蔗吞查。", "不知達人到此，元始浩刼爲家。", "燕坐能事畢矣，行遍海角天涯。", "鑑明不受微垢，玉潔靡見纖瑕。", "視軒冕如桎梏，棄財寶若泥沙。", "曲江一輪秋桂，豈容霧掩雲遮。", "盤旋火龍水虎，和合陰汞陽砂。", "真身自然騰化，駕鳳高凌紫霞。", "哀哉傍門小法，作用千種參差。", "箇箇辛苦無成，白首空自悲嗟。"]'),
('38782ab3-ddd7-4d90-821b-4cbce5672d32','和曾端伯安撫養生歌','郭印','宋','宋诗','song-poetry','','[]','大道靡涉多歧，迷塗爭求捷徑。',210,'全唐诗/poet.song.96000.json','["大道靡涉多歧，迷塗爭求捷徑。", "采御未免摇精，道引止能祛病。", "服食一藏偏強，燒煉千金或罄。", "紛紛小法小功，往往匪清匪凈。", "那知反照內觀，専在致虛守静。", "況始生之神氣，即本來之性命。", "源深其流必長，根固其葉斯盛。", "刳心自契真空，減息終成大定。", "謂虛固可集道，非睿不能作聖。", "夫人受中以生，惟我獨得其正。", "斡旋天地之機，提挈陰陽之柄。", "每嗟坐禪學佛，有似磨塼作鏡。", "聚塊積塵非理，槁木死灰失性。", "直須大用見前，方是真仙究竟。", "不生故能生生，古語由來堪聽。"]'),
('5de6196e-e054-4719-bfe2-b36e50e67d35','再和二首  其一','郭印','宋','宋诗','song-poetry','','[]','魚跳須過龍門，虎驟不從兔徑。',210,'全唐诗/poet.song.96000.json','["魚跳須過龍門，虎驟不從兔徑。", "上士聞道勤行，豈以難能爲病。", "固守滿堂之珍，肯使如瓶之罄。", "對境一念不萌，應緣六根皆凈。", "剛克本自沉潛，動直先由専静。", "達理必明其權，盡性以至於命。", "鼎中水騰火降，爐內陰衰陽盛。", "神功妙合虛無，天光潛發泰定。", "豈惟出塵離俗，便可超凡入聖。", "自憐末學多方，未得大中至正。", "莫知斡運帝車，寧解執持坤柄。", "丹經苦閱殘編，素髮羞看明鏡。", "要求直截真機，速了圓明正性。", "何妨萬兩金成，已是一生事竟。", "至言今許發蒙，三沐三薰諦聽。"]'),
('75f32ba9-3dce-4cf0-a81f-f12b4ce81fe0','再和二首  其二','郭印','宋','宋诗','song-poetry','','[]','涉海必假舟航，登山當尋蹊徑。',210,'全唐诗/poet.song.96000.json','["涉海必假舟航，登山當尋蹊徑。", "每歎修身錯路，譬如飲藥加病。", "逢人須是問津，有心未免擊磬。", "況遇先覺先知，早明不垢不凈。", "七情渙若冰雪，一性湛然淵靜。", "虛無體道合真，恬淡樂天知命。", "外之寇賊消亡，內焉邦家昌盛。", "初守一以處和，乃無事而生定。", "教不倦稱乎仁，德分人謂之聖。", "故玉非琢不成，惟木從繩而正。", "要明師指藥物，藉元神爲本柄。", "大道多歧亡羊，至人用心若鏡。", "何妨常善救物，免使大惑易性。", "門庭既已趣入，根株亦須窮竟。", "直至出死超生，方知聾者善聽。"]'),
('a91d8e00-8284-48e0-84f8-51bbb93f8e26','珊瑚花','郭印','宋','宋诗','song-poetry','','[]','彼美珊瑚樹，扶疏着絳英。',48,'全唐诗/poet.song.96000.json','["彼美珊瑚樹，扶疏着絳英。", "佳名爲世重，貴相亦天生。", "日裏顔尤耐，人來眼目眼。", "貧家還有此，玉石謾誇爭。"]'),
('c1c4c5f7-75d2-4aea-b402-7ef228aa163e','按部留小詩命男明復同賦','郭印','宋','宋诗','song-poetry','','[]','地涉雲安境，山居燕子龕。',48,'全唐诗/poet.song.96000.json','["地涉雲安境，山居燕子龕。", "簾垂看急溜，蓋偃得修楠。", "牢落前賢蹟，光明古佛庵。", "幽禽知客至，一一解玄談。"]'),
('29aa59da-a396-4366-86f2-50d5573e7d58','夔州','郭印','宋','宋诗','song-poetry','','[]','夔子巴峽衝，風物異蜀境。',180,'全唐诗/poet.song.96000.json','["夔子巴峽衝，風物異蜀境。", "城居版作屋，江汲地無井。", "四郊乏平原，冢墓緣山嶺。", "人傳蚯蚓瘴，俗飲茱萸茗。", "女婦盡背籃，老弱多垂癭。", "試問何所因，食彼山泉冷。", "巖栖固不少，亦有長細頸。", "似聞此土人，其性皆悍獷。", "胸中忿畜者，甕盎成項領。", "是說理有之，云胡不自省。", "我來適夏初，端坐愁日永。", "況經六七月，官舍如沸鼎。", "有雨未沾濡，蔬茹空盤皿。", "清泉不敢喫，僅免河魚梗。", "投紱歸去來，吾鄉等箕潁。"]'),
('c8d51d3e-ee70-45aa-8f5a-89c620312a82','大雪與同舍生飲太學初筮齋','陳東','宋','宋诗','song-poetry','','[]','飛廉強攪朔風起，朔雪飄飄灑中土。',158,'全唐诗/poet.song.96000.json','["飛廉強攪朔風起，朔雪飄飄灑中土。", "雪花着地不肯消，億萬蒼生受寒苦。", "天公剛被陰雲遮，那知世人凍死如亂麻。", "人間愁歎之聲不忍聽，誰肯採摭傳說聞達太上家。", "地行賤臣無言責，私憂過計如杞國。", "揭雲直欲上天門，首爲蒼生訟風伯。", "天公倘信臣言憐世間，開陽闔陰不作難。", "便驅飛廉囚下鄷都獄，急使飛雪作水流潺潺。", "東方日出能照耀，坐令和氣生人寰。"]'),
('6cb1c6f7-6fa6-4d2f-b6e7-46ef2055a85f','律詩三十韻僅存二韻','陳東','宋','宋诗','song-poetry','','[]','山嶽遭埋沒，乾坤着蔽蒙。',24,'全唐诗/poet.song.96000.json','["山嶽遭埋沒，乾坤着蔽蒙。", "已成堆積勢，漸費掃除功。"]'),
('8f37d1fd-f978-4d1f-8d3a-2bb8f3f361ee','自許昌如蔡與石士繇酌别一章','陳東','宋','宋诗','song-poetry','','[]','太學諸生出許昌，抱關夫子特相將。',96,'全唐诗/poet.song.96000.json','["太學諸生出許昌，抱關夫子特相將。", "輕衣短帽秋風裏，瘦馬羸童古柳傍。", "黄葉翻翻慘離思，濁醪沃沃澆愁腸。", "欲知此别情懷惡，正是平生氣味長。", "公歸且作詩書伴，我去還依鴻雁行。", "酒闌徑渡石橋子，回首高城揮夕陽。"]'),
('10216721-bac2-4886-9c57-6b522a76652a','與虞章舜卿二表弟季明游兼勝亭有作三律  其一','陳東','宋','宋诗','song-poetry','','[]','危亭兼雅勝，勝景足奇觀。',48,'全唐诗/poet.song.96000.json','["危亭兼雅勝，勝景足奇觀。", "湖水涵天入，山雲带雨蟠。", "千松偃夜月，萬竹撼春寒。", "玉井汲甘冷，塵緣那得干。"]'),
('3bc23720-df1e-4749-a547-d3bd0e887484','與虞章舜卿二表弟季明游兼勝亭有作三律  其二','陳東','宋','宋诗','song-poetry','','[]','野曠湖山遠，林深松竹幽。',48,'全唐诗/poet.song.96000.json','["野曠湖山遠，林深松竹幽。", "舊題看壁立，前事逐萍浮。", "荏苒荒三徑，依稀度九秋。", "故人應念我，雅會莫遲留。"]'),
('3fd1db1c-accc-40ac-935f-353c23a2a4a6','與虞章舜卿二表弟季明游兼勝亭有作三律  其三','陳東','宋','宋诗','song-poetry','','[]','三子皆吾弟，阿章才更豪。',48,'全唐诗/poet.song.96000.json','["三子皆吾弟，阿章才更豪。", "風流江左舊，句法杜陵高。", "雅志在五馬，壯心連六鰲。", "時哉偶未與，日且醉金舠。"]'),
('932de295-2af3-44a4-b3e3-2ce0613d74d1','次韻同舍李冲壽夜坐','陳東','宋','宋诗','song-poetry','','[]','時引金盃拔劍看，光芒高徹斗牛寒。',64,'全唐诗/poet.song.96000.json','["時引金盃拔劍看，光芒高徹斗牛寒。", "要令世事從心淡，可謂人情徹鼻酸。", "經術豈應窮皓首，文章何用苦雕肝。", "吾徒行與功名會，莫作覊人日夜歎。"]'),
('4f0b90f5-9233-436e-8506-0589e775b28d','秋夜獨坐有感一章奉呈師說令尹奉議光明主簿虞章','陳東','宋','宋诗','song-poetry','','[]','依依客館夜燃膏，子夜覊愁無處逃。',64,'全唐诗/poet.song.96000.json','["依依客館夜燃膏，子夜覊愁無處逃。", "閑炷爐香聽夜雨，快斟盃酒讀離騷。", "休驚時節云何速，獨弔古人殊不遭。", "一陣曉寒催畫角，朝來爽氣碧山高。"]'),
('ef994e7d-4d19-4689-bcf0-5766dac21dbd','彦雋母挽章二首  其一','陳東','宋','宋诗','song-poetry','','[]','人生五福古難全，天賦夫人獨不偏。',64,'全唐诗/poet.song.96000.json','["人生五福古難全，天賦夫人獨不偏。", "內行無慚詩婦孝，母儀何啻穆姜賢。", "庭幃已歎芳魂獨，宗族空留舊事傳。", "惟有南陔多少恨，忍看松柏鎖寒烟。"]'),
('28f4c63a-ce3c-4851-a189-7804a8396e9d','彦雋母挽章二首  其二','陳東','宋','宋诗','song-poetry','','[]','少馳賢孝譽，來配潁川家。',48,'全唐诗/poet.song.96000.json','["少馳賢孝譽，來配潁川家。", "雖奪共姜誓，曾無賢母瑕。", "一鄉蒙愛惠，百口藉生涯。", "享福踰中壽，歸與勿怨嗟。"]'),
('be470a7d-21e2-4da5-8158-ba995257a29e','穎川二絕  其一','陳東','宋','宋诗','song-poetry','','[]','我家本出穎川住，幾世不曾歸潁川。',32,'全唐诗/poet.song.96000.json','["我家本出穎川住，幾世不曾歸潁川。", "今我暫來忽暫去，太丘風流誰與傳。"]'),
('6482b73c-7a2d-4258-a69d-ea5a8c329631','穎川二絕  其二','陳東','宋','宋诗','song-poetry','','[]','我來穎川何所見，青青古柏古城傍。',32,'全唐诗/poet.song.96000.json','["我來穎川何所見，青青古柏古城傍。", "知是荀陳手親植，令人不覺淚行行。"]'),
('ad4cd494-d551-4ed9-af4f-839624b71cb9','次韻士繇惜别','陳東','宋','宋诗','song-poetry','','[]','男兒自有四方志，離别豈能動剛腸。',32,'全唐诗/poet.song.96000.json','["男兒自有四方志，離别豈能動剛腸。", "功名未遂身未死，白眼青青頻舉觴。"]'),
('98765bcb-14ad-4d39-9374-681cb82df91f','次韻邵予可彈琴二首  其一','陳東','宋','宋诗','song-poetry','','[]','雷公徽玉粲明星，照出師襄指下聲。',32,'全唐诗/poet.song.96000.json','["雷公徽玉粲明星，照出師襄指下聲。", "可憐此地無人識，喚作新來黑瘦筝。"]'),
('214275bf-688f-4d25-8dc1-e4ce96e036d0','次韻邵予可彈琴二首  其二','陳東','宋','宋诗','song-poetry','','[]','漫說朱絃大古清，政無矇瞽在周庭。',32,'全唐诗/poet.song.96000.json','["漫說朱絃大古清，政無矇瞽在周庭。", "高山流水本無事，安用區區里耳聽。"]'),
('89b33eb3-8423-492d-a4e3-842f291ebb01','與士繇遊金山翼日分袂二絕  其一','陳東','宋','宋诗','song-poetry','','[]','早别金山恰曉鐘，離帆分破一江風。',32,'全唐诗/poet.song.96000.json','["早别金山恰曉鐘，離帆分破一江風。", "瓜洲渡口波聲遠，後夜相思明月中。"]'),
('47822774-4962-4698-b19c-4a7a8670b3e4','與士繇遊金山翼日分袂二絕  其二','陳東','宋','宋诗','song-poetry','','[]','京口瓜洲一水間，秋風重約到金山。',32,'全唐诗/poet.song.96000.json','["京口瓜洲一水間，秋風重約到金山。", "江山自爲離人好，不爲離人數往還。"]'),
('0735879d-b77f-4801-be32-3b7ce1a6730c','題吳公輔庵','陳東','宋','宋诗','song-poetry','','[]','一徑縈迴屋數間，我來聊欲寄清閑。',32,'全唐诗/poet.song.96000.json','["一徑縈迴屋數間，我來聊欲寄清閑。", "道人杖履知何處，空鎻烟霞萬疊山。"]'),
('0fbb6505-3646-40ca-86e2-56fb0e0e6716','茶','陳東','宋','宋诗','song-poetry','','[]','偏愛君家碧玉盤，建溪雲腳未嘗亁。',32,'全唐诗/poet.song.96000.json','["偏愛君家碧玉盤，建溪雲腳未嘗亁。", "書生自恨無金換，聊以詩章乞數團。"]'),
('5283b902-3a81-4108-b4a6-fccfdd3481ab','送友人喪二絕  其一','陳東','宋','宋诗','song-poetry','','[]','欲認青帘索酒嘗，俄驚丹旐送君喪。',32,'全唐诗/poet.song.96000.json','["欲認青帘索酒嘗，俄驚丹旐送君喪。", "呂莊編戶傷心切，愁對清風想杜康。"]'),
('b927e281-e9ec-4a51-ae16-0a8e39e22c8c','送友人喪二絕  其二','陳東','宋','宋诗','song-poetry','','[]','初成大廈勢巍巍，有意于門駟馬車。',32,'全唐诗/poet.song.96000.json','["初成大廈勢巍巍，有意于門駟馬車。", "未乾壁土君先已，賀燕翻隨弔鶴飛。"]'),
('82adbab5-4f8f-4192-ba54-5811da430635','徐氏哀詞代作','陳東','宋','宋诗','song-poetry','','[]','憶昔常隨祖母過，登堂共慶尚垂胡。',32,'全唐诗/poet.song.96000.json','["憶昔常隨祖母過，登堂共慶尚垂胡。", "十年未遠皆流蕩，地下相逢果有無。"]'),
('d66670c4-5721-450b-894b-ccdb3c50958f','和邵予可賣俸豆','陳東','宋','宋诗','song-poetry','','[]','休論斥鹵與膏腴，豆藿連阡稻麥無。',32,'全唐诗/poet.song.96000.json','["休論斥鹵與膏腴，豆藿連阡稻麥無。", "舉世紛紛寶魚目，投人慎勿以明珠。"]'),
('53bdcd60-2793-43bc-b8f2-9fcbdc7c7dd6','謁王樂道之子聞方飯絕客一絕','陳東','宋','宋诗','song-poetry','','[]','晚生恨不及前輩，來訪諸郎觀典型。',32,'全唐诗/poet.song.96000.json','["晚生恨不及前輩，來訪諸郎觀典型。", "吐握風流何寂寞，滿林風竹自秋聲。"]'),
('dc6485d6-4fea-464d-abf6-a84beb254a51','詠桃花菊一章','陳東','宋','宋诗','song-poetry','','[]','潘郎嘗望塵，陶令亟避俗。',156,'全唐诗/poet.song.96000.json','["潘郎嘗望塵，陶令亟避俗。", "胸中定何如，清濁在一矚。", "河陽艶桃春，彭澤鬰秋菊。", "所好邈如許，二子殊品目。", "詩人易評量，忍使混衡斛。", "當使冰鑑磨，要遣鬚眉燭。", "勿容脂粉姿，濫入珪璋錄。", "神仙真渺茫，浪說武陵谷。", "不如臨清潭，飲水樂自足。", "誰令春雨紅，點污秋株綠。", "寒根豈無知，風霜怒應蓄。", "令尹非安仁，腰带肯輕束。", "脫巾漉酒漿，黄花泛新馥。"]'),
('2be885b5-fa6d-48f0-8f1a-68c99e8af770','春日偶題','陳東','宋','宋诗','song-poetry','','[]','驅除睡思茶甌外，收拾春光酒盞中。',32,'全唐诗/poet.song.96000.json','["驅除睡思茶甌外，收拾春光酒盞中。", "萬種窮愁渾不問，世間此樂幾人同。"]'),
('57943b43-1721-4da5-8bcc-4f2193b958ea','跋黄魯直買米帖','陳東','宋','宋诗','song-poetry','','[]','廣文弦歌飯不足，要是古來賢達人。',32,'全唐诗/poet.song.96000.json','["廣文弦歌飯不足，要是古來賢達人。", "山谷有錢能買米，比之魯公殊未貧。"]'),
('85b0aaae-34b9-4f41-a5ef-d742c1dfcb1f','尹館作此覓酒召李順之飲','陳東','宋','宋诗','song-poetry','','[]','今日天色惡，酒壺恰已空。',120,'全唐诗/poet.song.96000.json','["今日天色惡，酒壺恰已空。", "何來進童子，挈榼問主翁。", "主翁正對客，兀坐書堂中。", "諸生功課畢，鼔瑟歌醉翁。", "愛酒欲出門，杖頭無青銅。", "春衣典又盡，搜索計已窮。", "酒興不可遏，不免作詩呼。", "進童空壺挈，將納宅庫爲。", "我卻致䨥灰，紅得酒須尋。", "愛酒伴更煩，與召隴西翁。"]'),
('bf1ad083-ea92-45d4-9607-be8c3052840d','送黄仲達歸温州仍寄諸友','陳東','宋','宋诗','song-poetry','','[]','長安市上喜相逢，傾蓋恩情久要同。',64,'全唐诗/poet.song.96000.json','["長安市上喜相逢，傾蓋恩情久要同。", "幾載暌違勞想夢，一樽邂逅寫情衷。", "家山柑橘正酣露，江岸帆檣忽飽風。", "歸去借聲詢舊友，項髯方浪薛芹宫。"]'),
('7735c5de-72db-4caa-8791-d08bfdd2dfc6','謝温州黄仲達送鄂州瓜虀','陳東','宋','宋诗','song-poetry','','[]','黄夫子從汶上來，三束瓜虀送風土。',64,'全唐诗/poet.song.96000.json','["黄夫子從汶上來，三束瓜虀送風土。", "應知我亦困虀鹽，肯食沽酒與市脯。", "食肉者鄙無遠謀，甲第紛紛何足數。", "飯蔬飲水真樂哉，千古風流想尼父。"]'),
('aaa2cba6-d66d-4afa-844c-85ec58b8f942','夜飲二絕  其一','陳東','宋','宋诗','song-poetry','','[]','笋芽鵝炙殊可口，明月清風不着錢。',32,'全唐诗/poet.song.96000.json','["笋芽鵝炙殊可口，明月清風不着錢。", "坐對青州一從事，共君今夜不須眠。"]'),
('abff783b-a980-4c0d-b32b-c350ec1d4581','夜飲二絕  其二','陳東','宋','宋诗','song-poetry','','[]','欣然有意引陶潛，此意何妨俗士聯。',32,'全唐诗/poet.song.96000.json','["欣然有意引陶潛，此意何妨俗士聯。", "三百青錢亦希有，速將趁取夜厭厭。"]'),
('b2136ebe-409d-4573-9889-bd9aa5c7d279','輓修撰先生','何元泰','宋','宋诗','song-poetry','','[]','在昔虞庠日，嘗陪陳少陽。',48,'全唐诗/poet.song.96000.json','["在昔虞庠日，嘗陪陳少陽。", "詞傾三峽水，忠烈九秋霜。", "藥石塵丹扆，瑯玕寶皂囊。", "後來門下士，多有紫薇郎。"]'),
('d92fd158-21af-4003-839c-3ca7537af81a','山西行','沈與求','宋','宋诗','song-poetry','','[]','山西徤兒好身手，氣如車輪膽如斗。',384,'全唐诗/poet.song.96000.json','["山西徤兒好身手，氣如車輪膽如斗。", "十五射獵少年場，戲格黄羆同拉朽。", "二十竄名尺籍中，鐵馬追風快馳走。", "臂弓腰箭了一生，只喜論攻不論守。", "兵符夜半出轅門，將軍令肅誰敢後。", "自誇豪健天下無，誓爲官家掃群醜。", "蠻夷共事古來危，監軍巧落他人機。", "黑山未靖黄河沸，邉塵倐忽連紫微。", "長驅中州斥候絕，已聞飲馬金明池。", "种家猛將忠貫日，髮上衝冠頤指揮。", "主辱偷生事不武，壯士裂眦争相隨。", "東跨潼關達上國，城頭夜插將軍旗。", "諸軍下馬拜吾父，請成退舍纔有期。", "肉食謀國帝子質，勒兵不動護送之。", "壯士束手猛將死，敵來侮人猶小兒。", "明明二聖堯舜主，天翻地坼徒爾爲。", "天翻地坼徒爾爲，北望血淚滂兩頤。", "真人中興似光武，赤眉青犢折箠笞。", "一呼奮擊肯效死，風鶴尚信驚王師。", "嗚呼何爲背征討，紅帕兜鍪半爲盜。", "東家昨夜虜小姑，西婦朝逢握刀笑。", "錦衣玉食事奢侈，翠眉紅頰資彊暴。", "黄屋今懷旰食憂，忍與豺狼活蓬藋。", "時危宜爾悍且驕，側耳試聽哀痛詔。"]'),
('97d364dc-866c-45a5-b546-f31dd8a7621d','次韻劉殿院贈錢圃翁','沈與求','宋','宋诗','song-poetry','','[]','少日從畦丁，頗悟園官理。',156,'全唐诗/poet.song.96000.json','["少日從畦丁，頗悟園官理。", "菘韭記春秋，蔬食聊爾耳。", "十年困塵埃，幽事同脱屣。", "一飽不可謀，清痩只如此。", "仰止長城翁，趣尚兩奇偉。", "弱冠事筆耕，俛仰行六紀。", "晚以圃自娛，扶鋤寄深喜。", "柔風蔬甲怒，細雨蘭芽美。", "小摘定可供，餘事不掛齒。", "那復肯着屐，而一到城市。", "爲計一何疏，行須傳高士。", "木茹忌太潔，肉食忌太鄙。", "安得從公游，遠傲於陵子。"]'),
('16e0fd05-ec3b-4003-94b1-ed0947e6fedb','遊玲瓏山因訪朱氏草堂','沈與求','宋','宋诗','song-poetry','','[]','平生丘壑心，餘事不掛目。',288,'全唐诗/poet.song.96000.json','["平生丘壑心，餘事不掛目。", "藜杖南山來，要使富幽矚。", "異哉小玲瓏，蟠峙蒼弁腹。", "修藤結懸崖，飛溜響空曲。", "伏石卧虎狀，騰拏雜奔鹿。", "砑然互吞吐，側路劣容足。", "拂拭古蘚紋，字刻翳新綠。", "標榜玲瓏名，奇怪殆天屬。", "捫蘿上絕頂，坦坦類平陸。", "俯首瞰來蹤，穹然在幽谷。", "傳聞昔逋客，誅茅此營屋。", "清魂不可招，千載想遺躅。", "我思造物巧，妙供幽人祿。", "揮斤役山祗，斵此一拳玉。", "雲窗與霧閣，一一相亘屬。", "豈無部曲衆，猿鶴即更僕。", "豈無節旄貴，松檜自張纛。", "此事久棄置，蛛絲網巖麓。", "翩翩佳公子，心古韻不俗。", "駕言脱華簮，兹焉卜幽築。", "終日面巑岏，世故豈容觸。", "指點空洞姿，喜氣政堪掬。", "挾策校昔游，健步念須續。", "亦有招隱詩，薄暮不可讀。"]'),
('ebdc4b4b-2841-444e-b855-8066ba05d1f2','奉陪安守登膴原觀','沈與求','宋','宋诗','song-poetry','','[]','江南多佳山，駢首闖城郭。',168,'全唐诗/poet.song.96000.json','["江南多佳山，駢首闖城郭。", "緬懷在坦夷，要使一見廓。", "邦侯王事餘，幽致到丘壑。", "散策占城陰，含睇及民瘼。", "愛此郊原平，膴膴富耕穫。", "飛觀儵下臨，丹碧盪霄堮。", "野色四座浮，胸次潛領略。", "千畦雲弄黄，歲事初不惡。", "斗酒行勞農，歡謠入酺醵。", "勝地惡發揮，波神覆爲虐。", "蕭辰誰與娛，一笑寄華酌。", "落日耀旍旗，輕飇漾簾幕。", "卷白起壽公，歌聲渺林薄。", "老農止勿狂，嗣歲有真約。"]'),
('8bcba064-5193-4cf4-9715-f549a0150650','觀網魚','沈與求','宋','宋诗','song-poetry','','[]','暗雨垂垂梅欲黄，春山吐源春漲狂。',112,'全唐诗/poet.song.96000.json','["暗雨垂垂梅欲黄，春山吐源春漲狂。", "雪鱗頳尾泝流上，吹濤噴浪能奔忙。", "魚師布網名白大，萬目井井連重綱。", "聯艘絕流勢甚武，遮羅初若無留藏。", "大魚巳得小魚棄，要使遺育充陂塘。", "鰥鮞安用誤回避，鰕蟹亦復虛跳梁。", "寧知不比綸索手，欲以巧餌空滄浪。"]'),
('bb0944f7-a839-4f27-8a8b-c7a7d7d39add','子修步屧相過屬疾不能倒屣戲贈','沈與求','宋','宋诗','song-poetry','','[]','簿書日在手，佳思挽不留。',144,'全唐诗/poet.song.96000.json','["簿書日在手，佳思挽不留。", "而能痛撥置，時來訪清幽。", "古木占城陰，一曲縈寒流。", "落影插清泚，綠蔭亦巳稠。", "結亭坐蟠石，傲兀忘拘囚。", "雄談功名外，俊氣横九州。", "事故未應爾，長恐坐阻修。", "造物小兒相，妒我得暫休。", "河魚竟中潰，午枕猶扶頭。", "雙鳬飛舄聲，歷歷過牆陬。", "此興豈復淺，何當起從游。", "試令開丈室，子能問疾不。"]'),
('20a7182f-e79d-48d4-9dad-62720eeb9bcf','寄題淄川王景發肯構堂','沈與求','宋','宋诗','song-poetry','','[]','深林藝松柏，不數櫟與樗。',192,'全唐诗/poet.song.96000.json','["深林藝松柏，不數櫟與樗。", "坐待十畝陰，等爲匠氏儲。", "寧復知種德，責報不厭徐。", "名令後必大，善積慶有餘。", "於焉望豐屋，政可增修閭。", "王孫世東州，奕奕盈簮裾。", "金埒通里巷，珠樹連堦除。", "賢哉景發甫，爽爽衆莫如。", "直氣薄霄漢，妙語鏘瓊琚。", "定知磊落人，一見懷抱攄。", "謂我架華堂，映發先人廬。", "掲名取肯構，蓋念經營初。", "堂前植桃李，堂上羅詩書。", "桃李意取適，詩書計非疏。", "諸郎自蘭玉，舌耕起菑畬。", "吾詩以爲箴，會見聯高車。"]'),
('105739ac-c9ec-4ede-ac48-16c5b5289913','何子楚爲范明倫賦九疑石石吾不及見也讀詩可以知其巑岏秀峙之狀吾累卞峰石爲小寒林興寄不淺用其韻并及之','沈與求','宋','宋诗','song-poetry','','[]','峩弁千峰倚天碧，上有修筠材可篴。',128,'全唐诗/poet.song.96000.json','["峩弁千峰倚天碧，上有修筠材可篴。", "月明三弄面巉巖，驚起哀猿啼峭壁。", "兒童斵石攅青瑤，寒林蕭蕭吹墮樵。", "坐令結習落幽夢，芒鞋竹杖歸路遙。", "覺來隻影徒相守，哦子清詩筆如口。", "眼中何必小玲瓏，仿像九疑當戶牖。", "神丹已失大江漘，誰與安期追後塵。", "分天隔日不可到，使我目斷蒼梧雲。"]'),
('c58915ec-585f-4350-b17f-faab655ca7f5','次韻題沈傳曜痩節堂','沈與求','宋','宋诗','song-poetry','','[]','平生一字不療饑，誰云穅覈能瓠肥。',112,'全唐诗/poet.song.96000.json','["平生一字不療饑，誰云穅覈能瓠肥。", "牙籤玉筯五鼎食，是中有趣非錢癡。", "萬事顛倒絕可嗤，此腹卻受將軍譏。", "吾宗酷似騎曹掾，俗物紛紜那復看。", "眼中但有瀟洒侯，高節亭亭真老伴。", "山澤形容坐一癯，相要檢校還丹書。", "食薇飲水笑多事，知君此計誠非疏。"]'),
('eca7f39d-2461-4931-ad70-7724936cc9ab','劉行簡見借詩稿以長句歸之','沈與求','宋','宋诗','song-poetry','','[]','文章偏忌聲名早，富貴政須門第好。',176,'全唐诗/poet.song.96000.json','["文章偏忌聲名早，富貴政須門第好。", "了知二物不相關，風月膏粱兼者少。", "劉郎天韻真不凡，飛騰宜在蓬萊島。", "年來窮愁已到骨，只有珠璣落殘稿。", "紛紛餘子何能追，定向詩壇分六纛。", "造物小兒亦薄相，浪付繁華給揮掃。", "卻令徑坐詩人窮，只與清冷消熱惱。", "向來狗監非同邑，渇盡文園尚傭保。", "九原千古忽可作，如君自是不枯槁。", "茅齋夜誦誰得聞，咄咄空能訴穹昊。", "請君更作昇天行，勿使貧胡彊知寶。"]'),
('cb360aed-dd8a-441c-8bf8-a404d76b795e','送章文虎秀才歸荆南','沈與求','宋','宋诗','song-poetry','','[]','我生本吳儂，搦筆追楚些。',120,'全唐诗/poet.song.96000.json','["我生本吳儂，搦筆追楚些。", "佳人脱塵屣，幽韻恥獨和。", "君家楚江湄，詞語亦頓挫。", "學海富探討，渠數百紙過。", "春風歸鳳城，櫑具恰解駄。", "此地初識君，細語輒三賀。", "冉冉歲巳遒，雲山憶高卧。", "翩然理歸裝，餘事等棄唾。", "文圍久堅壁，定恐一戰破。", "行矣儻復來，憑將楚詞課。"]'),
('7d9a9907-c6ff-4b28-9d75-3704a558407f','次韻曾守懷玲瓏山','沈與求','宋','宋诗','song-poetry','','[]','泉石有膏肓，料理費和緩。',204,'全唐诗/poet.song.96000.json','["泉石有膏肓，料理費和緩。", "風埃客子游，夢想略相半。", "端如饜羊酪，投匕念鄉饌。", "懷哉小玲瓏，舊賞記酣宴。", "玉女下雲窗，輕我年未冠。", "誅茅老三間，此意已懸斷。", "少須草堂資，兩足那可絆。", "謝公愛東山，自結尋幽伴。", "詩筒忽相先，紙價豈容賤。", "流傳從使君，感此歸思亂。", "擷蘭躡危根，潄石俯長磵。", "野性等麋鹿，百嗜寧食薦。", "攬衣中夜興，測漏疾流盼。", "扃步愧駑筋，卑飛傷短翰。", "正使屐齒折，未救斧柯爛。", "時節脱復徂，遲莫空浩歎。", "何當脂下澤，去路鬰交貫。"]'),
('913d17bf-db50-4530-b0d9-aa02cf36b0dd','何亨老築堂里第榜曰安虛蓋取司馬子微不受外不逐外之說屬某賦詩以見意云','沈與求','宋','宋诗','song-poetry','','[]','幻境如群狙，喜怒眩名實。',204,'全唐诗/poet.song.96000.json','["幻境如群狙，喜怒眩名實。", "憐渠千刼迷，墮此一念失。", "世路波濤翻，時事風雨疾。", "胡爲隨物遷，坐此方寸窒。", "使君超世姿，軒裳起儒術。", "神交赤城仙，妙解窮隱密。", "向來心泰然，初不計升黜。", "危堂榜新顔，要以名自律。", "窗扉敞深明，空華亂初日。", "變滅驚須臾，蔽虧隔纖悉。", "了知內觀融，天光發虛室。", "山林猿鶴儔，廊廟鵷鸞匹。", "静躁塗或殊，出處心本一。", "清都五城開，真仙羅輔弼。", "行矣朝紫皇，啟沃造前膝。", "功名戲劇成，志願談笑畢。", "它年容買鄰，儻不傲蓬蓽。"]'),
('5c7f429a-dbb6-428f-a59e-f9af5861000c','次韻何子楚食櫻桃','沈與求','宋','宋诗','song-poetry','','[]','輕衫駿馬飛彈丸，上林花開紛繡團。',128,'全唐诗/poet.song.96000.json','["輕衫駿馬飛彈丸，上林花開紛繡團。", "御厨賜筍未解籜，山櫻亦復登金盤。", "宗廟薦新勤玉路，凡果紛紛不論數。", "風清日美雨絲收，朱實烘春燃綠樹。", "筠籠採擷價萬錢，北人羊酪雅所便。", "自從燕罷曲江曲，五湖十載身回旋。", "已作孤蓬任流轉，萬顆徒勞野人獻。", "故無清夢大明宫，醉倚酡顔浮玉盌。"]'),
('cac146d5-f151-4229-bc9a-2aee6e7d8192','擬古','沈與求','宋','宋诗','song-poetry','','[]','日月雙高懸，朝昏自升沈。',144,'全唐诗/poet.song.96000.json','["日月雙高懸，朝昏自升沈。", "有如轉轆轤，引絙環相尋。", "而我生其間，所閲幾古今。", "爾來三十年，又作裘氏吟。", "眠飯寄編簡，此身疑白蟫。", "皇皇走四方，誰是真知音。", "語欲離舌本，退縮翻如瘖。", "涉世聊爾耳，依阿亦何心。", "託質既巳迂，自謂百鍊金。", "恥作渭水鈎，寧爲太阿鐔。", "用捨安所之，齒髪忽已侵。", "日月不我留，潸然涕盈襟。"]'),
('7fb20477-b81f-4772-98b5-5d507aee331b','次韻黄子虛同飲葛次顔家釀玉友','沈與求','宋','宋诗','song-poetry','','[]','先生早年忘掃白，嬾飯青精借顔色。',160,'全唐诗/poet.song.96000.json','["先生早年忘掃白，嬾飯青精借顔色。", "獨餘驩伯爲友朋，熟不暇篘巾自瀝。", "何須引泉連百井，飲若長虹太豪猛。", "細斟玉筯滑無聲，酌我應憐官獨泠。", "奇篇更寫陟釐黄，逼人心地生清涼。", "了知二事盡家法，眼饞徑索銀瓶嘗。", "我老華池少滋液，年來愛酒如偷蜜。", "陶然一醉樂未央，此外要知俱長物。", "相期徑造君勿違，坐得名勝從忘歸。", "公侯似聞倦設醴，穆生正恐同分攜。"]'),
('736ac45a-a315-4717-b267-7b66bf64b108','次韻李元叔田邦鎮唱酬之什  其一','沈與求','宋','宋诗','song-poetry','','[]','李侯少年真自喜，收名擬擅東南美。',96,'全唐诗/poet.song.96000.json','["李侯少年真自喜，收名擬擅東南美。", "大科異等不作難，堂堂奏賦明光裏。", "眼看斗粟飽侏儒，空腸殷雷歸著書。", "胸中未減食牛氣，出手一擲當成盧。", "只今聊問復何如，要辨蟫蠧資軒渠。", "刺頭文字亦瑣碎，澤吻快意回焦枯。"]'),
('5cb8b774-506d-4b62-a87d-2055aa9a3956','次韻李元叔田邦鎮唱酬之什  其二','沈與求','宋','宋诗','song-poetry','','[]','大雅寂寥誰發喜，逆折波瀾須子美。',96,'全唐诗/poet.song.96000.json','["大雅寂寥誰發喜，逆折波瀾須子美。", "晚分一派大江西，約束曹劉歸句裏。", "武安耳孫有臞儒，載行無多一束書。", "蹇驢破帽踏城市，腰間蒯維鳴湛盧。", "叫閽自薦久未偶，淮南叢桂猶關渠。", "雕鑴戲出鄉學餘，掩面笑余詩井枯。"]'),
('a4feef17-0e44-4f7d-af42-1cf8eb261201','讀成士瑴詩卷和其書事一章','沈與求','宋','宋诗','song-poetry','','[]','長年賦子虛，狗監絕同里。',60,'全唐诗/poet.song.96000.json','["長年賦子虛，狗監絕同里。", "杯水聊自酬，博此一笑喜。", "副墨粲我前，頓使百廢起。", "朱絃渺遺音，慎勿娛俗耳。", "論交儻自今，相從期暮齒。"]'),
('76251919-7dd6-446e-8ea4-db934f4a99aa','錢塘賦水母','沈與求','宋','宋诗','song-poetry','','[]','疾風吹雨回江城，艣牙嘔啞潮欲平。',288,'全唐诗/poet.song.96000.json','["疾風吹雨回江城，艣牙嘔啞潮欲平。", "客居喜無人事攖，相與環坐臨前楹。", "眼中水怪狀莫名，出没沙觜如浮罌。", "復如緇笠絕兩纓，渾沌七竅俱未形。", "塊然背負群鰕行，嗟其巧以怪自呈。", "凝目愯視相將迎，老漁旁睨笑發聲。", "曰此水母官何驚，江流如奔絕滄瀛。", "潮汐往來月爲程，藏納衆污無滿盈。", "浮埃沈滓溷九清，結成此物宜昏盲。", "使鰕導迷作雙睛，乃能接迹蚌與蟶。", "亦猶巨蛩二體并，離則無目爲光精。", "江天八月霜葉鳴，罟師得鰕供水征。", "水母弃擲羅縱横，試令收拾輸庖丁。", "絳礬收涎體紆縈，飛刀鏤切武火烹。", "花甆飣餖粲白英，不殊冰盤堆水晶。", "稻醯韲寒芼香橙，入齒已復能解酲。", "遣漁止矣勿復評，嗟哉此性愚不更。", "定矜故態招三彭，且摩枵腹甘藜羹。"]'),
('e9ad4640-1620-475b-a8ca-d18951eda8d7','泛舟村落阻風不能少進而菱梢芡觜繚舷上下篙人病之','沈與求','宋','宋诗','song-poetry','','[]','艇子掠岸行，水痩不濡尾。',120,'全唐诗/poet.song.96000.json','["艇子掠岸行，水痩不濡尾。", "狂飇振疏篷，獵獵鳴兩耳。", "十篙八九褪，逆勢何乃爾。", "野芡伺吾間，回梢哆利觜。", "亦有芰浮角，一一肆輕鄙。", "初欲事幽尋，解纜出疏葦。", "乘流覓清淺，濯纓助深喜。", "事有大不然，移頃未離咫。", "安得望蓬萊，巨艦破潮起。", "征帆駕長風，一日三萬里。"]'),
('9b269aaf-33b4-445a-a5c4-3a70fb651e0a','夜坐感事','沈與求','宋','宋诗','song-poetry','','[]','沈沈夜氣歸，虛堂閉深寂。',48,'全唐诗/poet.song.96000.json','["沈沈夜氣歸，虛堂閉深寂。", "孤燈灺餘花，寒霤韻殘滴。", "醖釀萬斛愁，感槩一人敵。", "何當棄短檠，陰山叱鳴鏑。"]'),
('e432533d-4e61-40ea-b1f3-525a0f09f7e8','戊申初寒偶作','沈與求','宋','宋诗','song-poetry','','[]','去年十月冬猶温，單衣曉出錢塘門。',272,'全唐诗/poet.song.96000.json','["去年十月冬猶温，單衣曉出錢塘門。", "攜孥僅脱餓虎口，更吟楚些招驚魂。", "兒女争從亂離苦，咿啞遶膝多語言。", "舟行畏塗侵夜泊，孤燈明滅何處村。", "蕭蕭細雨疏葦響，風力漸搖枯柳根。", "失聲號寒泣龍具，促櫂傍險争前奔。", "還家依然四壁立，故衾敗絮那忍論。", "無衣豈暇具裘褐，海圖坼裂波濤翻。", "天公戲人亦太虐，雪花徑尺連上元。", "今年十月事羈宦，兩腳如舊身大存。", "紙窗寂歷風竹嘯，古木中夜號空園。", "旅人不眠毛骨冷，撫事念往多煩寃。", "吾儕小人不論數，豺狼滿目哀王孫。", "似聞易水寒墮指，北望大漠烟雲昏。", "安得壯士馭八駿，沙蟲猿鶴俱騰騫。", "歸歟莫如中土樂，天子孝友朝廷尊。", "坐令鐵衣掃蟣蝨，四海挾纊懷君恩。"]'),
('23e12977-b421-463f-aac4-90dd0cf7af4e','十里巖石壁','沈與求','宋','宋诗','song-poetry','','[]','巨靈手擘青瑤璞，平削無痕看斧鑿。',160,'全唐诗/poet.song.96000.json','["巨靈手擘青瑤璞，平削無痕看斧鑿。", "六丁取將天路遙，雷電收威半空落。", "至今崒嵂横道旁，絕壁萬仞青茫茫。", "倚天屹立不可近，下視培塿如群羊。", "蘚花斕斑風雨潰，藤梢夭矯蛟龍戲。", "中開微竇走鳴泉，白虹吞吐涵秋氣。", "泉流萬古潭水深，山寒無風鬰沈沈。", "下田納納禾稼茂，發源沾溉初何心。", "峭直誰令據當路，松柏蕭森半烟霧。", "猶恐夜深魑魅驚，更遣山靈謹呵護。"]'),
('41421768-a721-469d-aea5-b52d28e1fca9','夜書山驛','沈與求','宋','宋诗','song-poetry','','[]','天寒夜向闌，月出山更静。',48,'全唐诗/poet.song.96000.json','["天寒夜向闌，月出山更静。", "風露搖青空，萬象光耿耿。", "啼螿泣幽草，賓鴻度前嶺。", "歸來坐孤窗，松竹舞清影。"]'),
('bc6847f4-c75b-415d-be55-30a93ed1e9b9','績溪寨口','沈與求','宋','宋诗','song-poetry','','[]','青嶂插天塹，白水翻地軸。',192,'全唐诗/poet.song.96000.json','["青嶂插天塹，白水翻地軸。", "回環壯哉縣，不許飛鳥觸。", "往年羽書馳，盜發清溪曲。", "先聲雜妖幻，餘黨萃符祝。", "控攘最旁近，被害良慘毒。", "聚落燼烟空，生齒塗炭酷。", "豈無山川險，會有法令束。", "百年不用武，駢領甘此辱。", "至今風雨夜，猶聞鬼群哭。", "遺俗感舊憤，禦盜勇氣足。", "大兒佩刀劍，小兒利鋒鏃。", "老翁筋力衰，奮挺怒張目。", "營寨人自戍，不待官期促。", "矧今殺氣横，洒涕國步蹙。", "豺狼據道路，虎兕出林谷。", "儻持復讎心，公戰圖報國。"]'),
('7cdcbf0b-e176-4d80-b04c-0605e85a6084','聞招寇','沈與求','宋','宋诗','song-poetry','','[]','綠林煽餘習，無乃國計左。',180,'全唐诗/poet.song.96000.json','["綠林煽餘習，無乃國計左。", "誨盜爵秩崇，納叛金繒夥。", "戢姦在斧鉞，賞誘詎云可。", "萌芽緩誅鋤，猖披費結裹。", "戰多數招安，奚用腰箭笴。", "悍兵昔已然，黠將近亦頗。", "昌言假報國，湼面刺投火。", "豺狼奮哮噬，蠭蠆利掀簸。", "横行入通邑，焚掠窮委瑣。", "況聞南陵寇，執事初意惰。", "出没勢已張，翦滅計未果。", "宣城俯百里，千室盡奔嚲。", "王事吾有程，馬頭戴印顆。", "叱馭疾其驅，語言紛炙輠。", "何當說羆貅，一洗根本禍。"]'),
('7c0925c5-8e87-4c27-a47e-53c96b7a0e50','寧國道中','沈與求','宋','宋诗','song-poetry','','[]','山石犖确行路難，山風蕭蕭吹早寒。',144,'全唐诗/poet.song.96000.json','["山石犖确行路難，山風蕭蕭吹早寒。", "十步九歇僕馬瘁，兔蹊鳥道窮躋攀。", "崖谷空籠瀑泉走，碎玉零亂飛前灘。", "石堤捍水幾百級，落處疑有蛟龍盤。", "兩山之間開畎畝，石罅著鋤那得寛。", "前村後村烟火冷，土牆茅蓋常掩關。", "我行不知記近遠，官游歲晚良自歎。", "豈如家家一飽外，鷄豚社酒相追歡。", "那知亦有簡書畏，里胥剥啄驚衰顔。"]'),
('eeff9539-2da9-489a-a9e6-7b47a4c7070b','夜宿千秋嶺下田家','沈與求','宋','宋诗','song-poetry','','[]','陰壑來悲風，薄莫吹急雨。',168,'全唐诗/poet.song.96000.json','["陰壑來悲風，薄莫吹急雨。", "冥冥攬寒色，咫尺暗山路。", "茅簷兩三家，曲澗縈竹塢。", "停車且問訊，欲止此何許。", "老翁行步弱，扶杖倚門戶。", "問我官何忙，野宿今無所。", "向夜號狐狸，深林嘯豺虎。", "甘心在擇肉，闖首輒憑怒。", "駕言往何之，一榻翁敢拒。", "延我傍中堂，慇懃慰良苦。", "解衣土銼旁，支枕憩行旅。", "昏然飽安眼，境寂絕猜怖。", "雞聲報明發，征車犯寒去。", "呼燈別老翁，鼻息方栩栩。"]'),
('6e4a18ea-78ef-42b6-bc5e-d5f2ad6a98fe','溪上見梅','沈與求','宋','宋诗','song-poetry','','[]','晴溪漲淥如陰苔，晴山插影相低回。',192,'全唐诗/poet.song.96000.json','["晴溪漲淥如陰苔，晴山插影相低回。", "畫船疊鼓順流下，波光浩蕩征帆開。", "灘縈岸繚柂牙轉，水石相激如奔雷。", "須臾已復過絕壁，歸路漸近嚴陵臺。", "山重溪複境彌迥，暗香忽自空中來。", "日斜正見叢棘外，炯炯疏片飄寒梅。", "槎牙一種獨愁絕，含情不語明巖隈。", "凌波疑是水仙出，縞衣素質行徘徊。", "下窺清淺一笑粲，坐使凡卉俱塵埃。", "山谷之儒已臞甚，龜腸鶴骨世所咍。", "相逢頓覺百憂釋，不嫁春風誰與媒。", "舟行易遠空回首，角聲吹夢心悠哉。"]'),
('7ac0c6b8-fe98-45f7-94c3-567ede62d63a','次韻張仲宗感事','沈與求','宋','宋诗','song-poetry','','[]','諸侯救周衰，能事存筆削。',192,'全唐诗/poet.song.96000.json','["諸侯救周衰，能事存筆削。", "後學競專門，膚引迷注腳。", "寧知懼賊亂，誅意未爲虐。", "上皇志包荒，大度示恢廓。", "誤墮虜計中，九廟施箭鑿。", "將臣擁彊兵，首鼠事前卻。", "專雄懷顧望，散黨失歸着。", "坐令兩宫車，北轅狩沙漠。", "天王紹絕統，憤此國勢弱。", "嘗膽復大讎，此意良不薄。", "向來督真姦，國典猶闊略。", "群公争護前，循習久彌確。", "黄屋泛滄溟，黔首寄矰繳。", "世無管夷吾，老眼雙淚閣。", "何當誅賞行，浩歎成嗢噱。", "曜靈還中天，冰雪自銷鑠。"]'),
('5f96bb8c-0486-4c7e-8263-29885434c082','次韻允迪祕監同年所寄會稽唱酬之什','沈與求','宋','宋诗','song-poetry','','[]','秋鴻度寥廓，天遠勞目送。',168,'全唐诗/poet.song.96000.json','["秋鴻度寥廓，天遠勞目送。", "燕雀各有謀，墮此朝餔供。", "平生江海游，往事恍如夢。", "簮裳彊結裹，翰墨困嘲弄。", "一官冗不治，匹馬旁無從。", "迷行落小劫，直意識大洞。", "似聞脯麒麟，頗欲翳鸞鳳。", "眼無行祕書，此語誰與共。", "貧知世路艱，老覺交情重。", "功名等戲劇，射覆偶微中。", "龍媒駕鼓車，款段朱絲鞚。", "南游探禹穴，聊得登覧縱。", "時危要奇策，塗窮勿長慟。", "相期論少卑，材大古難用。"]'),
('82474ade-4e8a-4cd1-9f5c-577f027b1a6c','鄭維心約趙安道中大家兄次律學士及僕探梅城山乘月泛舟而歸','沈與求','宋','宋诗','song-poetry','','[]','窮居不厭車馬絕，委巷衡門常晝閉。',224,'全唐诗/poet.song.96000.json','["窮居不厭車馬絕，委巷衡門常晝閉。", "朝來剝啄誰過予，倒屣逢迎走驚蹶。", "里中勝士真可人，爲憶寒梅耿殘雪。", "招呼聞早探幽芳，平溪徑遣扁舟截。", "西山佳處雲塢深，松竹蕭森迷洞穴。", "上方小閣鏁空明，開窗下見千山列。", "畫手無人貌平遠，野闊天多供一瞥。", "冰花只作小寒枝，拄杖不辭穿巀嶭。", "野僧省事畏客狂，攀援自向南枝折。", "疏香低入坐中來，骨冷肌清伴高潔。", "襟期況有公子賢，伯也雄豪負奇節。", "手拈凍蘂薦深杯，妙語琅琅契禪悦。", "人間此會不多有，忍放杯空成小別。", "歸來懷抱與誰論，一櫂翻然載明月。"]'),
('aace101c-86ea-432a-8ef0-8414c7756fb6','臘月二十六夜大雪投曉霽色恍然鳥語啁啾便有春意感而賦之','沈與求','宋','宋诗','song-poetry','','[]','黄昏雪打窗，夜雨破幽夢。',144,'全唐诗/poet.song.96000.json','["黄昏雪打窗，夜雨破幽夢。", "晨光逗簷花，霽色晃池凍。", "老木驚向榮，好鳥發微哢。", "草根露纖芒，蟲聲試群哄。", "空畦土勻酥，側澗泉流湩。", "臘盡殺氣衰，春歸生理共。", "人情自多端，天意皆曲中。", "懸知造物公，未厭萌區衆。", "艱難重時節，俯仰疲迎送。", "心閑數造化，骨寒遭鬼弄。", "那驚梅柳新，但飽藜藿供。", "行須過田家，泥飲空社甕。"]'),
('0145ef32-f5af-4be0-96ed-2c37b1928e12','次韻葛魯卿送示近作一通二首  其一','沈與求','宋','宋诗','song-poetry','','[]','八騶盡屏如縈策，微步招尋老賓客。',128,'全唐诗/poet.song.96000.json','["八騶盡屏如縈策，微步招尋老賓客。", "離離草色亂溝塍，腳底春風隨蠟屐。", "蟄龍昨夜起洄潭，忽雷閃電飛千巖。", "朝來遺珠落懷袖，復見國風歌二南。", "公洗膏肓砭傳癖，詞伯儒宗蚤揚歷。", "詩成聊復貯錦囊，副在久應藏石室。", "只今漂泊客烟村，高哦七字哀王孫。", "有如此言公不食，東山那得留安石。"]'),
('f16d3ebc-79b7-41d0-8ae5-a5d2ae40b177','次韻葛魯卿送示近作一通二首  其二','沈與求','宋','宋诗','song-poetry','','[]','君侯胸次多籌策，歲晚翻爲江海客。',128,'全唐诗/poet.song.96000.json','["君侯胸次多籌策，歲晚翻爲江海客。", "小隱方營一把茅，幽尋定費幾兩屐。", "公心落月印寒潭，出濟巨川歸築巖。", "追還正始遊戲事，聊爲風騷作指南。", "我有幽憂如酒癖，起誦君詩春寂歷。", "天公下取氣凌雲，神物護持光滿室。", "老矣懷歸葑上村，倚公佳句譜桐孫。", "須公拯危紓旰食，快寫車攻刊樂石。"]'),
('8d5348ec-17ba-4a96-a828-f67c5c3c9f34','葛魯卿再和復用前韻奉酬  其一','沈與求','宋','宋诗','song-poetry','','[]','上謁軍門宜杖策，誰爲兵家分主客。',128,'全唐诗/poet.song.96000.json','["上謁軍門宜杖策，誰爲兵家分主客。", "猛將翻乘下瀨船，幽人退整登山屐。", "山泉聞似百花潭，山曲盤回十里巖。", "丘壑夔龍人太息，那將捷徑比終南。", "吾邦舊事論三癖，佳處還堪記遊歷。", "深譏表餌誤朝廷，急賛烝嘗安廟室。", "避地來居水遶村，鳬鷖哺子竹生孫。", "苜蓿堆盤從野食，人愛當年二千石。"]'),
('989a3403-025d-4011-af87-7f9c4d20b20e','葛魯卿再和復用前韻奉酬  其二','沈與求','宋','宋诗','song-poetry','','[]','平生自愧無奇策，魔去徑須呼逐客。',128,'全唐诗/poet.song.96000.json','["平生自愧無奇策，魔去徑須呼逐客。", "兀身聊欲避風塵，作意何能分履屐。", "驚魚畏網伏深潭，窮猿失木號重巖。", "殺氣漲天消息斷，但想滄海浮東南。", "囊無一錢誚錢癖，鮭菜醒人今齒歷。", "忍言走馬過章臺，空駭祝鷄餘土室。", "傖父嗔儂語带村，錦心繡口拜天孫。", "端爲遠謀箴肉食，誰能饒舌攻牢石。"]'),
('631e5e68-2479-4d71-87da-0283b24a6418','葛魯卿再和復用前韻奉酬  其一','沈與求','宋','宋诗','song-poetry','','[]','聞公卜居問龜策，隱屏畏人呼重客。',128,'全唐诗/poet.song.96000.json','["聞公卜居問龜策，隱屏畏人呼重客。", "閑招溪友鐵頭航，戲躡鄰娃金齒屐。", "舍旁修木蔭風潭，坐有郎君掣電巖。", "已將此段慰偪仄，更爲岑參來巷南。", "細說當年陳類癖，伏閤忿争書日歷。", "國醫袖手藥籠空，掛壁猶餘弓矢室。", "吾州萬落與千村，以葛名兒浸及孫。", "刲羊擊豕作寒食，定恐酌公忘斗石。"]'),
('b4e9978c-254c-494b-a6a6-c167b5bccd39','葛魯卿再和復用前韻奉酬  其二','沈與求','宋','宋诗','song-poetry','','[]','小檻觀魚呼策策，來伴漁蠻作逋客。',128,'全唐诗/poet.song.96000.json','["小檻觀魚呼策策，來伴漁蠻作逋客。", "風回別浦有飛帆，雨濕斷堤無響屐。", "夢回春到放龜潭，潭上雜花開石巖。", "十椽老屋烟燼滅，越鳥無日忘巢南。", "空說花驄酬馬癖，豈有過都如塊歷。", "出門咫尺行路難，只辦蒼黄問家室。", "鼓鼙聲動何處村，争挽神器歸王孫。", "今者不樂憤忘食，奮臂擬關弓五石。"]'),
('aa822e87-0bd3-4f7e-99a0-18a2b3e2aa09','奉題思上人妙峰堂','沈與求','宋','宋诗','song-poetry','','[]','上人游四方，雲水渺長道。',144,'全唐诗/poet.song.96000.json','["上人游四方，雲水渺長道。", "一言契深心，百法從此了。", "十年歸故山，不踏山前草。", "經營妙峰堂，想像德雲老。", "閉關習跏趺，宴坐兀枯槁。", "混迹雖寰中，寄意已塵表。", "深枝姹巖花，雅音喧谷鳥。", "翠竹伴幽禪，白蓮敷衆好。", "山空有雲歸，地净無塵掃。", "回觀第一義，湛湛孤月皎。", "法門有等差，問訊今誰曉。", "躍身寶樓閣，此堂終褊小。"]'),
('6a5f102c-c1d1-4df5-8bb3-d15648c814c4','維心方刊正三國史某以精筆遺之蒙餉大篇爲謝氣格渾然三復感歎漫依元韻奉和蕪陋增愧','沈與求','宋','宋诗','song-poetry','','[]','諸豪雄誇劍芒銛，毛錐斂避收餘尖。',224,'全唐诗/poet.song.96000.json','["諸豪雄誇劍芒銛，毛錐斂避收餘尖。", "櫝間黯黮渇銅雀，案上爬沙枯玉蟾。", "學堂山人有遺裔，筆力大可千人兼。", "掉頭不肯書柿葉，酒酣起舞怒奮髯。", "十年歸坐溪口屋，傲視冠冕猶髠箝。", "草玄草聖聊戲耳，如醫識藥信手拈。", "邇來直筆到三國，去取法度何森嚴。", "眼中青白世矜異，皮裏陽秋誰顧瞻。", "更憐中書今且老，鷄毛葦管争出奩。", "懸知入手便獰劣，那復助子窮幽潛。", "我持妙穎急送似，標題珍重存華籤。", "勢如執法貴心正，俗病要以此語砭。", "揮掃定見龍蛇走，紬繹何憚歲月淹。", "須知筆意似人意，柔順未必非凶憸。"]'),
('c33de002-6895-412c-82d0-f5067f1a51eb','長樂梁世則爲余言林氏達觀樓横海嶠天下奇景也索詩爲賦一章','沈與求','宋','宋诗','song-poetry','','[]','老眼紛世故，百嗜了若遺。',132,'全唐诗/poet.song.96000.json','["老眼紛世故，百嗜了若遺。", "忽聞佳山水，未到神已馳。", "迢迢古長樂，山水天下奇。", "中有隱君子，少讀昇天詞。", "兹遊不可遂，樓居在厜㕒。", "要欲盡一覧，吞滅海嶠姿。", "想當宴坐久，遠意渺莫追。", "定見月嶺墮，洪瀾浴朝曦。", "蓬萊蔚相向，拍手招安期。", "秀色故可餐，卻粒到玉芝。", "何當往從游，下視培塿卑。"]'),
('c82f0770-4121-4d9a-88e6-607257fdaf47','和張仲宗送柯田山人歸隱  其一','沈與求','宋','宋诗','song-poetry','','[]','我家洄潭上，卜鄰左顧龜。',60,'全唐诗/poet.song.96000.json','["我家洄潭上，卜鄰左顧龜。", "中有隱君子，孤風邈難追。", "玩世逐虎鬼，祈年訊蛇醫。", "籬根縣瓠壺，蔓野紛翠帷。", "客至勿遽迎，借問來者誰。"]'),
('efdc2af2-227c-4f8f-9e61-99c4115a74f4','和張仲宗送柯田山人歸隱  其二','沈與求','宋','宋诗','song-poetry','','[]','窮巷車馬絕，杖屨得往來。',60,'全唐诗/poet.song.96000.json','["窮巷車馬絕，杖屨得往來。", "老儂起招呼，情話真樂哉。", "意行忘早宴，佳處首重回。", "月出一犬吠，柴門風爲開。", "收還四方事，老子良足哀。"]'),
('c82b1df2-db96-4404-9993-a019c797afea','和張仲宗送柯田山人歸隱  其三','沈與求','宋','宋诗','song-poetry','','[]','誰爲雙眼青，自失兩鬢黑。',60,'全唐诗/poet.song.96000.json','["誰爲雙眼青，自失兩鬢黑。", "溪山招客子，占勝清涼國。", "古人如可作，晚歲意何及。", "是中但可飲，慎勿忘酒德。", "酒酣動長忿，驚問兵誰勒。"]'),
('5fe7e7d7-1d42-4146-a483-8c30eb0564d4','和張仲宗送柯田山人歸隱  其四','沈與求','宋','宋诗','song-poetry','','[]','往年城下盟，殺氣横九有。',60,'全唐诗/poet.song.96000.json','["往年城下盟，殺氣横九有。", "脱身敵中來，親戚驚老醜。", "抗言半渡擊，失計推禍首。", "誰能返秦璧，争欲仇魯酒。", "着鞭空浪忙，好語得鷄口。"]'),
('5e605121-73ed-425d-b572-ea1d8f5c1c7b','和張仲宗送柯田山人歸隱  其五','沈與求','宋','宋诗','song-poetry','','[]','有弟在一方，丹臆危涕横。',60,'全唐诗/poet.song.96000.json','["有弟在一方，丹臆危涕横。", "念言還鄉夢，遙夜懷紫荆。", "忽興攬衣坐，孤燈耿青熒。", "雁奴信何功，捫心愧鴻冥。", "棄置復棄置，終尋白鷗盟。"]'),
('d0e4ccb9-4698-4a15-82da-1dd7247ad44b','鄭維心用張仲宗韻見贈復次其韻奉酬  其一','沈與求','宋','宋诗','song-poetry','','[]','幽人臥南窗，支床伏穹龜。',60,'全唐诗/poet.song.96000.json','["幽人臥南窗，支床伏穹龜。", "白墮意冥契，黄庭心暗追。", "身閑有餘適，國病何當醫。", "此事姑棄置，溪光掛屏帷。", "顧影或自笑，問言子從誰。"]'),
('74503a30-b9aa-496c-b7d5-4c978114be49','鄭維心用張仲宗韻見贈復次其韻奉酬  其二','沈與求','宋','宋诗','song-poetry','','[]','少日功名心，偃蹇挽不來。',60,'全唐诗/poet.song.96000.json','["少日功名心，偃蹇挽不來。", "雄豪本戲耳，静樂真賢哉。", "畏事口三緘，憂時腸九回。", "無客榻長掛，有懷尊自開。", "酒酣氣如雲，高哦追八哀。"]'),
('cb65b7d3-ff44-4471-8071-8502b56233e3','鄭維心用張仲宗韻見贈復次其韻奉酬  其三','沈與求','宋','宋诗','song-poetry','','[]','胸中飽世故，了了分白黑。',60,'全唐诗/poet.song.96000.json','["胸中飽世故，了了分白黑。", "十年客異縣，中夜夢鄉國。", "買鄰枕寒溪，此計吾猶及。", "大恐歲星惡，翻令銷福德。", "不如早移文，徑效山庭勒。"]'),
('612c3227-32b0-4088-9f5e-dcc559a0ce84','鄭維心用張仲宗韻見贈復次其韻奉酬  其四','沈與求','宋','宋诗','song-poetry','','[]','浮名等浮雲，過眼亦何有。',60,'全唐诗/poet.song.96000.json','["浮名等浮雲，過眼亦何有。", "誰能學東鄰，深顰不知醜。", "朔風吹飛霜，素色侵皓首。", "幽憂無與娛，萬事付杯酒。", "客來勿多談，要使耳如口。"]'),
('44b784cf-81aa-4224-9488-b530b0002f74','鄭維心用張仲宗韻見贈復次其韻奉酬  其五','沈與求','宋','宋诗','song-poetry','','[]','江濤故洶湧，胡馬猶縱横。',60,'全唐诗/poet.song.96000.json','["江濤故洶湧，胡馬猶縱横。", "健兒委戌甲，老農持棘荆。", "去年拒胡地，白骨堆晶熒。", "機權失猶豫，理數歸杳冥。", "誰如管夷吾，九合先同盟。"]'),
('01f84ff7-55e2-4207-9c99-25c6549d8da6','次韻葉左丞見寄  其一','沈與求','宋','宋诗','song-poetry','','[]','先生少英發，身爲國元龜。',60,'全唐诗/poet.song.96000.json','["先生少英發，身爲國元龜。", "玉堂動敏翰，諸老歎莫追。", "向來三折肱，舉世推良醫。", "小試經綸才，艱難佐籌帷。", "憂時儻失聲，捨我今其誰。"]'),
('0f511a87-d059-411e-96b7-251b33fe0e31','次韻葉左丞見寄  其二','沈與求','宋','宋诗','song-poetry','','[]','巖棲分麾去，鼎食羞嗟來。',60,'全唐诗/poet.song.96000.json','["巖棲分麾去，鼎食羞嗟來。", "憂樂有大者，得喪良小哉。", "霣心驚地坼，攬涕祈天回。", "願言國步肅，追理邊隙開。", "潔身未足道，王孫真可哀。"]'),
('95b9da8d-b390-4648-8939-d7cc7e987dfd','次韻葉左丞見寄  其三','沈與求','宋','宋诗','song-poetry','','[]','幻緣東即西，妄境白成黑。',60,'全唐诗/poet.song.96000.json','["幻緣東即西，妄境白成黑。", "那於土偶間，平地見佛國。", "雲山樂未央，歲月嗟何及。", "恩讎一快意，聲利多慚德。", "名成復逃名，翻恐鍾鼎勒。"]'),
('cee10e3f-1eac-4430-9a63-946c32e32bc0','次韻葉左丞見寄  其四','沈與求','宋','宋诗','song-poetry','','[]','胸中浩無垠，富貴公自有。',60,'全唐诗/poet.song.96000.json','["胸中浩無垠，富貴公自有。", "厭居廊廟榮，戲習村野醜。", "荒山披石林，它年齊峴首。", "殺雞侑晨炊，炰羔行社酒。", "此樂應獨知，世味難可口。"]'),
('9b372f38-7d94-44b2-8d8a-14dd739379c9','次韻葉左丞見寄  其五','沈與求','宋','宋诗','song-poetry','','[]','仗馬失芻豆，那顧一榻横。',60,'全唐诗/poet.song.96000.json','["仗馬失芻豆，那顧一榻横。", "小兒衣挾楮，老妻釵墮荆。", "心事獨炯炯，眼力雙熒熒。", "君恩未報償，浩歌託沈冥。", "上天不難知，誰能訊背盟。"]'),
('44202e16-e59b-4c95-a5c5-2ca3b1c6eadb','希顔提舉愽士謁葉公左丞於石林公遺之詩屬余次韻','沈與求','宋','宋诗','song-poetry','','[]','劉侯磊落人中傑，半生塵土略如我。',64,'全唐诗/poet.song.96000.json','["劉侯磊落人中傑，半生塵土略如我。", "酒酣氣與天低昻，長笑拘儒費膏火。", "虺隤一馬上高崗，怪來喜色猶揚揚。", "探得驪珠攜滿袖，明月掛空無價償。"]'),
('90b8994b-1c78-4fad-bc0e-2ec98fe58489','夾竹桃花','沈與求','宋','宋诗','song-poetry','','[]','搖搖兒女花，挺挺君子操。',64,'全唐诗/poet.song.96000.json','["搖搖兒女花，挺挺君子操。", "一見適相逢，綢繆結深好。", "妾容似桃蕚，郎心如竹枝。", "桃花有時謝，竹枝無時衰。", "春園灼灼自顔色，願言歲晚長相隨。"]'),
('0dc7fae5-9b5d-4206-a142-0a85eff90665','蠶','沈與求','宋','宋诗','song-poetry','','[]','吳桑成綠陰，吳蠶盈翠箔。',48,'全唐诗/poet.song.96000.json','["吳桑成綠陰，吳蠶盈翠箔。", "闔門障風雨，荒祠動村落。", "千絲爲衣被，一繭自纒縛。", "殺身以成仁，此計殊不惡。"]'),
('bea3d614-2271-42a9-9a96-3a0b15127f2e','松下追涼','沈與求','宋','宋诗','song-poetry','','[]','佳哉十八公，凜凛廊廟具。',180,'全唐诗/poet.song.96000.json','["佳哉十八公，凜凛廊廟具。", "大匠偶未收，蒼髯鬰如許。", "根盤曲磵幽，勢宅層崖阻。", "清風自掃門，當伏不受暑。", "顧我蕭散姿，本是山中侣。", "出逢畏日長，隻影無地去。", "偷閑蕭寺游，清陰直修廡。", "神交先浩茫，徑造不我拒。", "斗酒起自行，開懷爲延佇。", "寒綠浸杯盤，勁氣逼牙輔。", "語已心地涼，外熱寧足禦。", "公家綠骨蛇，千歲穴深土。", "何當供晨餐，散我腰腳僂。", "它年聽颼飀，危冠掛神虎。", "此意亦大奇，勿與夏蟲語。"]'),
('393853ab-8cf4-4290-94b9-8167e13e4ad9','呈唐子明同年','沈與求','宋','宋诗','song-poetry','','[]','饑來驅我出蓬蒿，鬢影鬖鬖舞二毛。',64,'全唐诗/poet.song.96000.json','["饑來驅我出蓬蒿，鬢影鬖鬖舞二毛。", "黄甲浮名誇俗子，白丁結習數吾曹。", "老盆貯酒心猶健，嬾架抛書趣亦高。", "萬事含糊自堪樂，不須持板念徒勞。"]'),
('9e3bce6c-aca8-4f7b-9252-33795a0247ec','攝尉歸安呈江嘉','沈與求','宋','宋诗','song-poetry','','[]','無地誅鋤一束茅，清吟端作反離騷。',64,'全唐诗/poet.song.96000.json','["無地誅鋤一束茅，清吟端作反離騷。", "奔波且復同香尉，蕭散還須似馬曹。", "名下迹公初定價，暗中索我便矜豪。", "文章論世寧論晚，肯慕群飛輒仰高。"]'),
('b35cb1ae-0c7a-461c-8726-cf9f4f6e229a','小雨','沈與求','宋','宋诗','song-poetry','','[]','小雨廉纖未肯晴，勒回花信待清明。',32,'全唐诗/poet.song.96000.json','["小雨廉纖未肯晴，勒回花信待清明。", "冷官何預芳菲事，空聽春禽作意鳴。"]'),
('533f9c2c-418c-4332-82cc-c7697346fdb7','清明日晚晴','沈與求','宋','宋诗','song-poetry','','[]','正好園林藉落英，細風吹雨濕清明。',32,'全唐诗/poet.song.96000.json','["正好園林藉落英，細風吹雨濕清明。", "牆陰旱渴休無賴，自有鳴鳩解喚晴。"]'),
('f0dfa2cd-ccbc-438f-aa78-6d43d10f2bde','舟過荻塘','沈與求','宋','宋诗','song-poetry','','[]','野航春入荻芽塘，遠意相傳接渺茫。',64,'全唐诗/poet.song.96000.json','["野航春入荻芽塘，遠意相傳接渺茫。", "落日一篙桃葉浪，薫風十里藕花香。", "河回遽失青山曲，菱老難容碧草芳。", "村北村南歌自答，懸知歲事到金穰。"]'),
('c61f8c78-eebd-431f-803b-6a821d0cc9f2','夏日書事','沈與求','宋','宋诗','song-poetry','','[]','洗竹明新牖，疏泉理廢池。',48,'全唐诗/poet.song.96000.json','["洗竹明新牖，疏泉理廢池。", "破礱炊玉粒，釣鯽鱠銀絲。", "假寐抛書帙，蠲煩泥酒巵。", "空餘八角扇，嬾惰不能持。"]'),
('3fe24f27-fa84-41f1-8f37-ea69e6b591f7','秋日戲呈蔣達可檢討','沈與求','宋','宋诗','song-poetry','','[]','西風摵摵舞庭槐，沈李浮瓜事益乖。',64,'全唐诗/poet.song.96000.json','["西風摵摵舞庭槐，沈李浮瓜事益乖。", "不飲竟逃官長罵，長年唯厭太常齋。", "已看簾幕辭歸鷰，猶訝池塘沸亂蛙。", "坐想臞仙遙集處，應頽醉玉泥金釵。"]'),
('95765ea8-c317-4649-a636-fa85ba6e7387','同官用僕秋日詩韻述懷因復和之','沈與求','宋','宋诗','song-poetry','','[]','荷鍤相隨死便埋，達人於世豈長乖。',64,'全唐诗/poet.song.96000.json','["荷鍤相隨死便埋，達人於世豈長乖。", "囊錢擬定文章價，瓢飲聊甘祭祀齋。", "兒輩那知群野鶴，我曹寧復問官蛙。", "何如細瀹烹茶鼎，日向松陰爇亂釵。"]'),
('27803c7f-bfec-4eb9-8567-faf6d7d0c081','從劉殿院借書','沈與求','宋','宋诗','song-poetry','','[]','骨寒宜伴列仙臞，欲喜依劉計未疏。',64,'全唐诗/poet.song.96000.json','["骨寒宜伴列仙臞，欲喜依劉計未疏。", "自昔暗中人易記，到今名下士非虛。", "欲從給事論奇字，擬向中郎得異書。", "願借牙籤三萬軸，爲公一一辨蟫魚。"]'),
('39f8b95b-fa26-4dc1-8bcc-17b736fbe760','過徐氏莊居','沈與求','宋','宋诗','song-poetry','','[]','只着南冠不著纓，掉頭防我問功名。',64,'全唐诗/poet.song.96000.json','["只着南冠不著纓，掉頭防我問功名。", "數椽茅屋有時漏，一墢野田無具耕。", "酒地定能容勝踐，墨畦終擬過平生。", "扣舷歸去蒹葭閙，後夜相思看月明。"]'),
('859b5c4f-624f-4173-9f9e-7d797e8527fb','與道按田至湖山有詩凡九章次其韻 游天平山','沈與求','宋','宋诗','song-poetry','','[]','行盡郊原指掌平，亂峰争聳髻鬟青。',32,'全唐诗/poet.song.96000.json','["行盡郊原指掌平，亂峰争聳髻鬟青。", "山家不識高軒過，驚走兒童戶半扃。"]'),
('418f61cd-8f41-424d-864f-c61b5cd95b7c','與道按田至湖山有詩凡九章次其韻 白雲泉','沈與求','宋','宋诗','song-poetry','','[]','瓦鼓喧喧殢土龍，紙錢零亂野祠中。',32,'全唐诗/poet.song.96000.json','["瓦鼓喧喧殢土龍，紙錢零亂野祠中。", "誰能向此分餘瀝，潤澤焦枯不計功。"]'),
('7ffbd06a-d600-449e-ac99-026c4cb14923','與道按田至湖山有詩凡九章次其韻 題靈源寺','沈與求','宋','宋诗','song-poetry','','[]','出郭有餘適，到山無限清。',48,'全唐诗/poet.song.96000.json','["出郭有餘適，到山無限清。", "野泉依井落，古刹並湖成。", "水鳥閑中趣，風松意外聲。", "問僧知此觀，身世若爲輕。"]'),
('6ca50619-e85b-4482-b35c-73abb120c536','與道按田至湖山有詩凡九章次其韻 雲隱軒','沈與求','宋','宋诗','song-poetry','','[]','風埃滿眼作凄涼，招隱空山此計長。',32,'全唐诗/poet.song.96000.json','["風埃滿眼作凄涼，招隱空山此計長。", "祇恐誤隨雲出岫，不如專以醉爲鄉。"]'),
('3e1b7ca7-b5d4-49a5-aec9-6a8bd17b2274','與道按田至湖山有詩凡九章次其韻 題林屋洞口','沈與求','宋','宋诗','song-poetry','','[]','仙去遺蹤亦漫留，羽旗那復肯來遊。',32,'全唐诗/poet.song.96000.json','["仙去遺蹤亦漫留，羽旗那復肯來遊。", "欲知洞府烟霞邃，漠漠蒼崖面橘州。"]'),
('24c361c4-7341-4319-a72d-8f9b29220c38','與道按田至湖山有詩凡九章次其韻 題靈祐觀','沈與求','宋','宋诗','song-poetry','','[]','聞道藤蘿一一攀，要窮佳處識湖山。',32,'全唐诗/poet.song.96000.json','["聞道藤蘿一一攀，要窮佳處識湖山。", "青琳宫闕當西崦，應費巾車數往還。"]'),
('5ca89a86-f81d-4956-8940-669cdd21abab','與道按田至湖山有詩凡九章次其韻 毛公壇觀','沈與求','宋','宋诗','song-poetry','','[]','山脊層壇古，松根曲徑微。',48,'全唐诗/poet.song.96000.json','["山脊層壇古，松根曲徑微。", "衣冠久已化，殿閣自相輝。", "喬木交加合，閑雲自在飛。", "無端雪髯老，猶效鶴重歸。"]'),
('41ae2872-db7b-480a-879f-d303920ff180','與道按田至湖山有詩凡九章次其韻 題上真宫','沈與求','宋','宋诗','song-poetry','','[]','我欲款玄關，誰能供逋客。',24,'全唐诗/poet.song.96000.json','["我欲款玄關，誰能供逋客。", "相將持綵囊，珠露滿蒼柏。"]'),
('184d643b-a287-44b7-82fd-d92ea7e015fc','過徐氏郊居','沈與求','宋','宋诗','song-poetry','','[]','林梢眇眇墮斜暉，剝啄還來扣隱扉。',64,'全唐诗/poet.song.96000.json','["林梢眇眇墮斜暉，剝啄還來扣隱扉。", "門巷劣容居士屩，塵埃不到野人衣。", "恰當夜甑黄粱熟，盛供春山紫蕨肥。", "侍坐無人只山月，兩翁相對自忘機。"]'),
('ce2f63be-059b-4bba-9937-25f01ae571a3','到吳','沈與求','宋','宋诗','song-poetry','','[]','三載故鄉別，歸帆恰到吳。',48,'全唐诗/poet.song.96000.json','["三載故鄉別，歸帆恰到吳。", "食寒新火換，天闊斷雲孤。", "酒市仍依岸，漁村遠带湖。", "碧山千萬疊，翻憶夢崎嶇。"]'),
('e11b1069-965f-44c9-b697-f64171fe43fa','感事','沈與求','宋','宋诗','song-poetry','','[]','鬢毛端欲改，歲月竟相侵。',48,'全唐诗/poet.song.96000.json','["鬢毛端欲改，歲月竟相侵。", "薄宦顔難彊，窮塗感易深。", "舊交多得路，古道罕知音。", "吾事政如此，飄零違寸心。"]'),
('4fb83db7-1e93-4729-aef6-5b1f7441e3d5','旦日趨府','沈與求','宋','宋诗','song-poetry','','[]','紫簫吹夢斷，起視斗闌干。',48,'全唐诗/poet.song.96000.json','["紫簫吹夢斷，起視斗闌干。", "痩馬踏殘月，單衣中薄寒。", "錦囊那復佩，革带頓成寛。", "浪逐官曹底，更題敢自安。"]'),
('24ff060b-4ebf-48c7-b95e-bb990e9a5c4a','次韻秀守苗郎中喜雨','沈與求','宋','宋诗','song-poetry','','[]','旍斾傳呼起伏龍，雨翻枯澤已全通。',64,'全唐诗/poet.song.96000.json','["旍斾傳呼起伏龍，雨翻枯澤已全通。", "招呼急吹添秋思，袪逐驕陽助歲功。", "蝝子有知先避境，葑根無着盡浮空。", "老農自笑豚蹄祝，惠政流行盍屢豐。"]'),
('aff5755c-fe8d-4170-b523-043e952dc74f','次韻盧憲小雨','沈與求','宋','宋诗','song-poetry','','[]','狂風初作惡，小雨似知時。',48,'全唐诗/poet.song.96000.json','["狂風初作惡，小雨似知時。", "破睡心長折，呼愁眼易饑。", "勃姑穿渡急，鴉舅出林遲。", "春事今如此，幽尋有底期。"]'),
('8d5637ae-4c84-482b-8526-428225c891f9','雨不止','沈與求','宋','宋诗','song-poetry','','[]','已看城郭半浮楂，水戽聯翩接渚涯。',32,'全唐诗/poet.song.96000.json','["已看城郭半浮楂，水戽聯翩接渚涯。", "天意若知民意切，停鞭且止阿香車。"]'),
('3e70bd76-12d2-4978-ad85-a285b1fd54de','新春書事','沈與求','宋','宋诗','song-poetry','','[]','早歲驚逢上苑春，蹇驢朝踏落花塵。',32,'全唐诗/poet.song.96000.json','["早歲驚逢上苑春，蹇驢朝踏落花塵。", "只今嬾問芳菲事，桞眼相看也笑人。"]'),
('b5be2105-7399-4fc4-844c-a50547bf5376','次韻盧憲春意','沈與求','宋','宋诗','song-poetry','','[]','少陵花惱便顛狂，天與多情付此郎。',64,'全唐诗/poet.song.96000.json','["少陵花惱便顛狂，天與多情付此郎。", "宿露園林鶯舌亂，暖風庭院蜜脾香。", "閑愁幾欲縈春事，幽怨還能入醉鄉。", "應斷玉樓雙望眼，便須催促理歸檣。"]'),
('1c141f66-62ef-4dce-ba01-c322f0d2a0e1','清明','沈與求','宋','宋诗','song-poetry','','[]','杏火燒空潑眼明，游人蕩槳淥蕪城。',64,'全唐诗/poet.song.96000.json','["杏火燒空潑眼明，游人蕩槳淥蕪城。", "山歌慣習吳歈調，水戲終含楚些聲。", "草滿池塘春漲淺，鷰歸簾幕午風輕。", "踏青舊約誰能問，已喜年來粥有餳。"]'),
('5127be0a-493a-430d-b744-cbe50cca7bd6','報中有盛年休官者感而賦詩','沈與求','宋','宋诗','song-poetry','','[]','中都如海士如鱗，乘雁雙鳬亦見馴。',64,'全唐诗/poet.song.96000.json','["中都如海士如鱗，乘雁雙鳬亦見馴。", "林下已無長往客，江頭誰伴獨醒人。", "因循儻使能成事，彊健何須便乞身。", "但喜高風激頽俗，要令鐘漏一番新。"]');
